function getClusterStatusCommand(problem) {
  switch (String(problem?.cluster ?? '')) {
    case 'number-theory':
      return `erdos number-theory status ${problem.problemId}`;
    case 'sunflower':
      return `erdos sunflower status ${problem.problemId}`;
    case 'graph-theory':
      return `erdos graph-theory status ${problem.problemId}`;
    default:
      return `erdos problem show ${problem.problemId}`;
  }
}

function getClusterFrontierCommand(problem) {
  switch (String(problem?.cluster ?? '')) {
    case 'number-theory':
      return `erdos number-theory frontier ${problem.problemId}`;
    case 'sunflower':
      return `erdos sunflower frontier ${problem.problemId}`;
    case 'graph-theory':
      return `erdos graph-theory frontier ${problem.problemId}`;
    default:
      return null;
  }
}

function getSourceRefreshCommand(problem) {
  if (String(problem?.cluster ?? '') === 'number-theory' && String(problem?.problemId ?? '') === '848') {
    return {
      command: `erdos number-theory bridge-refresh ${problem.problemId}`,
      args: ['number-theory', 'bridge-refresh', String(problem.problemId), '--json'],
      kind: 'frontier_bridge',
    };
  }
  return null;
}

function getCurrentClaimSurface(problem, { bridge, theoremModule, routeBreakthrough }) {
  if (bridge?.current_bridge_state) {
    return 'bridge_backed_frontier_support';
  }
  if (problem?.researchState?.problem_solved) {
    return 'solved_result';
  }
  if (routeBreakthrough) {
    return 'frontier_supported_route';
  }
  if (theoremModule) {
    return 'theorem_module_registered';
  }
  return 'route_scaffolding';
}

function buildBaselineHooks({ activeRoute, theoremModule, firstReadyAtom, frontierNotePresent }) {
  const hooks = [];

  if (activeRoute) {
    hooks.push({
      hook_id: 'active_route_recorded',
      status: 'supported',
      note: `The pack records an active route, currently \`${activeRoute}\`.`,
    });
  }

  if (theoremModule) {
    hooks.push({
      hook_id: 'theorem_module_registered',
      status: 'supported',
      note: `A theorem module is already registered for the active route: \`${theoremModule}\`.`,
    });
  }

  if (firstReadyAtom?.atom_id) {
    hooks.push({
      hook_id: 'ready_atom_present',
      status: 'supported',
      note: `The live route already has a ready atom, \`${firstReadyAtom.atom_id}\`, which can feed the theorem lane.`,
    });
  }

  if (frontierNotePresent) {
    hooks.push({
      hook_id: 'frontier_note_present',
      status: 'supported',
      note: 'The pack already carries a frontier note that can anchor theorem-facing updates.',
    });
  }

  if (hooks.length === 0) {
    hooks.push({
      hook_id: 'theorem_loop_seeded',
      status: 'supported',
      note: 'The theorem loop is available as a baseline scaffold even though no deeper bridge-specific hook has been recorded yet.',
    });
  }

  return hooks;
}

function buildBaselineAgenda({
  activeRoute,
  theoremModule,
  firstReadyAtom,
  nextHonestMove,
  currentClaimSurface,
}) {
  const items = [];

  if (firstReadyAtom?.atom_id) {
    items.push({
      item_id: 'promote_ready_atom',
      status: 'ready',
      task: `Turn ready atom \`${firstReadyAtom.atom_id}\` into the next theorem-facing checkpoint.`,
      why: firstReadyAtom.next_move ?? nextHonestMove,
    });
  }

  if (theoremModule) {
    items.push({
      item_id: 'stabilize_theorem_module_boundary',
      status: 'ready',
      task: `Align the active route with theorem module \`${theoremModule}\` and freeze its public claim boundary.`,
      why: `The current claim surface is \`${currentClaimSurface}\`, so the next theorem move should sharpen what that module actually certifies.`,
    });
  }

  if (activeRoute) {
    items.push({
      item_id: 'tighten_active_route_claim',
      status: 'ready',
      task: `Compress the active route \`${activeRoute}\` into the next honest theorem-facing claim unit.`,
      why: nextHonestMove,
    });
  }

  if (items.length === 0) {
    items.push({
      item_id: 'seed_theorem_lane',
      status: 'ready',
      task: 'Seed the theorem lane with the smallest honest route-facing claim.',
      why: nextHonestMove,
    });
  }

  return items;
}

function buildBridgeBackedAgenda({ theoremHooks, bridgeState, nextHonestMove }) {
  const items = [
								      {
      item_id: 'choose_next_finite_gap_move',
      status: 'ready',
      task: 'Choose the next finite-gap closure move and keep the theorem-facing claim surface honest.',
      why: nextHonestMove,
    },
  ];

  const hookIds = new Set((theoremHooks ?? []).map((hook) => hook.hook_id));

  if (hookIds.has('next_unmatched_equals_282_failure') && bridgeState?.next_unmatched_representative !== undefined) {
    items.push({
      item_id: 'explain_next_unmatched_alignment',
      status: 'ready',
      task: `Explain structurally why shared-prefix representative \`${bridgeState.next_unmatched_representative}\` aligns with the first failure of tail \`282\`.`,
      why: 'If that alignment is structural rather than accidental, it turns a search coincidence into a theorem-facing obstruction class.',
    });
  }

  if (hookIds.has('completed_tail_vs_search_leader_split')
    && bridgeState?.strongest_completed_structured_tail?.continuation !== undefined
    && bridgeState?.current_family_aware_leader?.continuation !== undefined) {
    items.push({
      item_id: 'explain_completed_vs_search_leader_split',
      status: 'ready',
      task: `Explain why completed structured tail \`${bridgeState.strongest_completed_structured_tail.continuation}\` differs from current family-aware leader \`${bridgeState.current_family_aware_leader.continuation}\`.`,
      why: 'That split tells us whether the live frontier is a finite-window artifact or a genuinely better structural continuation class.',
    });
  }

  if (hookIds.has('repair_pool_not_closed')) {
    items.push({
      item_id: 'model_repair_pool_growth',
      status: 'ready',
      task: 'Model the repaired square-modulus pool as a growing family rather than treating it as already closed.',
      why: 'Recent packets introduced new square moduli, so the theorem lane should aim for controlled growth, not premature closure.',
    });
  }

  if (hookIds.has('top_repair_class_cluster') && Array.isArray(bridgeState?.top_gpu_tie_class) && bridgeState.top_gpu_tie_class.length > 0) {
    items.push({
      item_id: 'characterize_top_repair_cluster',
      status: 'ready',
      task: `Characterize what the top repair cluster \`${bridgeState.top_gpu_tie_class.join(', ')}\` shares structurally.`,
      why: 'If the tied tails share a common repair mechanism, that mechanism is a strong candidate for the next lemma-level abstraction.',
    });
  }

  return items;
}

function buildGenericFeatureExtractors(problem, theoremLoop) {
  const extractors = [
    {
      extractor_id: 'pack_route_state',
      kind: 'pack_context',
      scope: 'all_problems',
      status: 'ready',
      note: 'Reads pack route, ticket, and atom state as the baseline theorem-search context.',
    },
    {
      extractor_id: 'theorem_loop_snapshot',
      kind: 'theorem_loop',
      scope: 'all_problems',
      status: 'ready',
      note: 'Uses the canonical theorem-loop as the current claim-surface ledger.',
    },
  ];

  if (theoremLoop.currentBridgeState) {
    extractors.push({
      extractor_id: 'search_theorem_bridge_state',
      kind: 'search_bridge',
      scope: 'bridge_backed_problems',
      status: 'ready',
      note: 'Imports structured bridge state, packet ledgers, and search-side claim hooks.',
    });
  }

  if (problem.cluster === 'number-theory') {
    extractors.push({
      extractor_id: 'cluster_number_theory_features',
      kind: 'cluster_adapter',
      scope: 'number_theory',
      status: 'ready',
      note: 'Exposes number-theory specific finite-gap and verifier-facing metadata.',
    });
  } else if (problem.cluster === 'sunflower') {
    extractors.push({
      extractor_id: 'cluster_sunflower_features',
      kind: 'cluster_adapter',
      scope: 'sunflower',
      status: 'ready',
      note: 'Exposes sunflower-family route state, witness status, and compute packet context.',
    });
  } else if (problem.cluster === 'graph-theory') {
    extractors.push({
      extractor_id: 'cluster_graph_theory_features',
      kind: 'cluster_adapter',
      scope: 'graph_theory',
      status: 'ready',
      note: 'Exposes graph-theory archive or theorem-state context to the claim loop.',
    });
  }

  return extractors;
}

function buildGenericClaimGenerators(problem, theoremLoop) {
  const generators = [
    {
      generator_id: 'baseline_route_claims',
      kind: 'route_state',
      scope: 'all_problems',
      status: 'ready',
      note: 'Promotes active routes, ready atoms, and next-honest-move records into candidate claims.',
    },
    {
      generator_id: 'theorem_agenda_claims',
      kind: 'agenda_projection',
      scope: 'all_problems',
      status: 'ready',
      note: 'Turns theorem agenda items into explicit candidate claim tickets.',
    },
  ];

  if (theoremLoop.currentBridgeState) {
    generators.push({
      generator_id: 'search_bridge_claims',
      kind: 'bridge_pattern_projection',
      scope: 'bridge_backed_problems',
      status: 'ready',
      note: 'Projects bridge-backed structural hooks into concrete claim candidates.',
    });
  }

  if (problem.problemId === '848' && theoremLoop.currentBridgeState) {
    generators.push({
      generator_id: 'p848_repair_obstruction_claims',
      kind: 'problem_adapter',
      scope: 'problem_848',
      status: 'ready',
      note: 'Builds obstruction-alignment and repair-class candidate claims from the live packet ledger.',
    });
  }

  return generators;
}

function buildGenericClaimFalsifiers(problem, theoremLoop) {
  const falsifiers = [
    {
      falsifier_id: 'theorem_loop_consistency_check',
      kind: 'ledger_consistency',
      scope: 'all_problems',
      status: 'ready',
      note: 'Rejects claims that overstate the current theorem-loop claim surface.',
    },
    {
      falsifier_id: 'artifact_boundary_check',
      kind: 'artifact_boundary',
      scope: 'all_problems',
      status: 'ready',
      note: 'Rejects claims unsupported by canonical artifacts already present in the pack.',
    },
  ];

  if (problem.cluster === 'number-theory') {
    falsifiers.push({
      falsifier_id: 'exact_interval_counterexample_scan',
      kind: 'exact_verifier',
      scope: 'number_theory',
      status: 'ready',
      note: 'Uses bounded exact interval checks to kill false local claims quickly.',
    });
  }

  if (theoremLoop.currentBridgeState) {
    falsifiers.push({
      falsifier_id: 'bridge_packet_replay',
      kind: 'search_bridge_replay',
      scope: 'bridge_backed_problems',
      status: 'ready',
      note: 'Replays current bridge packets and tracked tails against candidate claims.',
    });
  }

  return falsifiers;
}

function buildGenericVerifierAdapters(problem, theoremLoop) {
  const adapters = [
    {
      adapter_id: 'canonical_artifact_reader',
      kind: 'artifact_reader',
      scope: 'all_problems',
      status: 'ready',
      note: 'Reads theorem-loop, route, and pack artifacts as verifier-facing evidence.',
    },
  ];

  if (problem.cluster === 'number-theory') {
    adapters.push({
      adapter_id: 'exact_small_n',
      kind: 'exact_verifier',
      scope: 'number_theory',
      status: 'ready',
      note: 'Bounded exact verifier for finite interval certification.',
    });
  }

  if (theoremLoop.currentBridgeState) {
    adapters.push({
      adapter_id: 'search_theorem_bridge',
      kind: 'bridge_verifier',
      scope: 'bridge_backed_problems',
      status: 'ready',
      note: 'Supplies live search-side packet and leaderboard evidence to the claim loop.',
    });
  }

  if (problem.problemId === '848' && theoremLoop.currentBridgeState) {
    adapters.push({
      adapter_id: 'p848_family_repair_surface',
      kind: 'problem_adapter',
      scope: 'problem_848',
      status: 'ready',
      note: 'Evaluates candidate claims against tracked-tail repair surfaces and shared-prefix packets.',
    });
  }

  return adapters;
}

function buildCandidateClaims(problem, theoremLoop) {
  const candidates = (theoremLoop.theoremAgenda ?? []).map((item) => ({
    claim_id: item.item_id,
    status: item.status ?? 'ready',
    source: 'theorem_agenda',
    summary: item.task,
    why: item.why ?? null,
    support: (theoremLoop.theoremHooks ?? [])
      .filter((hook) => hook.status === 'supported')
      .map((hook) => hook.hook_id),
  }));

  if (problem.problemId === '848' && theoremLoop.currentBridgeState) {
    const bridgeState = theoremLoop.currentBridgeState;
    candidates.push({
      claim_id: 'p848_next_unmatched_alignment_claim',
      status: 'ready',
      source: 'search_bridge',
      summary: `Shared-prefix representative ${bridgeState.next_unmatched_representative} aligns structurally with the first failure of tail 282.`,
      why: 'If this survives falsification, it upgrades a numerical coincidence into an obstruction-class candidate.',
      support: ['next_unmatched_equals_282_failure'],
    });
    candidates.push({
      claim_id: 'p848_top_repair_cluster_claim',
      status: 'ready',
      source: 'search_bridge',
      summary: `Top repair class ${Array.isArray(bridgeState.top_gpu_tie_class) ? bridgeState.top_gpu_tie_class.join(', ') : '(unknown)'} shares a common repair mechanism.`,
      why: 'A shared mechanism would compress the search frontier into a reusable lemma candidate.',
      support: ['top_repair_class_cluster'],
    });
  }

  return candidates;
}

export function buildProblemTheoremLoop(problem) {
  const paths = getProblemTheoremLoopPaths(problem);
  const contextPath = paths.packProblemDir ? path.join(paths.packProblemDir, 'context.yaml') : null;
  const routePacketPath = paths.packProblemDir ? path.join(paths.packProblemDir, 'ROUTE_PACKET.yaml') : null;
  const frontierNotePath = paths.packProblemDir ? path.join(paths.packProblemDir, 'FRONTIER_NOTE.md') : null;
  const opsDetailsPath = paths.packProblemDir ? path.join(paths.packProblemDir, 'OPS_DETAILS.yaml') : null;

  const context = readYamlIfPresent(contextPath) ?? {};
  const routePacket = readYamlIfPresent(routePacketPath) ?? {};
  const opsDetails = readYamlIfPresent(opsDetailsPath) ?? {};
  const bridge = readJsonIfPresent(paths.legacyBridgeJsonPath);
  const exactIntervalBookkeeping = buildP848ExactIntervalBookkeeping(problem);

  const activeRoute = problem?.researchState?.active_route
    ?? context.default_active_route
    ?? routePacket.route_id
    ?? opsDetails.routes?.[0]?.route_id
    ?? null;

  const activeRouteDetail = Array.isArray(opsDetails.routes)
    ? opsDetails.routes.find((route) => route.route_id === activeRoute) ?? opsDetails.routes[0] ?? null
    : null;
  const activeTicketDetail = Array.isArray(opsDetails.tickets)
    ? opsDetails.tickets.find((ticket) => ticket.status === 'active' && (!activeRoute || ticket.route_id === activeRoute))
      ?? opsDetails.tickets.find((ticket) => !activeRoute || ticket.route_id === activeRoute)
      ?? opsDetails.tickets[0]
      ?? null
    : null;
  const firstReadyAtom = Array.isArray(opsDetails.atoms)
    ? opsDetails.atoms.find((atom) => atom.status === 'ready' && (!activeRoute || atom.route_id === activeRoute))
      ?? opsDetails.atoms.find((atom) => atom.status === 'ready')
      ?? null
    : null;

  const theoremModule = activeRouteDetail?.theorem_module
    || routePacket.theorem_module
    || null;
  const routeBreakthrough = typeof problem?.researchState?.route_breakthrough === 'boolean'
    ? problem.researchState.route_breakthrough
    : false;
  const nextHonestMove = firstReadyAtom?.next_move
    ?? activeTicketDetail?.next_move
    ?? activeRouteDetail?.next_move
    ?? context.next_honest_move
    ?? 'Preserve the active route honestly and tighten the theorem-facing evidence stack without overclaiming.';
  const routeSummary = activeRouteDetail?.summary
    ?? context.route_story
    ?? routePacket.frontier_claim
    ?? problem.shortStatement;
  const currentClaimSurface = getCurrentClaimSurface(problem, {
    bridge,
    theoremModule,
    routeBreakthrough,
  });

  const bridgeBacked = Boolean(bridge?.current_bridge_state);
  const theoremHooks = bridgeBacked
    ? (bridge.candidate_theorem_hooks ?? []).map((hook) => ({
        hook_id: hook.hook_id ?? 'bridge_hook',
        status: hook.status ?? 'supported',
        note: hook.note ?? '',
      }))
    : buildBaselineHooks({
        activeRoute,
        theoremModule,
        firstReadyAtom,
        frontierNotePresent: Boolean(frontierNotePath && fs.existsSync(frontierNotePath)),
      });
  const theoremAgenda = bridgeBacked
    ? buildBridgeBackedAgenda({
        theoremHooks,
        bridgeState: bridge?.current_bridge_state ?? null,
        nextHonestMove,
      })
    : buildBaselineAgenda({
        activeRoute,
        theoremModule,
        firstReadyAtom,
        nextHonestMove,
        currentClaimSurface,
      });

  const sourceRefresh = getSourceRefreshCommand(problem);

  return {
    schema: 'erdos.problem_theorem_loop/1',
    generatedAt: new Date().toISOString(),
    problemId: problem.problemId,
    displayName: problem.displayName,
    title: problem.title,
    cluster: problem.cluster,
    sourceKind: bridgeBacked ? 'search_theorem_bridge' : 'pack_route_state',
    theoremLoopMode: bridgeBacked ? 'bridge_backed' : 'baseline',
    activeRoute,
    theoremModule,
    currentState: {
      siteStatus: problem.siteStatus,
      repoStatus: problem.repoStatus,
      openProblem: typeof problem?.researchState?.open_problem === 'boolean'
        ? problem.researchState.open_problem
        : String(problem.siteStatus ?? '').toLowerCase() === 'open',
      routeBreakthrough,
      problemSolved: typeof problem?.researchState?.problem_solved === 'boolean'
        ? problem.researchState.problem_solved
        : false,
      currentClaimSurface,
      routeSummary,
      nextHonestMove,
      ...(exactIntervalBookkeeping ? { exactIntervalBookkeeping } : {}),
    },
    theoremHooks,
    theoremAgenda,
    currentBridgeState: bridge?.current_bridge_state ?? null,
    commands: {
      problemShow: `erdos problem show ${problem.problemId}`,
      problemArtifacts: `erdos problem artifacts ${problem.problemId}`,
      theoremLoop: `erdos problem theorem-loop ${problem.problemId}`,
      theoremLoopRefresh: `erdos problem theorem-loop-refresh ${problem.problemId}`,
      clusterStatus: getClusterStatusCommand(problem),
      clusterFrontier: getClusterFrontierCommand(problem),
      sourceRefresh: sourceRefresh?.command ?? null,
    },
    sources: {
      packProblemDir: paths.packProblemDir,
      theoremLoopJsonPath: paths.theoremLoopJsonPath,
      theoremLoopMarkdownPath: paths.theoremLoopMarkdownPath,
      contextPath,
      routePacketPath,
      frontierNotePath,
      opsDetailsPath,
      legacyBridgeJsonPath: bridgeBacked ? paths.legacyBridgeJsonPath : null,
      legacyBridgeMarkdownPath: bridgeBacked ? paths.legacyBridgeMarkdownPath : null,
    },
  };
}

export function renderProblemTheoremLoopMarkdown(doc) {
  const lines = [
    `# ${doc.displayName} Theorem Loop`,
    '',
    bridgePreamble(doc),
    '',
    '## Current State',
    '',
    `- Theorem loop mode: \`${doc.theoremLoopMode}\`.`,
    `- Active route: \`${doc.activeRoute ?? '(none)'}\`.`,
    `- Current claim surface: \`${doc.currentState.currentClaimSurface}\`.`,
    `- Repo status: \`${doc.currentState.repoStatus}\`; site status: \`${doc.currentState.siteStatus}\`.`,
    `- Route breakthrough: ${doc.currentState.routeBreakthrough ? '`yes`' : '`no`'}.`,
    `- Problem solved: ${doc.currentState.problemSolved ? '`yes`' : '`no`'}.`,
    `- Open problem: ${doc.currentState.openProblem ? '`yes`' : '`no`'}.`,
    `- Theorem module: ${doc.theoremModule ? `\`${doc.theoremModule}\`` : '`(none)`'}.`,
    `- Route summary: ${doc.currentState.routeSummary}`,
    `- Next honest move: ${doc.currentState.nextHonestMove}`,
  ];
  if (doc.currentState.exactIntervalBookkeeping) {
    lines.push(`- Public raw exact packet interval: \`${doc.currentState.exactIntervalBookkeeping.publicRepoRawExactInterval ?? '(unknown)'}\`.`);
    lines.push(`- Local compact rollout evidence interval: \`${doc.currentState.exactIntervalBookkeeping.localIgnoredRolloutInterval ?? '(unknown)'}\`.`);
  }
  lines.push('', '## Theorem Hooks', '');

  for (const hook of doc.theoremHooks ?? []) {
    lines.push(`- \`${hook.hook_id}\`: ${hook.status}${hook.note ? ` | ${hook.note}` : ''}`);
  }

  lines.push('', '## Theorem Agenda', '');
  for (const item of doc.theoremAgenda ?? []) {
    lines.push(`- \`${item.item_id}\`: ${item.status} | ${item.task}${item.why ? ` | ${item.why}` : ''}`);
  }

  if (doc.currentBridgeState) {
    lines.push('', '## Bridge State', '');
    const bridgeState = doc.currentBridgeState;
    if (bridgeState.shared_prefix_failure_count !== undefined) {
      lines.push(`- Shared-prefix failures frozen: \`${bridgeState.shared_prefix_failure_count}\` through \`${bridgeState.shared_prefix_failure_max_n ?? '(unknown)'}\`.`);
    }
    if (bridgeState.strongest_completed_structured_tail?.continuation !== undefined) {
      lines.push(`- Strongest completed structured tail: \`${bridgeState.strongest_completed_structured_tail.continuation}\` through \`${bridgeState.strongest_completed_structured_tail.clean_through ?? '(unknown)'}\`.`);
    }
    if (bridgeState.current_family_aware_leader?.continuation !== undefined) {
      lines.push(`- Current family-aware leader: \`${bridgeState.current_family_aware_leader.continuation}\`.`);
    }
    if (bridgeState.next_unmatched_representative !== undefined) {
      lines.push(`- Next unmatched representative: \`${bridgeState.next_unmatched_representative}\`.`);
    }
  }

  lines.push('', '## Commands', '');
  lines.push(`- Problem surface: \`${doc.commands.problemShow}\``);
  lines.push(`- Canonical theorem loop: \`${doc.commands.theoremLoop}\``);
  lines.push(`- Refresh theorem loop: \`${doc.commands.theoremLoopRefresh}\``);
  lines.push(`- Problem artifacts: \`${doc.commands.problemArtifacts}\``);
  if (doc.commands.clusterStatus) {
    lines.push(`- Cluster status: \`${doc.commands.clusterStatus}\``);
  }
  if (doc.commands.clusterFrontier) {
    lines.push(`- Cluster frontier: \`${doc.commands.clusterFrontier}\``);
  }
  if (doc.commands.sourceRefresh) {
    lines.push(`- Source refresh: \`${doc.commands.sourceRefresh}\``);
  }

  lines.push('', '## Sources', '');
  for (const [label, value] of Object.entries(doc.sources ?? {})) {
    if (!value) {
      continue;
    }
    lines.push(`- ${label}: \`${value}\``);
  }
  lines.push('');
  return lines.join('\n');
}

function bridgePreamble(doc) {
  if (doc.sourceKind === 'search_theorem_bridge') {
    return 'This theorem loop is generated from a richer search/theorem bridge, then exposed through a generic product-wide theorem-loop surface.';
  }
  return 'This note is the generic theorem-loop surface for the problem pack. It keeps theorem-facing route state visible even when no richer search bridge exists yet.';
}

export function getProblemTheoremLoopSnapshot(problem) {
  const doc = buildProblemTheoremLoop(problem);
  const paths = getProblemTheoremLoopPaths(problem);
  return {
    ...doc,
    theoremLoopJsonPath: paths.theoremLoopJsonPath,
    theoremLoopMarkdownPath: paths.theoremLoopMarkdownPath,
    theoremLoopJsonPresent: Boolean(paths.theoremLoopJsonPath && fs.existsSync(paths.theoremLoopJsonPath)),
    theoremLoopMarkdownPresent: Boolean(paths.theoremLoopMarkdownPath && fs.existsSync(paths.theoremLoopMarkdownPath)),
  };
}

export function buildProblemClaimLoop(problem) {
  const theoremLoop = buildProblemTheoremLoop(problem);
  const paths = getProblemClaimLoopPaths(problem);
  const bridgeBacked = Boolean(theoremLoop.currentBridgeState);

  return {
    schema: 'erdos.problem_claim_loop/1',
    generatedAt: new Date().toISOString(),
    problemId: problem.problemId,
    displayName: problem.displayName,
    title: problem.title,
    cluster: problem.cluster,
    sourceKind: bridgeBacked ? 'theorem_loop_plus_bridge' : 'theorem_loop_only',
    claimLoopMode: bridgeBacked ? 'bridge_backed' : 'baseline',
    currentClaimSurface: theoremLoop.currentState.currentClaimSurface,
    currentState: {
      theoremLoopMode: theoremLoop.theoremLoopMode,
      activeRoute: theoremLoop.activeRoute,
      nextHonestMove: theoremLoop.currentState.nextHonestMove,
      routeSummary: theoremLoop.currentState.routeSummary,
      sourceRefresh: theoremLoop.commands.sourceRefresh ?? null,
      ...(theoremLoop.currentState.exactIntervalBookkeeping
        ? { exactIntervalBookkeeping: theoremLoop.currentState.exactIntervalBookkeeping }
        : {}),
    },
    featureExtractors: buildGenericFeatureExtractors(problem, theoremLoop),
    claimGenerators: buildGenericClaimGenerators(problem, theoremLoop),
    claimFalsifiers: buildGenericClaimFalsifiers(problem, theoremLoop),
    verifierAdapters: buildGenericVerifierAdapters(problem, theoremLoop),
    candidateClaims: buildCandidateClaims(problem, theoremLoop),
    theoremHooks: theoremLoop.theoremHooks ?? [],
    theoremAgenda: theoremLoop.theoremAgenda ?? [],
    commands: {
      problemShow: `erdos problem show ${problem.problemId}`,
      problemArtifacts: `erdos problem artifacts ${problem.problemId}`,
      theoremLoop: theoremLoop.commands.theoremLoop,
      theoremLoopRefresh: theoremLoop.commands.theoremLoopRefresh,
      claimLoop: `erdos problem claim-loop ${problem.problemId}`,
      claimLoopRefresh: `erdos problem claim-loop-refresh ${problem.problemId}`,
      sourceRefresh: theoremLoop.commands.sourceRefresh ?? null,
    },
    sources: {
      claimLoopJsonPath: paths.claimLoopJsonPath,
      claimLoopMarkdownPath: paths.claimLoopMarkdownPath,
      theoremLoopJsonPath: theoremLoop.sources.theoremLoopJsonPath ?? theoremLoop.sources.theoremLoopPath ?? null,
      theoremLoopMarkdownPath: theoremLoop.sources.theoremLoopMarkdownPath ?? null,
      legacyBridgeJsonPath: theoremLoop.sources.legacyBridgeJsonPath ?? null,
      legacyBridgeMarkdownPath: theoremLoop.sources.legacyBridgeMarkdownPath ?? null,
      packProblemDir: theoremLoop.sources.packProblemDir ?? null,
    },
  };
}

export function renderProblemClaimLoopMarkdown(doc) {
  const lines = [
    `# ${doc.displayName} Claim Loop`,
    '',
    doc.sourceKind === 'theorem_loop_plus_bridge'
      ? 'This claim loop generalizes theorem-search-verification work using the theorem loop plus richer bridge-backed search evidence.'
      : 'This claim loop generalizes theorem-search-verification work directly from the canonical theorem loop, even when no richer bridge is present yet.',
    '',
    '## Current State',
    '',
    `- Claim loop mode: \`${doc.claimLoopMode}\`.`,
    `- Current claim surface: \`${doc.currentClaimSurface}\`.`,
    `- Active route: \`${doc.currentState.activeRoute ?? '(none)'}\`.`,
    `- Route summary: ${doc.currentState.routeSummary}`,
    `- Next honest move: ${doc.currentState.nextHonestMove}`,
  ];
  if (doc.currentState.exactIntervalBookkeeping) {
    lines.push(`- Public raw exact packet interval: \`${doc.currentState.exactIntervalBookkeeping.publicRepoRawExactInterval ?? '(unknown)'}\`.`);
    lines.push(`- Local compact rollout evidence interval: \`${doc.currentState.exactIntervalBookkeeping.localIgnoredRolloutInterval ?? '(unknown)'}\`.`);
  }
  lines.push('', '## Feature Extractors', '');

  for (const extractor of doc.featureExtractors ?? []) {
    lines.push(`- \`${extractor.extractor_id}\`: ${extractor.status} | ${extractor.note}`);
  }

  lines.push('', '## Claim Generators', '');
  for (const generator of doc.claimGenerators ?? []) {
    lines.push(`- \`${generator.generator_id}\`: ${generator.status} | ${generator.note}`);
  }

  lines.push('', '## Claim Falsifiers', '');
  for (const falsifier of doc.claimFalsifiers ?? []) {
    lines.push(`- \`${falsifier.falsifier_id}\`: ${falsifier.status} | ${falsifier.note}`);
  }

  lines.push('', '## Verifier Adapters', '');
  for (const adapter of doc.verifierAdapters ?? []) {
    lines.push(`- \`${adapter.adapter_id}\`: ${adapter.status} | ${adapter.note}`);
  }

  lines.push('', '## Candidate Claims', '');
  for (const claim of doc.candidateClaims ?? []) {
    lines.push(`- \`${claim.claim_id}\`: ${claim.status} | ${claim.summary}${claim.why ? ` | ${claim.why}` : ''}`);
  }

  lines.push('', '## Commands', '');
  lines.push(`- Problem surface: \`${doc.commands.problemShow}\``);
  lines.push(`- Problem artifacts: \`${doc.commands.problemArtifacts}\``);
  lines.push(`- Theorem loop: \`${doc.commands.theoremLoop}\``);
  lines.push(`- Theorem refresh: \`${doc.commands.theoremLoopRefresh}\``);
  lines.push(`- Claim loop: \`${doc.commands.claimLoop}\``);
  lines.push(`- Claim refresh: \`${doc.commands.claimLoopRefresh}\``);
  if (doc.commands.sourceRefresh) {
    lines.push(`- Source refresh: \`${doc.commands.sourceRefresh}\``);
  }

  lines.push('', '## Sources', '');
  for (const [label, value] of Object.entries(doc.sources ?? {})) {
    if (!value) {
      continue;
    }
    lines.push(`- ${label}: \`${value}\``);
  }
  lines.push('');
  return lines.join('\n');
}

export function getProblemClaimLoopSnapshot(problem) {
  const doc = buildProblemClaimLoop(problem);
  const paths = getProblemClaimLoopPaths(problem);
  return {
    ...doc,
    claimLoopJsonPath: paths.claimLoopJsonPath,
    claimLoopMarkdownPath: paths.claimLoopMarkdownPath,
    claimLoopJsonPresent: Boolean(paths.claimLoopJsonPath && fs.existsSync(paths.claimLoopJsonPath)),
    claimLoopMarkdownPresent: Boolean(paths.claimLoopMarkdownPath && fs.existsSync(paths.claimLoopMarkdownPath)),
  };
}

function parseClosedIntegerRange(rangeText) {
  const match = String(rangeText ?? '').trim().match(/^(\d+)\.\.(\d+)$/);
  if (!match) {
    return null;
  }
  return {
    min: Number(match[1]),
    max: Number(match[2]),
  };
}

function getLatestVerifiedInterval(intervalQueue) {
  const intervals = Array.isArray(intervalQueue?.intervals) ? intervalQueue.intervals : [];
  const verified = intervals
    .filter((interval) => interval.status === 'done' && interval.claim_level === 'verified')
    .map((interval) => ({
      ...interval,
      parsedRange: parseClosedIntegerRange(interval.range),
    }))
    .filter((interval) => interval.parsedRange);

  if (verified.length === 0) {
    return null;
  }

  verified.sort((left, right) => left.parsedRange.max - right.parsedRange.max);
  return verified.at(-1);
}

function buildHookAssessment(hook, bridgeHook, theoremLoop, bridgeDoc) {
  const currentBridgeState = theoremLoop.currentBridgeState ?? {};
  const trackedTailMatrix = Array.isArray(bridgeDoc?.tracked_tail_matrix) ? bridgeDoc.tracked_tail_matrix : [];
  const gpuLeaderboard = Array.isArray(bridgeDoc?.gpu_leaderboard) ? bridgeDoc.gpu_leaderboard : [];
  const note = bridgeHook?.detail ?? hook.note ?? null;

  let verdict = hook.status === 'supported' ? 'supported' : 'unresolved';
  let evidenceClass = theoremLoop.currentBridgeState ? 'bridge_state' : 'pack_route_state';
  let theoremReady = false;
  let rationale = note;
  let nextAction = null;

  switch (hook.hook_id) {
    case 'next_unmatched_equals_282_failure': {
      const nextRepresentative = currentBridgeState.next_unmatched_representative;
      const tail282 = trackedTailMatrix.find((entry) => entry.continuation === 282) ?? null;
      const supported = Boolean(
        currentBridgeState.next_unmatched_matches_282_failure
        && nextRepresentative !== undefined
        && tail282?.effective_first_failure === nextRepresentative,
      );
      verdict = supported ? 'supported' : (nextRepresentative === undefined ? 'unresolved' : 'broken');
      evidenceClass = 'search_bridge_alignment';
      rationale = supported
        ? `Shared-prefix representative ${nextRepresentative} matches tracked tail 282 first failure ${tail282.effective_first_failure}.`
        : (note ?? 'The current bridge no longer certifies the 282-alignment claim.');
      nextAction = 'formalize_alignment_mechanism';
      break;
    }
    case 'completed_tail_vs_search_leader_split': {
      const completed = currentBridgeState.strongest_completed_structured_tail?.continuation;
      const leader = currentBridgeState.current_family_aware_leader?.continuation;
      const supported = completed !== undefined && leader !== undefined && completed !== leader;
      verdict = supported ? 'supported' : ((completed === undefined || leader === undefined) ? 'unresolved' : 'broken');
      evidenceClass = 'search_bridge_split';
      rationale = supported
        ? `Completed structured tail ${completed} differs from family-aware leader ${leader} on the live bridge.`
        : (note ?? 'The bridge does not currently show a meaningful completed-tail versus leader split.');
      nextAction = 'explain_search_leader_split';
      break;
    }
    case 'repair_pool_not_closed': {
      const expansions = Array.isArray(currentBridgeState.recent_pool_expansion_moduli)
        ? currentBridgeState.recent_pool_expansion_moduli
        : [];
      const supported = expansions.length > 0;
      verdict = supported ? 'supported' : 'unresolved';
      evidenceClass = 'bridge_packet_growth';
      rationale = supported
        ? `Recent bridge packets introduced new square moduli: ${expansions.join(', ')}.`
        : (note ?? 'No recent pool-expansion evidence is frozen in the bridge right now.');
      nextAction = 'model_repair_pool_growth';
      break;
    }
    case 'top_repair_class_cluster': {
      const tieClass = Array.isArray(currentBridgeState.top_gpu_tie_class) ? currentBridgeState.top_gpu_tie_class : [];
      const rows = gpuLeaderboard.filter((row) => tieClass.includes(row.continuation));
      const supported = tieClass.length >= 2
        && rows.length === tieClass.length
        && rows.every((row) => row.repaired_known_packets === rows[0].repaired_known_packets
          && row.repaired_predicted_families === rows[0].repaired_predicted_families
          && row.effective_clean_through === rows[0].effective_clean_through);
      verdict = supported ? 'supported' : (tieClass.length === 0 ? 'unresolved' : 'broken');
      evidenceClass = 'gpu_leaderboard_cluster';
      rationale = supported
        ? `Tie class ${tieClass.join(', ')} shares repaired-known=${rows[0].repaired_known_packets}, repaired-predicted=${rows[0].repaired_predicted_families}, clean-through=${rows[0].effective_clean_through}.`
        : (note ?? 'The current leaderboard does not preserve a stable repair cluster.');
      nextAction = 'formalize_repair_cluster_mechanism';
      break;
    }
    case 'active_route_recorded':
      verdict = theoremLoop.activeRoute ? 'supported' : 'unresolved';
      evidenceClass = 'route_state';
      nextAction = 'promote_route_claim';
      break;
    case 'theorem_module_registered':
      verdict = theoremLoop.theoremModule ? 'supported' : 'unresolved';
      evidenceClass = 'theorem_module';
      nextAction = 'stabilize_theorem_module_boundary';
      break;
    case 'ready_atom_present':
      verdict = (theoremLoop.theoremAgenda ?? []).some((item) => item.item_id === 'promote_ready_atom') ? 'supported' : 'unresolved';
      evidenceClass = 'ready_atom';
      nextAction = 'promote_ready_atom';
      break;
    case 'frontier_note_present':
      evidenceClass = 'frontier_note';
      nextAction = 'anchor_frontier_note';
      break;
    case 'theorem_loop_seeded':
      evidenceClass = 'theorem_loop';
      nextAction = 'seed_theorem_lane';
      break;
    default:
      break;
  }

  return {
    hook_id: hook.hook_id,
    verdict,
    status: hook.status ?? null,
    evidenceClass,
    theoremReady,
    rationale: rationale ?? 'No further hook-specific rationale recorded yet.',
    nextAction,
  };
}

function buildClaimAssessment(problem, claim, theoremLoop, claimLoop, hookAssessments, bridgeDoc, intervalQueue) {
  const currentBridgeState = theoremLoop.currentBridgeState ?? {};
  const trackedTailMatrix = Array.isArray(bridgeDoc?.tracked_tail_matrix) ? bridgeDoc.tracked_tail_matrix : [];
  const gpuLeaderboard = Array.isArray(bridgeDoc?.gpu_leaderboard) ? bridgeDoc.gpu_leaderboard : [];
  const latestVerifiedInterval = getLatestVerifiedInterval(intervalQueue);
  const supportingHooks = Array.isArray(claim.support) ? claim.support : [];
  const supportedSupportCount = hookAssessments.filter((item) => supportingHooks.includes(item.hook_id) && item.verdict === 'supported').length;
  const allSupportingHooksSupported = supportingHooks.length > 0 && supportedSupportCount === supportingHooks.length;

  let verdict = claim.source === 'theorem_agenda' ? 'actionable' : 'unresolved';
  let evidenceClass = claim.source === 'search_bridge' ? 'search_bridge' : 'theorem_agenda';
  let theoremReady = false;
  let rationale = claim.why ?? claim.summary;
  let nextAction = null;

  if (claim.source === 'theorem_agenda') {
    switch (claim.claim_id) {
      case 'choose_next_finite_gap_move':
        nextAction = latestVerifiedInterval
          ? `decide_post_${latestVerifiedInterval.parsedRange.max}_verification_lane`
          : 'choose_next_finite_gap_move';
        rationale = latestVerifiedInterval
          ? `The current canonical exact base is ${latestVerifiedInterval.range}; the next interval is still open.`
          : rationale;
        break;
      case 'explain_next_unmatched_alignment':
        nextAction = 'formalize_alignment_mechanism';
        break;
      case 'explain_completed_vs_search_leader_split':
        nextAction = 'explain_search_leader_split';
        break;
      case 'model_repair_pool_growth':
        nextAction = 'model_repair_pool_growth';
        break;
      case 'characterize_top_repair_cluster':
        nextAction = 'formalize_repair_cluster_mechanism';
        break;
      case 'promote_ready_atom':
        nextAction = 'promote_ready_atom';
        break;
      case 'stabilize_theorem_module_boundary':
        nextAction = 'stabilize_theorem_module_boundary';
        break;
      case 'tighten_active_route_claim':
        nextAction = 'tighten_active_route_claim';
        break;
      default:
        nextAction = claim.claim_id;
        break;
    }

    return {
      claim_id: claim.claim_id,
      source: claim.source,
      verdict,
      evidenceClass,
      theoremReady,
      supportSatisfied: allSupportingHooksSupported,
      summary: claim.summary,
      rationale,
      nextAction,
    };
  }

  if (problem.problemId === '848' && claim.claim_id === 'p848_next_unmatched_alignment_claim') {
    const nextRepresentative = currentBridgeState.next_unmatched_representative;
    const tail282 = trackedTailMatrix.find((entry) => entry.continuation === 282) ?? null;
    const supported = Boolean(
      currentBridgeState.next_unmatched_matches_282_failure
      && nextRepresentative !== undefined
      && tail282?.effective_first_failure === nextRepresentative,
    );
    verdict = supported ? 'supported' : (nextRepresentative === undefined ? 'unresolved' : 'broken');
    evidenceClass = 'search_bridge_alignment';
    rationale = supported
      ? `The bridge matches shared-prefix representative ${nextRepresentative} with tracked tail 282 first failure ${tail282.effective_first_failure}.`
      : 'The current bridge payload does not support the 282-alignment claim.';
    nextAction = 'formalize_alignment_mechanism';
  } else if (problem.problemId === '848' && claim.claim_id === 'p848_top_repair_cluster_claim') {
    const tieClass = Array.isArray(currentBridgeState.top_gpu_tie_class) ? currentBridgeState.top_gpu_tie_class : [];
    const rows = gpuLeaderboard.filter((row) => tieClass.includes(row.continuation));
    const supported = tieClass.length >= 2
      && rows.length === tieClass.length
      && rows.every((row) => row.repaired_known_packets === rows[0].repaired_known_packets
        && row.repaired_predicted_families === rows[0].repaired_predicted_families
        && row.effective_clean_through === rows[0].effective_clean_through);
    verdict = supported ? 'supported' : (tieClass.length === 0 ? 'unresolved' : 'broken');
    evidenceClass = 'gpu_leaderboard_cluster';
    rationale = supported
      ? `Top cluster ${tieClass.join(', ')} shares repaired-known=${rows[0].repaired_known_packets}, repaired-predicted=${rows[0].repaired_predicted_families}, clean-through=${rows[0].effective_clean_through}.`
      : 'The current leaderboard does not preserve a stable shared repair cluster.';
    nextAction = 'formalize_repair_cluster_mechanism';
  }

  return {
    claim_id: claim.claim_id,
    source: claim.source,
    verdict,
    evidenceClass,
    theoremReady,
    supportSatisfied: allSupportingHooksSupported,
    summary: claim.summary,
    rationale,
    nextAction,
  };
}

function buildClaimPassRecommendations(problem, theoremLoop, claimAssessments, hookAssessments, intervalQueue) {
  const recommendations = [];
  const latestVerifiedInterval = getLatestVerifiedInterval(intervalQueue);

  const addRecommendation = (recommendation) => {
    if (!recommendations.some((item) => item.recommendation_id === recommendation.recommendation_id)) {
      recommendations.push(recommendation);
    }
  };

  const supportedClaims = claimAssessments.filter((claim) => claim.verdict === 'supported');

  for (const claim of supportedClaims) {
    if (claim.claim_id === 'p848_next_unmatched_alignment_claim') {
      addRecommendation({
        recommendation_id: 'formalize_282_alignment',
        priority: 'high',
        lane: 'theorem_formalization',
        reason: claim.rationale,
        command: `erdos problem formalization ${problem.problemId}`,
      });
    }
    if (claim.claim_id === 'p848_top_repair_cluster_claim') {
      addRecommendation({
        recommendation_id: 'formalize_top_repair_cluster',
        priority: 'high',
        lane: 'theorem_formalization',
        reason: claim.rationale,
        command: `erdos problem formalization ${problem.problemId}`,
      });
    }
  }

  if (problem.problemId === '848' && latestVerifiedInterval) {
    addRecommendation({
      recommendation_id: `decide_post_${latestVerifiedInterval.parsedRange.max}_verification_lane`,
      priority: 'high',
      lane: 'exact_verifier',
      reason: `The canonical exact base currently ends at ${latestVerifiedInterval.range}. The next verification move is still open.`,
      command: `erdos number-theory dispatch ${problem.problemId}`,
    });
  }

  if (recommendations.length === 0) {
    const actionableClaim = claimAssessments.find((claim) => claim.verdict === 'actionable');
    if (actionableClaim) {
      addRecommendation({
        recommendation_id: actionableClaim.nextAction ?? actionableClaim.claim_id,
        priority: 'medium',
        lane: actionableClaim.source === 'theorem_agenda' ? 'theorem_formalization' : 'claim_followup',
        reason: actionableClaim.rationale,
        command: actionableClaim.source === 'theorem_agenda'
          ? `erdos problem formalization ${problem.problemId}`
          : `erdos problem claim-pass ${problem.problemId}`,
      });
    }
  }

  for (const hook of hookAssessments) {
    if (hook.hook_id === 'repair_pool_not_closed' && hook.verdict === 'supported') {
      addRecommendation({
        recommendation_id: 'model_repair_pool_growth',
        priority: 'medium',
        lane: 'theorem_formalization',
        reason: hook.rationale,
        command: `erdos problem formalization ${problem.problemId}`,
      });
    }
  }

  return recommendations;
}

function buildClaimPassSummary(hookAssessments, claimAssessments) {
  const summarize = (items) => ({
    total: items.length,
    supported: items.filter((item) => item.verdict === 'supported').length,
    actionable: items.filter((item) => item.verdict === 'actionable').length,
    unresolved: items.filter((item) => item.verdict === 'unresolved').length,
    broken: items.filter((item) => item.verdict === 'broken').length,
  });

  return {
    hooks: summarize(hookAssessments),
    claims: summarize(claimAssessments),
  };
}

function titleCaseWords(text) {
  return String(text ?? '')
    .split(/[_\s-]+/)
    .filter(Boolean)
    .map((word) => word.charAt(0).toUpperCase() + word.slice(1))
    .join(' ');
}

function positiveMod(value, modulus) {
  const remainder = Number(value) % Number(modulus);
  return remainder < 0 ? remainder + Number(modulus) : remainder;
}

function gcdInt(left, right) {
  let a = Math.abs(Number(left));
  let b = Math.abs(Number(right));
  while (b !== 0) {
    const next = a % b;
    a = b;
    b = next;
  }
  return a;
}

function extendedGcdInt(left, right) {
  let oldR = Number(left);
  let r = Number(right);
  let oldS = 1;
  let s = 0;
  let oldT = 0;
  let t = 1;

  while (r !== 0) {
    const quotient = Math.trunc(oldR / r);
    [oldR, r] = [r, oldR - quotient * r];
    [oldS, s] = [s, oldS - quotient * s];
    [oldT, t] = [t, oldT - quotient * t];
  }

  return {
    gcd: oldR,
    x: oldS,
    y: oldT,
  };
}

function modularInverseInt(value, modulus) {
  const reduced = positiveMod(value, modulus);
  const result = extendedGcdInt(reduced, modulus);
  if (Math.abs(result.gcd) !== 1) {
    return null;
  }
  return positiveMod(result.x, modulus);
}

function solveLinearCongruenceNonnegative(coeff, rhs, modulus) {
  const safeModulus = Number(modulus);
  if (!Number.isInteger(safeModulus) || safeModulus <= 0) {
    return null;
  }

  const reducedCoeff = positiveMod(coeff, safeModulus);
  const reducedRhs = positiveMod(rhs, safeModulus);
  const divisor = gcdInt(reducedCoeff, safeModulus);
  if (reducedRhs % divisor !== 0) {
    return {
      solvable: false,
      gcdCoeffModulus: divisor,
      solution: null,
      period: null,
    };
  }

  const coeffQuotient = reducedCoeff / divisor;
  const rhsQuotient = reducedRhs / divisor;
  const modulusQuotient = safeModulus / divisor;
  const inverse = modularInverseInt(coeffQuotient, modulusQuotient);
  if (inverse === null) {
    return {
      solvable: false,
      gcdCoeffModulus: divisor,
      solution: null,
      period: null,
    };
  }

  return {
    solvable: true,
    gcdCoeffModulus: divisor,
    solution: positiveMod(inverse * rhsQuotient, modulusQuotient),
    period: modulusQuotient,
  };
}

function positiveModBigInt(value, modulus) {
  const bigValue = BigInt(value);
  const bigModulus = BigInt(modulus);
  let remainder = bigValue % bigModulus;
  if (remainder < 0n) {
    remainder += bigModulus;
  }
  return remainder;
}

function extendedGcdBigInt(left, right) {
  let oldR = BigInt(left);
  let r = BigInt(right);
  let oldS = 1n;
  let s = 0n;
  let oldT = 0n;
  let t = 1n;

  while (r !== 0n) {
    const quotient = oldR / r;
    [oldR, r] = [r, oldR - quotient * r];
    [oldS, s] = [s, oldS - quotient * s];
    [oldT, t] = [t, oldT - quotient * t];
  }

  return {
    gcd: oldR,
    x: oldS,
    y: oldT,
  };
}

function modularInverseBigInt(value, modulus) {
  const reduced = positiveModBigInt(value, modulus);
  const result = extendedGcdBigInt(reduced, modulus);
  if (result.gcd !== 1n && result.gcd !== -1n) {
    return null;
  }
  return positiveModBigInt(result.x, modulus);
}

function toJsonInteger(value) {
  if (typeof value !== 'bigint') {
    return value;
  }
  const asNumber = Number(value);
  return Number.isSafeInteger(asNumber) ? asNumber : value.toString();
}

function deriveTupleRowCrt(tupleRows, witnessSquareModulus) {
  if (!Array.isArray(tupleRows) || tupleRows.length === 0) {
    return null;
  }

  let residue = 0n;
  let modulus = 1n;
  const steps = [];
  const witness = witnessSquareModulus === null || witnessSquareModulus === undefined
    ? null
    : BigInt(witnessSquareModulus);

  for (const row of tupleRows) {
    const rowModulus = BigInt(row.squareModulus);
    const rowResidue = BigInt(row.residue);
    const inverse = modularInverseBigInt(modulus, rowModulus);
    if (inverse === null) {
      return null;
    }
    const stepFactor = positiveModBigInt((rowResidue - residue) * inverse, rowModulus);
    const preCombinedResidue = residue;
    const preCombinedModulus = modulus;
    residue = residue + modulus * stepFactor;
    modulus *= rowModulus;
    residue = positiveModBigInt(residue, modulus);
    steps.push({
      anchor: row.anchor,
      rowSquareModulus: row.squareModulus,
      rowResidue: row.residue,
      preCombinedResidue: toJsonInteger(preCombinedResidue),
      preCombinedModulus: toJsonInteger(preCombinedModulus),
      liftParameter: toJsonInteger(stepFactor),
      combinedResidue: toJsonInteger(residue),
      combinedModulus: toJsonInteger(modulus),
      residueModWitness: witness === null ? null : toJsonInteger(positiveModBigInt(residue, witness)),
    });
  }

  const finalProjectedResidue = witness === null ? null : toJsonInteger(positiveModBigInt(residue, witness));
  const firstStableProjectionStep = witness === null
    ? null
    : (() => {
      const finalResidue = positiveModBigInt(residue, witness);
      for (let index = 0; index < steps.length; index += 1) {
        const suffixStable = steps.slice(index).every((step) => BigInt(step.residueModWitness) === finalResidue);
        if (suffixStable) {
          return steps[index].anchor;
        }
      }
      return null;
    })();

  return {
    combinedResidue: toJsonInteger(residue),
    combinedModulus: toJsonInteger(modulus),
    projectedResidueModuloWitness: finalProjectedResidue,
    firstStableProjectionAnchor: firstStableProjectionStep,
    steps,
  };
}

function getRequiredFailureResidue(anchor, witnessSquareModulus) {
  if (!witnessSquareModulus || gcdInt(anchor, witnessSquareModulus) !== 1) {
    return null;
  }
  const inverse = modularInverseInt(anchor, witnessSquareModulus);
  return inverse === null ? null : positiveMod(-inverse, witnessSquareModulus);
}

function deriveTupleRowActivationSequence(tupleRows, repairRows, witnessSquareModulus) {
  const tupleRowCrtDerivation = deriveTupleRowCrt(tupleRows, witnessSquareModulus);
  if (!tupleRowCrtDerivation || !witnessSquareModulus) {
    return [];
  }

  const trackedFailureResidues = (Array.isArray(repairRows) ? repairRows : []).map((row) => ({
    anchor: row.anchor,
    requiredNResidueForFailure: getRequiredFailureResidue(row.anchor, witnessSquareModulus),
  }));

  return tupleRowCrtDerivation.steps.map((step) => {
    const matchingTrackedAnchors = trackedFailureResidues
      .filter((row) => row.requiredNResidueForFailure !== null && row.requiredNResidueForFailure === Number(step.residueModWitness))
      .map((row) => row.anchor);
    return {
      anchor: step.anchor,
      residueModWitness: Number(step.residueModWitness),
      matchingTrackedAnchors,
      uniqueTrackedMatch: matchingTrackedAnchors.length === 1 ? matchingTrackedAnchors[0] : null,
    };
  });
}

function summarizeP848MenuActivationPatterns(allFamilies) {
  const rows = [];

  for (const [familyIndex, family] of (Array.isArray(allFamilies) ? allFamilies : []).entries()) {
    const repairRows = Array.isArray(family?.repairRows) ? family.repairRows : [];
    for (const repairRow of repairRows) {
      if (repairRow?.squarefree !== false || !Array.isArray(repairRow.squareWitnesses)) {
        continue;
      }
      for (const witness of repairRow.squareWitnesses) {
        const witnessSquareModulus = witness?.squareModulus ?? null;
        const activationSequence = deriveTupleRowActivationSequence(
          Array.isArray(family?.tupleRows) ? family.tupleRows : [],
          repairRows,
          witnessSquareModulus,
        );
        const firstMatch = activationSequence.find((step) => step.matchingTrackedAnchors.length > 0) ?? null;
        rows.push({
          familyIndex,
          representative: family?.representative ?? null,
          tupleKey: family?.tupleKey ?? null,
          failingAnchor: repairRow.anchor,
          witnessSquareModulus,
          firstMatchAnchor: firstMatch?.anchor ?? null,
          firstMatchTrackedAnchors: firstMatch?.matchingTrackedAnchors ?? [],
          firstMatchUniqueTrackedAnchor: firstMatch?.uniqueTrackedMatch ?? null,
          firstMatchIsFailingAnchor: firstMatch?.uniqueTrackedMatch === repairRow.anchor,
          activationSequence,
        });
      }
    }
  }

  const countBy = (key) => rows.reduce((accumulator, row) => {
    const value = row[key] ?? 'none';
    accumulator[value] = (accumulator[value] ?? 0) + 1;
    return accumulator;
  }, {});
  const rowsWith132TargetActivation = rows.filter((row) => row.firstMatchAnchor === 132 && row.firstMatchIsFailingAnchor);

  return {
    totalFailingWitnessRows: rows.length,
    firstMatchAnchorCounts: countBy('firstMatchAnchor'),
    targetAtFirstMatchCount: rows.filter((row) => row.firstMatchIsFailingAnchor).length,
    rowsWith132TargetActivationCount: rowsWith132TargetActivation.length,
    rowsWith132TargetActivationByFailingAnchor: rowsWith132TargetActivation.reduce((accumulator, row) => {
      accumulator[row.failingAnchor] = (accumulator[row.failingAnchor] ?? 0) + 1;
      return accumulator;
    }, {}),
    rowsWith132TargetActivationByWitness: rowsWith132TargetActivation.reduce((accumulator, row) => {
      accumulator[row.witnessSquareModulus] = (accumulator[row.witnessSquareModulus] ?? 0) + 1;
      return accumulator;
    }, {}),
    targetActivationRows: rowsWith132TargetActivation.map((row) => ({
      familyIndex: row.familyIndex,
      representative: row.representative,
      failingAnchor: row.failingAnchor,
      witnessSquareModulus: row.witnessSquareModulus,
      firstMatchAnchor: row.firstMatchAnchor,
      firstMatchTrackedAnchors: row.firstMatchTrackedAnchors,
      tupleKey: row.tupleKey,
      activationSequence: row.activationSequence.map((step) => ({
        anchor: step.anchor,
        residueModWitness: step.residueModWitness,
        matchingTrackedAnchors: step.matchingTrackedAnchors,
        uniqueTrackedMatch: step.uniqueTrackedMatch,
      })),
    })),
    examples: rowsWith132TargetActivation.slice(0, 8).map((row) => ({
      familyIndex: row.familyIndex,
      representative: row.representative,
      failingAnchor: row.failingAnchor,
      witnessSquareModulus: row.witnessSquareModulus,
      tupleKey: row.tupleKey,
      activationSequence: row.activationSequence.map((step) => ({
        anchor: step.anchor,
        residueModWitness: step.residueModWitness,
        matchingTrackedAnchors: step.matchingTrackedAnchors,
      })),
    })),
  };
}

function buildP848ActivationLemmaSchema({
  menuActivationSurvey,
  tupleRowActivationBoundary,
  tupleRowActivationSequence,
  representative,
  tupleKey,
  witnessSquareModulus,
  representativeResidueModuloWitness,
  familyMenuPath,
}) {
  const certifiedRows = Array.isArray(menuActivationSurvey?.targetActivationRows)
    ? menuActivationSurvey.targetActivationRows
    : [];
  if (certifiedRows.length === 0) {
    return null;
  }

  const activatedAnchors = Object.keys(menuActivationSurvey.rowsWith132TargetActivationByFailingAnchor ?? {})
    .map((value) => Number(value))
    .filter((value) => Number.isFinite(value))
    .sort((left, right) => left - right);
  const witnessSquareModuli = Object.keys(menuActivationSurvey.rowsWith132TargetActivationByWitness ?? {})
    .map((value) => Number(value))
    .filter((value) => Number.isFinite(value))
    .sort((left, right) => left - right);

  return {
    schemaId: 'p848_finite_menu_132_target_activation_schema_v1',
    status: 'finite_menu_schema_ready',
    scope: {
      problemId: '848',
      evidenceSurface: 'current_finite_family_menu',
      universalClaim: false,
      certifiedRowCount: certifiedRows.length,
      totalFailingWitnessRows: menuActivationSurvey.totalFailingWitnessRows,
      activatedTrackedAnchors: activatedAnchors,
      witnessSquareModuli,
      familyMenuPath,
    },
    informalStatement: 'For each certified finite-menu witness row in this packet, the tuple-row CRT projection has no tracked failure-residue match before anchor 132; anchor 132 is the first step whose projected residue matches the failing tracked tail; anchor 182 preserves that match on the current six-row menu.',
    hypotheses: [
      {
        hypothesisId: 'H1_finite_menu_row',
        text: 'The row is one of the current finite family-menu rows with a tracked repair anchor a and square witness q^2 for a*n+1.',
      },
      {
        hypothesisId: 'H2_tuple_crt_projection',
        text: 'The tuple rows are replayed in anchor order, and each CRT prefix is projected modulo the same witness q^2.',
      },
      {
        hypothesisId: 'H3_failure_residue_formula',
        text: 'For every tracked anchor b coprime to q^2, the witness failure residue is n = -b^{-1} mod q^2; non-coprime anchors are marked unsolvable for that witness.',
      },
      {
        hypothesisId: 'H4_pre_132_clear',
        text: 'No tuple-row CRT prefix before anchor 132 lands on any tracked witness-failure residue modulo q^2.',
      },
      {
        hypothesisId: 'H5_132_unique_target_activation',
        text: 'The anchor-132 CRT prefix lands on exactly one tracked witness-failure residue, and that tracked anchor is the failing repair anchor a.',
      },
      {
        hypothesisId: 'H6_182_preservation',
        text: 'The anchor-182 CRT prefix preserves the same unique tracked witness-failure match and does not activate a competing tracked anchor.',
      },
    ],
    conclusion: {
      text: 'Inside the current finite family menu, the row has a controlled 132 target-activation certificate rather than an unexplained one-row coincidence.',
      outputs: [
        'firstTrackedActivationAnchor = 132',
        'firstTrackedActivationAnchorMatchesFailingAnchor = true',
        'anchor182PreservesTargetActivation = true',
      ],
    },
    falsifierBoundary: [
      {
        falsifierId: 'pre_132_tracked_match',
        text: 'A replayed row has a tracked witness-failure residue match at anchor 7, 32, 57, or 82.',
      },
      {
        falsifierId: 'wrong_132_target',
        text: 'Anchor 132 activates no tracked anchor, multiple tracked anchors, or a tracked anchor different from the failing repair anchor.',
      },
      {
        falsifierId: 'lost_182_preservation',
        text: 'Anchor 182 changes the projection so the target activation is no longer the unique tracked match.',
      },
      {
        falsifierId: 'menu_refresh_breaks_certificate',
        text: 'A refreshed finite menu changes the witness rows, tuple rows, or repair rows so the 17 row certificates no longer replay.',
      },
      {
        falsifierId: 'scope_overclaim',
        text: 'The schema is used as a universal theorem without first proving the symbolic CRT hypotheses beyond the current finite menu.',
      },
    ],
    currentBoundaryInstance: {
      representative,
      tupleKey,
      failingAnchor: 282,
      witnessSquareModulus,
      representativeResidueModuloWitness,
      activationBoundary: tupleRowActivationBoundary,
      activationSequence: tupleRowActivationSequence,
    },
    rowCertificates: certifiedRows,
    nextProofObligations: [
      'Replay the 17 row certificates from tuple-row CRT equations in a dedicated checker rather than trusting the summarized packet data.',
      'Decide whether the schema can be lifted from the current finite menu to a symbolic CRT lemma for a reusable obstruction family.',
      'Keep the finite-menu scope explicit until the symbolic lift is proved.',
    ],
  };
}

function checkP848ActivationLemmaCertificates(allFamilies, familyMenuPath) {
  const survey = summarizeP848MenuActivationPatterns(allFamilies);
  const certifiedRows = Array.isArray(survey.targetActivationRows) ? survey.targetActivationRows : [];
  const rowChecks = certifiedRows.map((row) => {
    const activationSequence = Array.isArray(row.activationSequence) ? row.activationSequence : [];
    const pre132Steps = activationSequence.filter((step) => Number(step.anchor) < 132);
    const step132 = activationSequence.find((step) => Number(step.anchor) === 132) ?? null;
    const step182 = activationSequence.find((step) => Number(step.anchor) === 182) ?? null;
    const firstTrackedMatch = activationSequence.find((step) => (
      Array.isArray(step.matchingTrackedAnchors) && step.matchingTrackedAnchors.length > 0
    )) ?? null;
    const pre132HasNoTrackedMatch = pre132Steps.every((step) => (
      Array.isArray(step.matchingTrackedAnchors) && step.matchingTrackedAnchors.length === 0
    ));
    const firstMatchIs132 = Number(firstTrackedMatch?.anchor) === 132;
    const activation132MatchesOnlyFailingAnchor = Array.isArray(step132?.matchingTrackedAnchors)
      && step132.matchingTrackedAnchors.length === 1
      && Number(step132.matchingTrackedAnchors[0]) === Number(row.failingAnchor);
    const preservation182KeepsOnlyFailingAnchor = Array.isArray(step182?.matchingTrackedAnchors)
      && step182.matchingTrackedAnchors.length === 1
      && Number(step182.matchingTrackedAnchors[0]) === Number(row.failingAnchor);
    const falsifierFlags = [
      pre132HasNoTrackedMatch ? null : 'pre_132_tracked_match',
      firstMatchIs132 ? null : 'first_tracked_match_not_132',
      activation132MatchesOnlyFailingAnchor ? null : 'wrong_132_target',
      preservation182KeepsOnlyFailingAnchor ? null : 'lost_182_preservation',
    ].filter(Boolean);

    return {
      familyIndex: row.familyIndex,
      representative: row.representative,
      tupleKey: row.tupleKey,
      failingAnchor: row.failingAnchor,
      witnessSquareModulus: row.witnessSquareModulus,
      firstTrackedMatchAnchor: firstTrackedMatch?.anchor ?? null,
      firstTrackedMatchAnchors: firstTrackedMatch?.matchingTrackedAnchors ?? [],
      pre132HasNoTrackedMatch,
      activation132MatchesOnlyFailingAnchor,
      preservation182KeepsOnlyFailingAnchor,
      status: falsifierFlags.length === 0 ? 'passed' : 'failed',
      falsifierFlags,
    };
  });
  const failures = rowChecks.filter((row) => row.status !== 'passed');

  return {
    checkerId: 'p848_132_activation_row_certificate_checker_v1',
    source: 'raw_family_menu_tuple_row_crt_replay',
    familyMenuPath,
    status: failures.length === 0 && rowChecks.length > 0 ? 'passed' : 'failed',
    checkedRowCount: rowChecks.length,
    passCount: rowChecks.length - failures.length,
    failCount: failures.length,
    expectedShape: {
      firstTrackedMatchAnchor: 132,
      pre132HasNoTrackedMatch: true,
      anchor132UniqueTarget: true,
      anchor182PreservesUniqueTarget: true,
    },
    surveyCounts: {
      totalFailingWitnessRows: survey.totalFailingWitnessRows,
      rowsWith132TargetActivationCount: survey.rowsWith132TargetActivationCount,
      rowsWith132TargetActivationByFailingAnchor: survey.rowsWith132TargetActivationByFailingAnchor,
      rowsWith132TargetActivationByWitness: survey.rowsWith132TargetActivationByWitness,
    },
    failures,
    ...(rowChecks.length <= 100
      ? { rowChecks }
      : {
        rowCheckSample: tightestRows,
        rowChecksOmitted: rowChecks.length - tightestRows.length,
      }),
  };
}

function buildP848ActivationSymbolicLiftCandidate({
  activationLemmaSchema,
  activationLemmaCheck,
  tupleRowLift132Proof,
  witnessSquareModulus,
}) {
  const rowCertificates = Array.isArray(activationLemmaSchema?.rowCertificates)
    ? activationLemmaSchema.rowCertificates
    : [];
  if (!activationLemmaSchema || rowCertificates.length === 0) {
    return null;
  }

  const anchorOrder = [7, 32, 57, 82, 132, 182];
  const trackedAnchors = [157, 232, 282, 332, 382, 432, 782, 832];
  const rowSummaries = rowCertificates.map((row) => {
    const activationSequence = Array.isArray(row.activationSequence) ? row.activationSequence : [];
    const stepByAnchor = Object.fromEntries(activationSequence.map((step) => [Number(step.anchor), step]));
    const pre132Residues = anchorOrder
      .filter((anchor) => anchor < 132)
      .map((anchor) => ({
        anchor,
        residueModWitness: stepByAnchor[anchor]?.residueModWitness ?? null,
        matchingTrackedAnchors: stepByAnchor[anchor]?.matchingTrackedAnchors ?? [],
      }));
    const step132 = stepByAnchor[132] ?? null;
    const step182 = stepByAnchor[182] ?? null;
    return {
      familyIndex: row.familyIndex,
      representative: row.representative,
      tupleKey: row.tupleKey,
      failingAnchor: row.failingAnchor,
      witnessSquareModulus: row.witnessSquareModulus,
      pre132Residues,
      residueAt132: step132?.residueModWitness ?? null,
      uniqueTrackedMatchAt132: step132?.uniqueTrackedMatch ?? null,
      residueAt182: step182?.residueModWitness ?? null,
      uniqueTrackedMatchAt182: step182?.uniqueTrackedMatch ?? null,
    };
  });
  const candidateChecks = rowSummaries.map((row) => {
    const pre132Clear = row.pre132Residues.every((step) => (
      Array.isArray(step.matchingTrackedAnchors) && step.matchingTrackedAnchors.length === 0
    ));
    const targetAt132 = Number(row.uniqueTrackedMatchAt132) === Number(row.failingAnchor);
    const preservedAt182 = Number(row.uniqueTrackedMatchAt182) === Number(row.failingAnchor)
      && row.residueAt182 === row.residueAt132;
    const failedChecks = [
      pre132Clear ? null : 'pre_132_clear_symbolic_hypothesis_not_observed',
      targetAt132 ? null : 'target_activation_symbolic_hypothesis_not_observed',
      preservedAt182 ? null : 'preservation_symbolic_hypothesis_not_observed',
    ].filter(Boolean);
    return {
      familyIndex: row.familyIndex,
      failingAnchor: row.failingAnchor,
      witnessSquareModulus: row.witnessSquareModulus,
      status: failedChecks.length === 0 ? 'passed' : 'failed',
      failedChecks,
    };
  });
  const failures = candidateChecks.filter((row) => row.status !== 'passed');
  const activationCheckerPassed = activationLemmaCheck?.status === 'passed';
  const liftCheckerPassed = tupleRowLift132Proof?.status === 'proved_from_tuple_row_crt';
  const status = activationCheckerPassed && liftCheckerPassed && failures.length === 0
    ? 'symbolic_crt_hypothesis_packet_ready'
    : 'blocked';

  return {
    candidateId: 'p848_132_activation_symbolic_lift_candidate_v1',
    checkerId: 'p848_132_activation_symbolic_lift_candidate_checker_v1',
    source: 'finite_menu_certificate_to_symbolic_crt_hypotheses',
    status,
    checkedRowCount: candidateChecks.length,
    passCount: candidateChecks.length - failures.length,
    failCount: failures.length + (activationCheckerPassed ? 0 : 1) + (liftCheckerPassed ? 0 : 1),
    failedRows: failures,
    scope: {
      problemId: '848',
      universalClaim: false,
      candidateOnly: true,
      finiteCertificateRows: rowCertificates.length,
      boundaryWitnessSquareModulus: witnessSquareModulus ?? null,
    },
    parameterization: {
      anchorOrder,
      trackedAnchors,
      variables: [
        'Q: square witness modulus q^2',
        'a: failing tracked repair anchor',
        'M_i: square modulus introduced by tuple anchor i',
        'r_i: tuple-row residue introduced by tuple anchor i',
        'N_i: CRT prefix residue after anchors up to i',
        'R_b(Q): tracked failure residue -b^{-1} mod Q when gcd(b, Q) = 1',
      ],
      crtPrefixRecurrence: 'N_i is the unique residue modulo lcm(M_7,...,M_i) satisfying all tuple rows through anchor i.',
      failureResidueFormula: 'R_b(Q) = -b^{-1} mod Q for gcd(b,Q)=1; if gcd(b,Q)>1, b cannot supply a residue class modulo Q unless the divisibility condition is satisfied.',
    },
    symbolicHypotheses: [
      {
        hypothesisId: 'S1_pairwise_crt_compatibility',
        text: 'The tuple-row moduli through anchors 7, 32, 57, 82, 132, 182 are CRT-compatible and define prefixes N_i.',
      },
      {
        hypothesisId: 'S2_same_witness_projection',
        text: 'Every prefix N_i is projected modulo the same square witness Q attached to the failing repair row a*n+1.',
      },
      {
        hypothesisId: 'S3_pre_132_clear',
        text: 'For i in {7,32,57,82}, N_i is not congruent to R_b(Q) for any tracked anchor b whose failure residue is defined.',
      },
      {
        hypothesisId: 'S4_anchor_132_unique_target',
        text: 'N_132 is congruent to R_a(Q), and N_132 is not congruent to R_b(Q) for every tracked b != a whose failure residue is defined.',
      },
      {
        hypothesisId: 'S5_anchor_182_preserves_target',
        text: 'N_182 is congruent to N_132 modulo Q, so the target activation survives the final shared-prefix anchor.',
      },
      {
        hypothesisId: 'S6_no_scope_promotion_without_domain_closure',
        text: 'A problem-level theorem may use this packet only after a separate domain-closure lemma proves S1-S5 for the intended family, not merely for the current finite menu.',
      },
    ],
    symbolicConclusion: {
      text: 'Any row satisfying S1-S5 has first tracked failure-residue activation at anchor 132, uniquely activates the failing anchor a, and preserves that activation at anchor 182.',
      proofSketch: [
        'S3 rules out every tracked activation before anchor 132.',
        'S4 makes anchor 132 a unique activation of the target failing anchor.',
        'S5 carries the same witness-residue class through anchor 182 without adding a competing tracked match.',
      ],
    },
    finiteEvidence: {
      activationCheckerId: activationLemmaCheck?.checkerId ?? null,
      activationCheckerStatus: activationLemmaCheck?.status ?? null,
      activationCheckedRows: activationLemmaCheck?.checkedRowCount ?? null,
      liftCheckerId: tupleRowLift132Proof?.checkerId ?? null,
      liftCheckerStatus: tupleRowLift132Proof?.status ?? null,
      boundaryLiftEquation: tupleRowLift132Proof?.reducedEquation ?? null,
      boundaryLiftParameter: tupleRowLift132Proof?.liftParameter ?? null,
      rowSummaries,
      candidateChecks,
    },
    nextProofObligations: [
      'Prove a domain-closure lemma that supplies S1-S5 for a reusable class of tuple rows instead of only the 17 current finite-menu rows.',
      'Decide whether the domain-closure class should be the 282 obstruction family, the full 132-activation survey, or the stricter 782-vs-1232 exchange family.',
      'Connect the symbolic activation packet to the finite-gap verifier boundary so it narrows the post-11300 exact work rather than becoming an isolated lemma.',
    ],
  };
}

function buildP848ActivationDomainClosureAssessment(activationSymbolicLiftCandidate, topRepairSeparationAnalysis) {
  const rowSummaries = Array.isArray(activationSymbolicLiftCandidate?.finiteEvidence?.rowSummaries)
    ? activationSymbolicLiftCandidate.finiteEvidence.rowSummaries
    : [];
  if (rowSummaries.length === 0) {
    return null;
  }

  const groupRowsBy = (keyFn) => rowSummaries.reduce((accumulator, row) => {
    const key = keyFn(row);
    accumulator[key] = accumulator[key] ?? [];
    accumulator[key].push(row);
    return accumulator;
  }, {});
  const byFailingAnchor = groupRowsBy((row) => String(row.failingAnchor));
  const byWitness = groupRowsBy((row) => String(row.witnessSquareModulus));
  const byAnchorWitness = groupRowsBy((row) => `${row.failingAnchor}/${row.witnessSquareModulus}`);
  const repeatedAnchorWitnessGroups = Object.entries(byAnchorWitness)
    .filter(([, rows]) => rows.length > 1)
    .map(([key, rows]) => {
      const [failingAnchor, witnessSquareModulus] = key.split('/').map((value) => Number(value));
      return {
        groupId: `anchor_${failingAnchor}_witness_${witnessSquareModulus}`,
        failingAnchor,
        witnessSquareModulus,
        rowCount: rows.length,
        familyIndices: rows.map((row) => row.familyIndex),
        representatives: [...new Set(rows.map((row) => row.representative))],
        tupleKeys: [...new Set(rows.map((row) => row.tupleKey))],
      };
    })
    .sort((left, right) => right.rowCount - left.rowCount || left.failingAnchor - right.failingAnchor);
  const strict782Vs1232 = (Array.isArray(topRepairSeparationAnalysis?.strictDominancePairs)
    ? topRepairSeparationAnalysis.strictDominancePairs
    : []).find((row) => Number(row.topContinuation) === 782 && Number(row.contrastContinuation) === 1232) ?? null;
  const firstRepeatedAnchorWitness = repeatedAnchorWitnessGroups[0] ?? null;
  const recommendedClosureLane = firstRepeatedAnchorWitness
    ? {
      laneId: 'repeat_anchor_witness_activation_family',
      targetGroupId: firstRepeatedAnchorWitness.groupId,
      why: `This is the largest repeated symbolic-activation class in the 17-row survey: anchor ${firstRepeatedAnchorWitness.failingAnchor} with witness ${firstRepeatedAnchorWitness.witnessSquareModulus} appears ${firstRepeatedAnchorWitness.rowCount} times.`,
    }
    : {
      laneId: 'single_boundary_instance_closure',
      targetGroupId: 'anchor_282_witness_841',
      why: 'No repeated anchor/witness group exists, so the only honest domain closure is the single 282/841 boundary instance.',
    };

  return {
    assessmentId: 'p848_132_activation_domain_closure_assessment_v1',
    status: Object.keys(byFailingAnchor).length > 1 && Object.keys(byWitness).length > 1
      ? 'broad_domain_closure_not_supported_yet'
      : 'single_domain_candidate',
    checkedRowCount: rowSummaries.length,
    failCount: 0,
    broadClosureVerdict: {
      verdict: 'do_not_promote_broad_17_row_survey_to_universal_domain',
      reason: `The finite symbolic-lift survey splits across ${Object.keys(byFailingAnchor).length} failing anchors and ${Object.keys(byWitness).length} witness moduli, so the current evidence supports parameterized hypotheses but not one broad domain theorem.`,
      failingAnchorCounts: Object.fromEntries(Object.entries(byFailingAnchor).map(([key, rows]) => [key, rows.length])),
      witnessCounts: Object.fromEntries(Object.entries(byWitness).map(([key, rows]) => [key, rows.length])),
    },
    repeatedAnchorWitnessGroups,
    narrowedClosureCandidates: [
      {
        candidateId: 'p848_282_841_boundary_instance_closure',
        priority: 'high',
        rowCount: rowSummaries.filter((row) => row.failingAnchor === 282 && row.witnessSquareModulus === 841).length,
        task: 'Prove the 282/841 boundary instance from the explicit CRT equations and keep it scoped as the current obstruction packet.',
        tradeoff: 'Best alignment with the 282 north star, but currently only a single finite-menu row.',
      },
      firstRepeatedAnchorWitness
        ? {
          candidateId: `p848_${firstRepeatedAnchorWitness.failingAnchor}_${firstRepeatedAnchorWitness.witnessSquareModulus}_repeated_activation_family`,
          priority: 'high',
          rowCount: firstRepeatedAnchorWitness.rowCount,
          task: `Try to prove a reusable closure lemma for anchor ${firstRepeatedAnchorWitness.failingAnchor} with witness ${firstRepeatedAnchorWitness.witnessSquareModulus}.`,
          tradeoff: 'Best repeated symbolic-lift family in the current activation survey, but it may be less directly tied to the 282 alignment.',
        }
        : null,
      strict782Vs1232
        ? {
          candidateId: 'p848_782_1232_strict_exchange_closure',
          priority: 'high',
          rowCount: strict782Vs1232.repairedByTopMissedByContrast.length,
          task: 'Use the strict 782 > 1232 exchange rows as a small theorem-facing family for the mod-50 lane closure.',
          tradeoff: 'Best bridge to the top repair-class mechanism, but it is a top-cluster theorem lane rather than the 132 activation lane itself.',
        }
        : null,
    ].filter(Boolean),
    recommendedClosureLane,
    nextProofObligations: [
      'Do not claim a universal 17-row domain theorem until a single structural family supplies S1-S5.',
      `Start with ${recommendedClosureLane.targetGroupId} and prove or falsify its CRT-domain closure.`,
      'After one narrow closure lane is proved, decide whether it genuinely reduces the finite gap or only explains a search-side feature.',
    ],
  };
}

function parseP848AnchorWitnessGroupId(groupId) {
  const match = /^anchor_(\d+)_witness_(\d+)$/.exec(String(groupId ?? ''));
  if (!match) {
    return null;
  }
  return {
    failingAnchor: Number(match[1]),
    witnessSquareModulus: Number(match[2]),
  };
}

function getP848Pre132ProfileId(pre132Residues) {
  return `pre132_${(Array.isArray(pre132Residues) ? pre132Residues : [])
    .map((step) => `${step.anchor}_${step.residueModWitness}`)
    .join('_')}`;
}

function summarizeP848Pre132Profile(pre132Residues) {
  return (Array.isArray(pre132Residues) ? pre132Residues : [])
    .map((step) => `${step.anchor}->${step.residueModWitness}`)
    .join(', ');
}

function buildP848AnchorWitnessDomainClosurePacket({
  activationDomainClosureAssessment,
  allFamilies,
  familyMenuPath,
}) {
  const targetGroupId = activationDomainClosureAssessment?.recommendedClosureLane?.targetGroupId ?? null;
  const parsedTarget = parseP848AnchorWitnessGroupId(targetGroupId);
  if (!parsedTarget) {
    return null;
  }

  const { failingAnchor, witnessSquareModulus } = parsedTarget;
  const targetGroup = (Array.isArray(activationDomainClosureAssessment?.repeatedAnchorWitnessGroups)
    ? activationDomainClosureAssessment.repeatedAnchorWitnessGroups
    : []).find((group) => group.groupId === targetGroupId) ?? null;
  const targetFailureResidue = getRequiredFailureResidue(failingAnchor, witnessSquareModulus);
  const targetRows = (Array.isArray(allFamilies) ? allFamilies : [])
    .map((family, familyIndex) => {
      const repairRow = (Array.isArray(family?.repairRows) ? family.repairRows : [])
        .find((row) => Number(row?.anchor) === failingAnchor
          && Array.isArray(row?.squareWitnesses)
          && row.squareWitnesses.some((witness) => Number(witness?.squareModulus) === witnessSquareModulus));
      return repairRow
        ? {
          familyIndex,
          family,
          repairRow,
        }
        : null;
    })
    .filter(Boolean);
  const rowProofs = targetRows.map(({ familyIndex, family, repairRow }) => {
    const tupleRows = Array.isArray(family?.tupleRows) ? family.tupleRows : [];
    const crtDerivation = deriveTupleRowCrt(tupleRows, witnessSquareModulus);
    const activationSequence = deriveTupleRowActivationSequence(tupleRows, family?.repairRows ?? [], witnessSquareModulus);
    const pre132Steps = activationSequence.filter((step) => Number(step.anchor) < 132);
    const step132 = activationSequence.find((step) => Number(step.anchor) === 132) ?? null;
    const step182 = activationSequence.find((step) => Number(step.anchor) === 182) ?? null;
    const crt132 = (Array.isArray(crtDerivation?.steps) ? crtDerivation.steps : [])
      .find((step) => Number(step.anchor) === 132) ?? null;
    const crt182 = (Array.isArray(crtDerivation?.steps) ? crtDerivation.steps : [])
      .find((step) => Number(step.anchor) === 182) ?? null;
    const firstTrackedMatch = activationSequence.find((step) => (
      Array.isArray(step.matchingTrackedAnchors) && step.matchingTrackedAnchors.length > 0
    )) ?? null;
    const pre132Residues = pre132Steps.map((step) => ({
      anchor: step.anchor,
      residueModWitness: step.residueModWitness,
      matchingTrackedAnchors: step.matchingTrackedAnchors,
    }));
    const pre132ProfileId = getP848Pre132ProfileId(pre132Residues);
    const representativeResidueModuloWitness = witnessSquareModulus
      ? positiveMod(family?.representative, witnessSquareModulus)
      : null;
    const crtResidue = crtDerivation?.combinedResidue ?? null;
    const crtModulus = crtDerivation?.combinedModulus ?? null;
    const rawRepresentativeMatchesCrtResidue = crtResidue !== null && crtModulus !== null
      ? positiveModBigInt(BigInt(family?.representative ?? 0) - BigInt(crtResidue), BigInt(crtModulus)) === 0n
      : false;
    const checks = {
      witnessPresentOnTargetRepair: Boolean(repairRow),
      repairValueDivisibleByWitness: witnessSquareModulus
        ? positiveMod(repairRow?.value ?? 0, witnessSquareModulus) === 0
        : false,
      representativeHitsTargetFailureResidue: representativeResidueModuloWitness === targetFailureResidue,
      rawRepresentativeMatchesCrtResidue,
      pre132HasNoTrackedMatch: pre132Steps.length > 0
        && pre132Steps.every((step) => Array.isArray(step.matchingTrackedAnchors) && step.matchingTrackedAnchors.length === 0),
      firstTrackedMatchIs132: Number(firstTrackedMatch?.anchor) === 132,
      anchor132UniqueTarget: Array.isArray(step132?.matchingTrackedAnchors)
        && step132.matchingTrackedAnchors.length === 1
        && Number(step132.matchingTrackedAnchors[0]) === failingAnchor
        && Number(step132.residueModWitness) === targetFailureResidue,
      anchor182PreservesTarget: Array.isArray(step182?.matchingTrackedAnchors)
        && step182.matchingTrackedAnchors.length === 1
        && Number(step182.matchingTrackedAnchors[0]) === failingAnchor
        && Number(step182.residueModWitness) === targetFailureResidue,
      anchor182ZeroLift: Number(crt182?.liftParameter ?? -1) === 0,
    };
    const failedChecks = Object.entries(checks)
      .filter(([, value]) => value !== true)
      .map(([key]) => key);

    return {
      familyIndex,
      representative: family?.representative ?? null,
      tupleKey: family?.tupleKey ?? null,
      failingAnchor,
      witnessSquareModulus,
      targetFailureResidue,
      repairValue: repairRow?.value ?? null,
      squareWitnesses: repairRow?.squareWitnesses ?? [],
      representativeResidueModuloWitness,
      pre132ProfileId,
      pre132Profile: summarizeP848Pre132Profile(pre132Residues),
      pre132Residues,
      residueAt132: step132?.residueModWitness ?? null,
      residueAt182: step182?.residueModWitness ?? null,
      anchor132LiftParameter: crt132?.liftParameter ?? null,
      anchor182LiftParameter: crt182?.liftParameter ?? null,
      anchor182RowSquareModulus: crt182?.rowSquareModulus ?? null,
      anchor182RowResidue: crt182?.rowResidue ?? null,
      tupleRows: tupleRows.map((row) => ({
        anchor: row.anchor,
        squareModulus: row.squareModulus,
        residue: row.residue,
      })),
      crtDerivation,
      checks,
      status: failedChecks.length === 0 ? 'passed' : 'failed',
      failedChecks,
    };
  });
  const failedRows = rowProofs.filter((row) => row.status !== 'passed');
  const profileGroups = Object.values(rowProofs.reduce((accumulator, row) => {
    accumulator[row.pre132ProfileId] = accumulator[row.pre132ProfileId] ?? {
      profileId: row.pre132ProfileId,
      profile: row.pre132Profile,
      rowCount: 0,
      familyIndices: [],
      representatives: [],
      tupleKeys: [],
      anchor182RowSquareModuli: [],
    };
    const group = accumulator[row.pre132ProfileId];
    group.rowCount += 1;
    group.familyIndices.push(row.familyIndex);
    if (!group.representatives.includes(row.representative)) {
      group.representatives.push(row.representative);
    }
    if (!group.tupleKeys.includes(row.tupleKey)) {
      group.tupleKeys.push(row.tupleKey);
    }
    if (!group.anchor182RowSquareModuli.includes(row.anchor182RowSquareModulus)) {
      group.anchor182RowSquareModuli.push(row.anchor182RowSquareModulus);
    }
    return accumulator;
  }, {})).sort((left, right) => right.rowCount - left.rowCount || left.profileId.localeCompare(right.profileId));
  const repeatedProfile = profileGroups.find((group) => group.rowCount > 1) ?? null;
  const expectedRowCount = targetGroup?.rowCount ?? rowProofs.length;
  const rowCountMatchesAssessment = rowProofs.length === expectedRowCount;
  const failCount = failedRows.length + (rowCountMatchesAssessment ? 0 : 1);
  const finiteGroupCertified = failCount === 0 && rowProofs.length > 0;
  const profileSplit = profileGroups.length > 1;
  const recommendedSuccessor = repeatedProfile
    ? {
      laneId: 'repeat_pre132_profile_subfamily',
      targetProfileId: repeatedProfile.profileId,
      task: `Prove or falsify the repeated ${targetGroupId} pre-132 profile sublane ${repeatedProfile.profileId} beyond finite rows ${repeatedProfile.familyIndices.join(', ')}.`,
      why: `Rows ${repeatedProfile.familyIndices.join(', ')} share the same pre-132 residues, hit ${targetFailureResidue} mod ${witnessSquareModulus} at anchor 132, and have a zero-lift anchor-182 preservation step despite different final tuple moduli.`,
    }
    : {
      laneId: 'switch_to_mod50_or_exact_verifier',
      targetProfileId: null,
      task: 'Switch from the finite 832/529 closure lane to the mod-50 symbolic lane or the next local exact verifier rollout.',
      why: 'No repeated pre-132 profile remains inside the recommended anchor/witness group.',
    };

  return {
    checkerId: 'p848_832_529_anchor_witness_domain_closure_checker_v1',
    packetId: 'p848_832_529_anchor_witness_domain_closure_packet_v1',
    source: 'raw_family_menu_anchor_witness_replay',
    familyMenuPath,
    status: finiteGroupCertified
      ? profileSplit
        ? 'finite_group_closure_certified_symbolic_domain_split'
        : 'finite_group_closure_certified_single_profile_candidate'
      : 'failed',
    checkedRowCount: rowProofs.length,
    passCount: rowProofs.length - failedRows.length,
    failCount,
    targetGroupId,
    failingAnchor,
    witnessSquareModulus,
    targetFailureResidue,
    expectedRowCount,
    rowCountMatchesAssessment,
    finiteScopeConclusion: finiteGroupCertified
      ? `Every current finite-menu occurrence of ${targetGroupId} replays from raw tuple-row CRT data: pre-132 prefixes are clear, anchor 132 uniquely activates tracked tail ${failingAnchor}, and anchor 182 preserves residue ${targetFailureResidue} mod ${witnessSquareModulus}.`
      : `The current finite-menu occurrences of ${targetGroupId} do not all replay cleanly.`,
    symbolicDomainDecision: {
      verdict: profileSplit
        ? 'single_profile_symbolic_domain_falsified_by_profile_split'
        : 'single_profile_symbolic_domain_candidate',
      reason: profileSplit
        ? `The recommended anchor/witness group splits into ${profileGroups.length} pre-132 residue profiles, so one broad single-profile symbolic closure would overclaim the evidence.`
        : 'The recommended anchor/witness group has one pre-132 residue profile, so it remains a plausible symbolic subdomain candidate.',
      profileGroupCount: profileGroups.length,
      repeatedProfileId: repeatedProfile?.profileId ?? null,
    },
    zeroLiftPreservation: {
      allRowsAnchor182ZeroLift: rowProofs.length > 0
        && rowProofs.every((row) => row.checks.anchor182ZeroLift),
      explanation: 'In the certified rows, the anchor-132 CRT prefix already satisfies the anchor-182 tuple row, so adding anchor 182 uses lift parameter 0 and cannot move the witness residue modulo 529.',
    },
    profileGroups,
    rowProofs,
    failedRows,
    recommendedSuccessor,
    falsifierBoundary: [
      `A refreshed family menu adds another ${targetGroupId} row that fails any row check in this packet.`,
      `A refreshed family menu removes one of the certified rows ${rowProofs.map((row) => row.familyIndex).join(', ')} or changes its witness modulus.`,
      'A symbolic theorem tries to use the finite group as one broad profile despite the recorded profile split.',
      'A future profile sublane instance has a nonzero anchor-182 lift or a pre-132 tracked failure-residue match.',
    ],
    nextProofObligations: [
      recommendedSuccessor.task,
      'Decide whether the repeated profile is a true symbolic family or only a finite-menu duplicate created by alternative final tuple rows.',
      'If the repeated profile is finite-only, move the theorem lane to the mod-50 bad-family signature or the next local exact verifier rollout.',
    ],
  };
}

function buildP848AnchorWitnessProfileSublanePacket(anchorWitnessDomainClosurePacket) {
  const targetProfileId = anchorWitnessDomainClosurePacket?.recommendedSuccessor?.targetProfileId ?? null;
  if (!anchorWitnessDomainClosurePacket || !targetProfileId) {
    return null;
  }

  const rowProofs = (Array.isArray(anchorWitnessDomainClosurePacket.rowProofs)
    ? anchorWitnessDomainClosurePacket.rowProofs
    : []).filter((row) => row.pre132ProfileId === targetProfileId);
  if (rowProofs.length === 0) {
    return null;
  }

  const tupleSignature = (tupleRows, predicate = () => true) => JSON.stringify((Array.isArray(tupleRows) ? tupleRows : [])
    .filter(predicate)
    .map((row) => ({
      anchor: row.anchor,
      squareModulus: row.squareModulus,
      residue: row.residue,
    })));
  const unique = (values) => [...new Set(values)];
  const prefixSignatures = unique(rowProofs.map((row) => tupleSignature(row.tupleRows, (tupleRow) => Number(tupleRow.anchor) <= 132)));
  const fullSignatures = unique(rowProofs.map((row) => tupleSignature(row.tupleRows)));
  const finalAnchorSignatures = unique(rowProofs.map((row) => tupleSignature(row.tupleRows, (tupleRow) => Number(tupleRow.anchor) === 182)));
  const representatives = unique(rowProofs.map((row) => row.representative));
  const repairValues = unique(rowProofs.map((row) => row.repairValue));
  const anchor132LiftParameters = unique(rowProofs.map((row) => row.anchor132LiftParameter));
  const anchor182LiftParameters = unique(rowProofs.map((row) => row.anchor182LiftParameter));
  const checks = {
    repeatedProfileHasAtLeastTwoRows: rowProofs.length >= 2,
    sameRepresentative: representatives.length === 1,
    sameRepairValue: repairValues.length === 1,
    sameTuplePrefixThrough132: prefixSignatures.length === 1,
    distinctFullTupleRows: fullSignatures.length === rowProofs.length,
    differsOnlyAtAnchor182: prefixSignatures.length === 1 && finalAnchorSignatures.length === rowProofs.length,
    sameAnchor132Lift: anchor132LiftParameters.length === 1,
    anchor182ZeroLiftForEveryRow: anchor182LiftParameters.length === 1 && Number(anchor182LiftParameters[0]) === 0,
    allRowsAlreadyPassedParentClosure: rowProofs.every((row) => row.status === 'passed'),
  };
  const failedChecks = Object.entries(checks)
    .filter(([, value]) => value !== true)
    .map(([key]) => key);
  const resolvedAsDuplicate = failedChecks.length === 0;

  return {
    checkerId: 'p848_832_529_pre132_profile_sublane_checker_v1',
    packetId: 'p848_832_529_pre132_profile_sublane_packet_v1',
    source: 'anchor_witness_domain_closure_profile_replay',
    status: resolvedAsDuplicate
      ? 'finite_profile_sublane_resolved_as_zero_lift_duplicate'
      : 'unresolved',
    checkedRowCount: rowProofs.length,
    passCount: resolvedAsDuplicate ? rowProofs.length : 0,
    failCount: failedChecks.length,
    parentPacketId: anchorWitnessDomainClosurePacket.packetId ?? null,
    targetGroupId: anchorWitnessDomainClosurePacket.targetGroupId,
    targetProfileId,
    failingAnchor: anchorWitnessDomainClosurePacket.failingAnchor,
    witnessSquareModulus: anchorWitnessDomainClosurePacket.witnessSquareModulus,
    targetFailureResidue: anchorWitnessDomainClosurePacket.targetFailureResidue,
    familyIndices: rowProofs.map((row) => row.familyIndex),
    representatives,
    repairValues,
    tupleKeys: rowProofs.map((row) => row.tupleKey),
    sharedPrefixThrough132: rowProofs[0]?.tupleRows
      ?.filter((row) => Number(row.anchor) <= 132)
      ?.map((row) => ({
        anchor: row.anchor,
        squareModulus: row.squareModulus,
        residue: row.residue,
      })) ?? [],
    finalAnchorVariants: rowProofs.map((row) => ({
      familyIndex: row.familyIndex,
      anchor: 182,
      squareModulus: row.anchor182RowSquareModulus,
      residue: row.anchor182RowResidue,
      liftParameter: row.anchor182LiftParameter,
    })),
    anchor132LiftParameter: anchor132LiftParameters.length === 1 ? anchor132LiftParameters[0] : null,
    checks,
    failedChecks,
    rowProofRefs: rowProofs.map((row) => ({
      familyIndex: row.familyIndex,
      representative: row.representative,
      tupleKey: row.tupleKey,
      residueAt132: row.residueAt132,
      residueAt182: row.residueAt182,
      anchor182LiftParameter: row.anchor182LiftParameter,
    })),
    conclusion: resolvedAsDuplicate
      ? `Rows ${rowProofs.map((row) => row.familyIndex).join(', ')} are a finite duplicate final-anchor variant over the same CRT prefix through anchor 132, not evidence for a separate broad symbolic family.`
      : `Rows ${rowProofs.map((row) => row.familyIndex).join(', ')} do not yet reduce to a zero-lift duplicate profile.`,
    symbolicDomainDecision: {
      verdict: resolvedAsDuplicate
        ? 'profile_sublane_not_a_new_symbolic_family'
        : 'profile_sublane_still_open',
      reason: resolvedAsDuplicate
        ? 'The repeated profile rows share representative, repair value, tuple prefix through anchor 132, and anchor-132 lift; they differ only by the final anchor-182 tuple row, which is a zero-lift in both cases.'
        : 'At least one duplicate-profile check failed, so this profile cannot yet be dismissed as a finite final-anchor variant.',
    },
    nextProofObligations: resolvedAsDuplicate
      ? [
        'Move the theorem lane to the mod-50 bad-family signature, because the repeated 832/529 profile did not yield a new broad symbolic domain.',
        'Keep the 832/529 packet as finite checked wisdom for future family-menu refreshes.',
        'Run the next local exact verifier rollout only after the theorem-facing mod-50 handoff has been sharpened or falsified.',
      ]
      : [
        'Repair the failed profile-sublane checks or find the exact row feature that prevents the zero-lift duplicate interpretation.',
        'Only promote the profile sublane if it survives raw tuple-row replay without a finite-duplicate explanation.',
      ],
  };
}

function buildPrimeList(limit) {
  const normalizedLimit = Math.max(2, Math.floor(Number(limit) || 0));
  const sieve = new Uint8Array(normalizedLimit + 1);
  const primes = [];
  for (let candidate = 2; candidate <= normalizedLimit; candidate += 1) {
    if (sieve[candidate]) {
      continue;
    }
    primes.push(candidate);
    if (candidate * candidate > normalizedLimit) {
      continue;
    }
    for (let value = candidate * candidate; value <= normalizedLimit; value += candidate) {
      sieve[value] = 1;
    }
  }
  return primes;
}

function findSquareWitnessModuli(value, primes) {
  let remaining = Number(value);
  const witnesses = [];
  for (const prime of primes) {
    if (prime * prime > remaining) {
      break;
    }
    if (remaining % prime !== 0) {
      continue;
    }
    let exponent = 0;
    while (remaining % prime === 0) {
      remaining /= prime;
      exponent += 1;
    }
    if (exponent >= 2) {
      witnesses.push(prime * prime);
    }
  }
  return witnesses;
}

function scoreP848FamilyMenuContinuation(allFamilies, continuation, primes) {
  const rows = (Array.isArray(allFamilies) ? allFamilies : [])
    .map((family, familyIndex) => {
      const representative = Number(family?.representative);
      const repairValue = Number(continuation) * representative + 1;
      const squareWitnesses = Number.isFinite(repairValue)
        ? findSquareWitnessModuli(repairValue, primes)
        : [];
      const matchesKnownFailure = Boolean(family?.matchesKnownFailure ?? family?.matches_known_failure);
      return {
        continuation,
        familyIndex,
        representative,
        tupleKey: family?.tupleKey ?? family?.tuple_key ?? null,
        matchesKnownFailure,
        predicted: !matchesKnownFailure,
        repairValue,
        rescued: Number(continuation) <= representative && squareWitnesses.length === 0,
        squareWitnesses,
      };
    })
    .filter((row) => Number.isFinite(row.representative));
  const predictedRows = rows.filter((row) => row.predicted);
  const missedPredictedRows = predictedRows.filter((row) => !row.rescued);
  const repairedPredictedRows = predictedRows.filter((row) => row.rescued);
  const repairedKnownRows = rows.filter((row) => row.matchesKnownFailure && row.rescued);
  const missedKnownRows = rows.filter((row) => row.matchesKnownFailure && !row.rescued);

  return {
    continuation,
    familyCount: rows.length,
    predictedFamilyCount: predictedRows.length,
    repairedKnownFamilyCount: repairedKnownRows.length,
    missedKnownFamilyCount: missedKnownRows.length,
    repairedPredictedFamilyCount: repairedPredictedRows.length,
    missedPredictedFamilyCount: missedPredictedRows.length,
    missedPredictedRows,
    firstMissedPredictedRepresentatives: missedPredictedRows.slice(0, 8).map((row) => row.representative),
  };
}

function summarizeP848ScoredFamilyRow(row) {
  return {
    continuation: row.continuation,
    familyIndex: row.familyIndex,
    representative: row.representative,
    tupleKey: row.tupleKey,
    repairValue: row.repairValue,
    squareWitnesses: row.squareWitnesses,
  };
}

function getP848ScoredFamilyRowKey(row) {
  return `${row.familyIndex}:${row.representative}:${row.tupleKey ?? ''}`;
}

function getP848ContinuationLaneIndex(continuation, laneBase = 32, laneStep = 50) {
  const normalizedContinuation = Number(continuation);
  const numerator = normalizedContinuation - laneBase;
  if (!Number.isInteger(normalizedContinuation) || numerator % laneStep !== 0) {
    return null;
  }
  return numerator / laneStep;
}

function deriveP848LaneWitnessSignatures(row, repairedContinuation, laneBase = 32, laneStep = 50) {
  const missedLaneIndex = getP848ContinuationLaneIndex(row.continuation, laneBase, laneStep);
  const repairedLaneIndex = getP848ContinuationLaneIndex(repairedContinuation, laneBase, laneStep);
  return (Array.isArray(row.squareWitnesses) ? row.squareWitnesses : []).map((witnessSquareModulus) => {
    const coeff = positiveMod(laneStep * Number(row.representative), witnessSquareModulus);
    const rhs = positiveMod(-(laneBase * Number(row.representative) + 1), witnessSquareModulus);
    const congruence = solveLinearCongruenceNonnegative(coeff, rhs, witnessSquareModulus);
    const laneIndexMatches = (laneIndex) => congruence?.solvable
      && laneIndex !== null
      && positiveMod(Number(laneIndex) - congruence.solution, congruence.period) === 0;
    return {
      witnessSquareModulus,
      laneEquation: `${coeff}*m ≡ ${rhs} (mod ${witnessSquareModulus})`,
      gcdCoeffWitness: congruence?.gcdCoeffModulus ?? null,
      laneIndexResidue: congruence?.solution ?? null,
      laneIndexPeriod: congruence?.period ?? null,
      missedLaneIndex,
      repairedLaneIndex,
      missedLaneIndexMatches: laneIndexMatches(missedLaneIndex),
      repairedLaneIndexMatches: laneIndexMatches(repairedLaneIndex),
    };
  });
}

function summarizeP848ExchangeFamilyRow(row, repairedContinuation, laneBase = 32, laneStep = 50) {
  const laneWitnessSignatures = deriveP848LaneWitnessSignatures(row, repairedContinuation, laneBase, laneStep);
  return {
    ...summarizeP848ScoredFamilyRow(row),
    missedLaneIndex: getP848ContinuationLaneIndex(row.continuation, laneBase, laneStep),
    repairedContinuation,
    repairedLaneIndex: getP848ContinuationLaneIndex(repairedContinuation, laneBase, laneStep),
    laneWitnessSignatures,
    laneSignatureStatus: laneWitnessSignatures.length > 0
      && laneWitnessSignatures.some((signature) => signature.missedLaneIndexMatches)
      && laneWitnessSignatures.every((signature) => !signature.repairedLaneIndexMatches)
      ? 'passed'
      : 'failed',
  };
}

function buildP848Mod50LaneSignature(pairwiseDeltas, continuations) {
  const laneBase = 32;
  const laneStep = 50;
  const continuationLaneIndices = Object.fromEntries((Array.isArray(continuations) ? continuations : [])
    .map((continuation) => [continuation, getP848ContinuationLaneIndex(continuation, laneBase, laneStep)]));
  const exchangeRows = (Array.isArray(pairwiseDeltas) ? pairwiseDeltas : []).flatMap((delta) => [
    ...delta.contrastOnlyMissedRows.map((row) => ({
      exchangeKind: 'contrast_only_miss',
      topContinuation: delta.topContinuation,
      contrastContinuation: delta.contrastContinuation,
      ...row,
    })),
    ...delta.topOnlyMissedRows.map((row) => ({
      exchangeKind: 'top_only_miss',
      topContinuation: delta.topContinuation,
      contrastContinuation: delta.contrastContinuation,
      ...row,
    })),
  ]);
  const failedRows = exchangeRows.filter((row) => row.laneSignatureStatus !== 'passed');
  const strictDominanceRows = exchangeRows.filter((row) => (
    row.topContinuation === 782
    && row.contrastContinuation === 1232
    && row.exchangeKind === 'contrast_only_miss'
  ));
  return {
    checkerId: 'p848_mod50_lane_bad_family_signature_checker_v1',
    schemaId: 'p848_mod50_lane_bad_family_signature_v1',
    source: 'pairwise_exchange_row_lane_congruence_replay',
    status: failedRows.length === 0 && exchangeRows.length > 0
      ? 'finite_menu_mod50_lane_signature_certified'
      : 'failed',
    laneBase,
    laneStep,
    laneFormula: 'continuation = 32 + 50*m',
    continuationLaneIndices,
    checkedRowCount: exchangeRows.length,
    passCount: exchangeRows.length - failedRows.length,
    failCount: failedRows.length,
    failedRows,
    strictDominanceRows,
    exchangeRows,
    conclusion: failedRows.length === 0 && exchangeRows.length > 0
      ? 'Every pairwise exchange row is explained by a bad lane-index congruence m modulo the square witness; the missed continuation hits that congruence and the repaired continuation does not.'
      : 'At least one pairwise exchange row lacks a clean bad lane-index congruence certificate.',
    nextProofObligations: [
      'Generalize the finite-menu lane-index congruence schema beyond the currently replayed exchange rows.',
      'Choose the strict 782 vs 1232 handoff rows or a broader exchange family as the next theorem-facing symbolic family.',
      'Connect the lane-index bad-family schema back to the finite-gap closure target rather than treating it as only a leaderboard feature.',
    ],
  };
}

function buildP848Mod50LaneSymbolicSchema(mod50LaneSignature) {
  const exchangeRows = Array.isArray(mod50LaneSignature?.exchangeRows)
    ? mod50LaneSignature.exchangeRows
    : [];
  if (!mod50LaneSignature || exchangeRows.length === 0) {
    return null;
  }

  const laneBase = mod50LaneSignature.laneBase ?? 32;
  const laneStep = mod50LaneSignature.laneStep ?? 50;
  const instanceChecks = exchangeRows.flatMap((row) => {
    const recomputedSignatures = deriveP848LaneWitnessSignatures(row, row.repairedContinuation, laneBase, laneStep);
    return (Array.isArray(row.laneWitnessSignatures) ? row.laneWitnessSignatures : [])
      .map((signature, signatureIndex) => {
        const recomputed = recomputedSignatures[signatureIndex] ?? null;
        const checks = {
          laneFormulaAppliesToMissedContinuation: getP848ContinuationLaneIndex(row.continuation, laneBase, laneStep) === row.missedLaneIndex,
          laneFormulaAppliesToRepairedContinuation: getP848ContinuationLaneIndex(row.repairedContinuation, laneBase, laneStep) === row.repairedLaneIndex,
          equationRecomputes: recomputed?.laneEquation === signature.laneEquation
            && recomputed?.laneIndexResidue === signature.laneIndexResidue
            && recomputed?.laneIndexPeriod === signature.laneIndexPeriod,
          missedLaneHitsBadClass: signature.missedLaneIndexMatches === true,
          repairedLaneAvoidsBadClass: signature.repairedLaneIndexMatches === false,
          congruenceSolvable: signature.laneIndexResidue !== null && signature.laneIndexPeriod !== null,
        };
        const failedChecks = Object.entries(checks)
          .filter(([, value]) => value !== true)
          .map(([key]) => key);
        return {
          exchangeKind: row.exchangeKind,
          topContinuation: row.topContinuation,
          contrastContinuation: row.contrastContinuation,
          continuation: row.continuation,
          repairedContinuation: row.repairedContinuation,
          familyIndex: row.familyIndex,
          representative: row.representative,
          witnessSquareModulus: signature.witnessSquareModulus,
          laneEquation: signature.laneEquation,
          laneIndexResidue: signature.laneIndexResidue,
          laneIndexPeriod: signature.laneIndexPeriod,
          missedLaneIndex: signature.missedLaneIndex,
          repairedLaneIndex: signature.repairedLaneIndex,
          status: failedChecks.length === 0 ? 'passed' : 'failed',
          checks,
          failedChecks,
        };
      });
  });
  const failedInstances = instanceChecks.filter((row) => row.status !== 'passed');
  const periodCounts = instanceChecks.reduce((accumulator, row) => {
    const key = String(row.laneIndexPeriod);
    accumulator[key] = (accumulator[key] ?? 0) + 1;
    return accumulator;
  }, {});
  const strict782Vs1232Instances = instanceChecks.filter((row) => (
    Number(row.topContinuation) === 782
    && Number(row.contrastContinuation) === 1232
    && row.exchangeKind === 'contrast_only_miss'
  ));

  return {
    checkerId: 'p848_mod50_bad_lane_symbolic_schema_checker_v1',
    schemaId: 'p848_mod50_bad_lane_symbolic_schema_v1',
    source: 'mod50_lane_congruence_lift',
    status: failedInstances.length === 0 && mod50LaneSignature.status === 'finite_menu_mod50_lane_signature_certified'
      ? 'symbolic_bad_lane_schema_ready'
      : 'failed',
    laneBase,
    laneStep,
    laneFormula: mod50LaneSignature.laneFormula ?? 'continuation = 32 + 50*m',
    checkedRowCount: instanceChecks.length,
    passCount: instanceChecks.length - failedInstances.length,
    failCount: failedInstances.length + (mod50LaneSignature.status === 'finite_menu_mod50_lane_signature_certified' ? 0 : 1),
    failedInstances,
    scope: {
      universalDivisibilityClaim: true,
      universalSquarefreeRepairClaim: false,
      finiteExchangeRowsChecked: exchangeRows.length,
      symbolicVariables: [
        'n: family representative',
        'Q: square witness modulus',
        'm: lane index in c = 32 + 50*m',
        'c: continuation being tested',
      ],
    },
    symbolicStatement: `For any representative n and square witness modulus Q, continuation c = ${laneBase} + ${laneStep}*m has Q | c*n + 1 exactly when (${laneStep}*n)*m ≡ -(${laneBase}*n + 1) (mod Q). When this congruence is solvable, it defines the bad m-class modulo Q/gcd(${laneStep}*n,Q).`,
    proofSketch: [
      `Substitute c = ${laneBase} + ${laneStep}*m into c*n + 1 ≡ 0 (mod Q).`,
      `Rearrange to (${laneStep}*n)*m ≡ -(${laneBase}*n + 1) (mod Q).`,
      'Solve the linear congruence; the missed continuation is bad exactly when its lane index lies in the solution class.',
      'Avoiding this one witness class is necessary for repair on that row, but not by itself sufficient for global squarefreeness.',
    ],
    periodCounts,
    strict782Vs1232Instances,
    instanceChecks,
    conclusion: failedInstances.length === 0
      ? `The finite mod-50 exchange packet is now backed by a reusable divisibility schema over ${instanceChecks.length} checked witness instances.`
      : 'At least one finite exchange row failed to replay under the symbolic bad-lane schema.',
    nextProofObligations: [
      'Connect the symbolic bad-lane schema to the finite-gap closure target using a theorem-facing handoff family, preferably the strict 782 vs 1232 rows.',
      'Prove that the selected handoff family controls all relevant square witnesses, not only the witnessed bad lane in each finite exchange row.',
      'If no such control family exists, route the next step to local exact verification beyond 11300 instead of overclaiming the lane schema.',
    ],
  };
}

function buildP848Strict7821232HandoffPacket(topRepairSeparationAnalysis, mod50LaneSymbolicSchema) {
  if (!topRepairSeparationAnalysis || !mod50LaneSymbolicSchema) {
    return null;
  }

  const strictPair = (Array.isArray(topRepairSeparationAnalysis.strictDominancePairs)
    ? topRepairSeparationAnalysis.strictDominancePairs
    : []).find((row) => Number(row.topContinuation) === 782 && Number(row.contrastContinuation) === 1232) ?? null;
  const pairwiseDelta = (Array.isArray(topRepairSeparationAnalysis.pairwiseDeltas)
    ? topRepairSeparationAnalysis.pairwiseDeltas
    : []).find((row) => Number(row.topContinuation) === 782 && Number(row.contrastContinuation) === 1232) ?? null;
  if (!strictPair || !pairwiseDelta) {
    return null;
  }

  const strictRows = Array.isArray(strictPair.repairedByTopMissedByContrast)
    ? strictPair.repairedByTopMissedByContrast
    : [];
  const strictInstances = Array.isArray(mod50LaneSymbolicSchema.strict782Vs1232Instances)
    ? mod50LaneSymbolicSchema.strict782Vs1232Instances
    : [];
  const instanceKey = (row) => `${row.familyIndex}:${row.representative}:${row.witnessSquareModulus}`;
  const instancesByKey = Object.fromEntries(strictInstances.map((row) => [instanceKey(row), row]));
  const rowChecks = strictRows.flatMap((row) => (Array.isArray(row.laneWitnessSignatures) ? row.laneWitnessSignatures : [])
    .map((signature) => {
      const matchingInstance = instancesByKey[`${row.familyIndex}:${row.representative}:${signature.witnessSquareModulus}`] ?? null;
      const checks = {
        symbolicSchemaInstancePresent: Boolean(matchingInstance),
        missedContinuationIs1232: Number(row.continuation) === 1232,
        repairedContinuationIs782: Number(row.repairedContinuation) === 782,
        missedLaneIndexIs24: Number(row.missedLaneIndex) === 24,
        repairedLaneIndexIs15: Number(row.repairedLaneIndex) === 15,
        missedLaneHitsBadClass: signature.missedLaneIndexMatches === true,
        repairedLaneAvoidsBadClass: signature.repairedLaneIndexMatches === false,
      };
      const failedChecks = Object.entries(checks)
        .filter(([, value]) => value !== true)
        .map(([key]) => key);
      return {
        familyIndex: row.familyIndex,
        representative: row.representative,
        tupleKey: row.tupleKey,
        witnessSquareModulus: signature.witnessSquareModulus,
        laneEquation: signature.laneEquation,
        laneIndexResidue: signature.laneIndexResidue,
        laneIndexPeriod: signature.laneIndexPeriod,
        missedLaneIndex: row.missedLaneIndex,
        repairedLaneIndex: row.repairedLaneIndex,
        status: failedChecks.length === 0 ? 'passed' : 'failed',
        checks,
        failedChecks,
      };
    }));
  const failedRows = rowChecks.filter((row) => row.status !== 'passed');
  const checks = {
    strictDominancePairPresent: Boolean(strictPair),
    pairwiseDeltaPresent: Boolean(pairwiseDelta),
    topContinuationIs782: Number(pairwiseDelta.topContinuation) === 782,
    contrastContinuationIs1232: Number(pairwiseDelta.contrastContinuation) === 1232,
    topRepairsTwoMorePredictedRows: Number(pairwiseDelta.netExtraRepairsForTop) === 2,
    noTopOnlyMissRows: Number(pairwiseDelta.topOnlyMissCount) === 0,
    contrastOnlyMissRowsAreTwo: Number(pairwiseDelta.contrastOnlyMissCount) === 2,
    strictRowsCoveredBySymbolicSchema: strictRows.length > 0 && rowChecks.length === strictRows.length,
    rowChecksPass: failedRows.length === 0,
  };
  const failedChecks = Object.entries(checks)
    .filter(([, value]) => value !== true)
    .map(([key]) => key);
  const certified = failedChecks.length === 0;

  return {
    checkerId: 'p848_782_1232_strict_handoff_checker_v1',
    packetId: 'p848_782_1232_strict_handoff_packet_v1',
    source: 'mod50_symbolic_schema_to_finite_menu_handoff',
    status: certified
      ? 'finite_strict_handoff_certified_not_gap_closure'
      : 'failed',
    checkedRowCount: rowChecks.length,
    passCount: rowChecks.length - failedRows.length,
    failCount: failedRows.length + failedChecks.length,
    topContinuation: 782,
    contrastContinuation: 1232,
    topLaneIndex: getP848ContinuationLaneIndex(782),
    contrastLaneIndex: getP848ContinuationLaneIndex(1232),
    netExtraRepairsForTop: pairwiseDelta.netExtraRepairsForTop,
    topOnlyMissCount: pairwiseDelta.topOnlyMissCount,
    contrastOnlyMissCount: pairwiseDelta.contrastOnlyMissCount,
    topRepairedPredictedFamilyCount: pairwiseDelta.topRepairedPredictedFamilyCount,
    contrastRepairedPredictedFamilyCount: pairwiseDelta.contrastRepairedPredictedFamilyCount,
    checks,
    failedChecks,
    rowChecks,
    failedRows,
    strictRows: strictRows.map((row) => ({
      familyIndex: row.familyIndex,
      representative: row.representative,
      tupleKey: row.tupleKey,
      repairValue: row.repairValue,
      squareWitnesses: row.squareWitnesses,
      missedLaneIndex: row.missedLaneIndex,
      repairedLaneIndex: row.repairedLaneIndex,
    })),
    conclusion: certified
      ? 'The strict 782 > 1232 handoff is certified on the current finite menu: 782 repairs exactly two predicted rows that 1232 misses, 1232 repairs no predicted row that 782 misses, and both strict rows are explained by the symbolic mod-50 bad-lane schema.'
      : 'The strict 782 > 1232 handoff did not replay cleanly against the symbolic mod-50 bad-lane schema.',
    theoremBoundary: {
      finiteMenuHandoffClaim: certified,
      allNFiniteGapClosureClaim: false,
      reason: 'This packet connects the symbolic bad-lane schema to the finite exchange surface, but it does not prove that all post-11300 candidates are controlled by the strict handoff family.',
    },
    nextProofObligations: certified
      ? [
        'Use the strict handoff packet as theorem-side guidance for the next local exact verifier rollout beyond 11300.',
        'If exact verification finds a new boundary row, replay it through the bad-lane schema before widening search.',
        'Do not claim all-N closure from the 782 > 1232 handoff without a separate coverage theorem over all relevant square witnesses.',
      ]
      : [
        'Repair the strict handoff replay or choose a different pairwise handoff family.',
      ],
  };
}

function buildP848TopRepairSeparationAnalysis(alignmentContext, tieClass, primaryContrasts) {
  const allFamilies = Array.isArray(alignmentContext?.allFamilies) ? alignmentContext.allFamilies : [];
  const contrastContinuations = (Array.isArray(primaryContrasts) ? primaryContrasts : [])
    .map((row) => Number(row?.continuation))
    .filter((continuation) => Number.isFinite(continuation));
  const continuations = [...new Set([
    ...(Array.isArray(tieClass) ? tieClass : []).map((continuation) => Number(continuation)),
    ...contrastContinuations,
  ].filter((continuation) => Number.isFinite(continuation)))];
  if (allFamilies.length === 0 || continuations.length === 0) {
    return {
      checkerId: 'p848_top_repair_plus2_family_menu_replay_checker_v1',
      status: 'family_menu_unavailable',
      failCount: 1,
      checkedRowCount: 0,
      reason: 'The family menu or continuation set is unavailable.',
    };
  }

  const maxRepresentative = Math.max(...allFamilies.map((row) => Number(row?.representative)).filter(Number.isFinite));
  const maxContinuation = Math.max(...continuations);
  const primes = buildPrimeList(Math.floor(Math.sqrt(maxRepresentative * maxContinuation + 1)) + 1);
  const scores = continuations.map((continuation) => scoreP848FamilyMenuContinuation(allFamilies, continuation, primes));
  const scoreByContinuation = Object.fromEntries(scores.map((score) => [score.continuation, score]));
  const leaderboardByContinuation = Object.fromEntries((Array.isArray(alignmentContext?.gpuLeaderboard) ? alignmentContext.gpuLeaderboard : [])
    .map((row) => [Number(row?.continuation), row]));
  const trackedByContinuation = Object.fromEntries((Array.isArray(alignmentContext?.trackedTailMatrix) ? alignmentContext.trackedTailMatrix : [])
    .map((row) => [Number(row?.continuation), row]));
  const topScores = (Array.isArray(tieClass) ? tieClass : [])
    .map((continuation) => scoreByContinuation[Number(continuation)])
    .filter(Boolean);
  const contrastScores = contrastContinuations
    .map((continuation) => scoreByContinuation[continuation])
    .filter(Boolean);
  const predictedFamilyCount = scores[0]?.predictedFamilyCount ?? null;
  const allTopMiss13 = topScores.every((score) => score.missedPredictedFamilyCount === 13);
  const allPrimaryContrastsMiss15 = contrastScores.every((score) => score.missedPredictedFamilyCount === 15);
  const allTopRepair242 = topScores.every((score) => score.repairedPredictedFamilyCount === 242);
  const allPrimaryContrastsRepair240 = contrastScores.every((score) => score.repairedPredictedFamilyCount === 240);
  const allScoresMatchLeaderboard = scores.every((score) => {
    const leaderboardRow = leaderboardByContinuation[score.continuation];
    if (!leaderboardRow) {
      return true;
    }
    return Number(leaderboardRow.repaired_predicted_families) === score.repairedPredictedFamilyCount;
  });
  const allScoresMatchTrackedRows = scores.every((score) => {
    const trackedRow = trackedByContinuation[score.continuation];
    if (!trackedRow) {
      return true;
    }
    return Number(trackedRow.repaired_predicted_family_count) === score.repairedPredictedFamilyCount;
  });
  const missedKeysByContinuation = Object.fromEntries(scores.map((score) => [
    score.continuation,
    new Set(score.missedPredictedRows.map(getP848ScoredFamilyRowKey)),
  ]));
  const topTieSharedMissedPredictedRows = topScores.length === 0
    ? []
    : topScores[0].missedPredictedRows
      .filter((row) => topScores.every((score) => missedKeysByContinuation[score.continuation].has(getP848ScoredFamilyRowKey(row))))
      .map(summarizeP848ScoredFamilyRow);
  const pairwiseDeltas = topScores.flatMap((topScore) => contrastScores.map((contrastScore) => {
    const topMissedKeys = missedKeysByContinuation[topScore.continuation];
    const contrastMissedKeys = missedKeysByContinuation[contrastScore.continuation];
    const contrastOnlyMissedRows = contrastScore.missedPredictedRows
      .filter((row) => !topMissedKeys.has(getP848ScoredFamilyRowKey(row)));
    const topOnlyMissedRows = topScore.missedPredictedRows
      .filter((row) => !contrastMissedKeys.has(getP848ScoredFamilyRowKey(row)));
    const netExtraRepairsForTop = contrastOnlyMissedRows.length - topOnlyMissedRows.length;
    return {
      topContinuation: topScore.continuation,
      contrastContinuation: contrastScore.continuation,
      topMissedPredictedFamilyCount: topScore.missedPredictedFamilyCount,
      contrastMissedPredictedFamilyCount: contrastScore.missedPredictedFamilyCount,
      topRepairedPredictedFamilyCount: topScore.repairedPredictedFamilyCount,
      contrastRepairedPredictedFamilyCount: contrastScore.repairedPredictedFamilyCount,
      contrastOnlyMissCount: contrastOnlyMissedRows.length,
      topOnlyMissCount: topOnlyMissedRows.length,
      netExtraRepairsForTop,
      dominanceKind: topOnlyMissedRows.length === 0 && netExtraRepairsForTop === 2
        ? 'strict_superset_on_predicted_menu'
        : 'net_exchange',
      status: netExtraRepairsForTop === 2 ? 'net_plus2_certified' : 'unresolved',
      contrastOnlyMissedRows: contrastOnlyMissedRows.map((row) => summarizeP848ExchangeFamilyRow(row, topScore.continuation)),
      topOnlyMissedRows: topOnlyMissedRows.map((row) => summarizeP848ExchangeFamilyRow(row, contrastScore.continuation)),
    };
  }));
  const strictDominancePairs = pairwiseDeltas
    .filter((row) => row.dominanceKind === 'strict_superset_on_predicted_menu')
    .map((row) => ({
      topContinuation: row.topContinuation,
      contrastContinuation: row.contrastContinuation,
      repairedByTopMissedByContrast: row.contrastOnlyMissedRows,
    }));
  const mod50LaneSignature = buildP848Mod50LaneSignature(pairwiseDeltas, continuations);
  const allPairwiseNetPlus2 = pairwiseDeltas.length > 0
    && pairwiseDeltas.every((row) => row.status === 'net_plus2_certified');
  const status = allTopMiss13
    && allPrimaryContrastsMiss15
    && allTopRepair242
    && allPrimaryContrastsRepair240
    && allPairwiseNetPlus2
    && allScoresMatchLeaderboard
    && allScoresMatchTrackedRows
    ? 'finite_menu_plus2_replay_certified'
    : 'unresolved';

  return {
    checkerId: 'p848_top_repair_plus2_family_menu_replay_checker_v1',
    source: 'raw_family_menu_squarefree_replay',
    familyMenuPath: alignmentContext?.familyMenuPath ?? null,
    status,
    failCount: status === 'finite_menu_plus2_replay_certified' ? 0 : 1,
    checkedRowCount: pairwiseDeltas.length,
    checkedContinuationCount: scores.length,
    checkedPairCount: pairwiseDeltas.length,
    predictedFamilyCount,
    topTieCounts: topScores.map((score) => ({
      continuation: score.continuation,
      repairedPredictedFamilyCount: score.repairedPredictedFamilyCount,
      missedPredictedFamilyCount: score.missedPredictedFamilyCount,
      repairedKnownFamilyCount: score.repairedKnownFamilyCount,
      firstMissedPredictedRepresentatives: score.firstMissedPredictedRepresentatives,
      matchesLeaderboard: leaderboardByContinuation[score.continuation]
        ? Number(leaderboardByContinuation[score.continuation].repaired_predicted_families) === score.repairedPredictedFamilyCount
        : null,
      matchesTrackedTailMatrix: trackedByContinuation[score.continuation]
        ? Number(trackedByContinuation[score.continuation].repaired_predicted_family_count) === score.repairedPredictedFamilyCount
        : null,
    })),
    primaryContrastCounts: contrastScores.map((score) => ({
      continuation: score.continuation,
      repairedPredictedFamilyCount: score.repairedPredictedFamilyCount,
      missedPredictedFamilyCount: score.missedPredictedFamilyCount,
      repairedKnownFamilyCount: score.repairedKnownFamilyCount,
      firstMissedPredictedRepresentatives: score.firstMissedPredictedRepresentatives,
      matchesLeaderboard: leaderboardByContinuation[score.continuation]
        ? Number(leaderboardByContinuation[score.continuation].repaired_predicted_families) === score.repairedPredictedFamilyCount
        : null,
      matchesTrackedTailMatrix: trackedByContinuation[score.continuation]
        ? Number(trackedByContinuation[score.continuation].repaired_predicted_family_count) === score.repairedPredictedFamilyCount
        : null,
    })),
    topTieSharedMissedPredictedRows,
    pairwiseDeltas,
    strictDominancePairs,
    mod50LaneSignature,
    verifiedAgainstBridge: {
      allScoresMatchLeaderboard,
      allScoresMatchTrackedRows,
      allTopMiss13,
      allPrimaryContrastsMiss15,
      allTopRepair242,
      allPrimaryContrastsRepair240,
      allPairwiseNetPlus2,
    },
    conclusion: status === 'finite_menu_plus2_replay_certified'
      ? `The current finite menu has ${predictedFamilyCount} predicted families; each top tail misses 13 and each primary contrast misses 15, so the top tie repairs exactly two more predicted families under the same menu evidence.`
      : 'The finite-menu replay did not certify the full +2 separation under the current bridge evidence.',
  };
}

function buildP848TopRepairClassMechanism(alignmentContext) {
  const tieClass = Array.isArray(alignmentContext?.bridgeState?.top_gpu_tie_class)
    ? alignmentContext.bridgeState.top_gpu_tie_class
    : [];
  if (tieClass.length === 0) {
    return null;
  }

  const trackedRows = tieClass
    .map((continuation) => alignmentContext.trackedTailMatrix.find((row) => Number(row?.continuation) === Number(continuation)) ?? null)
    .filter(Boolean);
  const leaderboardRows = tieClass
    .map((continuation) => alignmentContext.gpuLeaderboard.find((row) => Number(row?.continuation) === Number(continuation)) ?? null)
    .filter(Boolean);
  if (trackedRows.length !== tieClass.length || leaderboardRows.length !== tieClass.length) {
    return null;
  }

  const uniqueSorted = (values) => [...new Set((Array.isArray(values) ? values : [])
    .filter((value) => value !== null && value !== undefined)
    .map((value) => Number(value))
    .filter((value) => Number.isFinite(value)))]
    .sort((left, right) => left - right);
  const missedSets = trackedRows.map((row) => uniqueSorted(row.first_missed_predicted_representatives));
  const commonMissedPredictedRepresentatives = missedSets.length === 0
    ? []
    : missedSets.slice(1).reduce(
      (common, values) => common.filter((value) => values.includes(value)),
      missedSets[0],
    );
  const tailSpecificMissedPredictedRepresentatives = Object.fromEntries(trackedRows.map((row, index) => [
    row.continuation,
    missedSets[index].filter((value) => !commonMissedPredictedRepresentatives.includes(value)),
  ]));
  const nearestContrasts = alignmentContext.gpuLeaderboard
    .filter((row) => !tieClass.includes(row.continuation))
    .filter((row) => Number(row.repaired_known_packets) === Number(leaderboardRows[0].repaired_known_packets))
    .slice(0, 5);
  const primaryContrasts = nearestContrasts.slice(0, 3);
  const separationAnalysis = buildP848TopRepairSeparationAnalysis(alignmentContext, tieClass, primaryContrasts);
  const sameMetric = (key, rows) => rows.every((row) => row?.[key] === rows[0]?.[key]);
  const mod50Lane = uniqueSorted([
    ...tieClass,
    ...nearestContrasts.map((row) => row.continuation),
  ].map((continuation) => Number(continuation) % 50));

  return {
    mechanismId: 'p848_top_repair_class_mechanism_packet_v1',
    status: 'seeded_from_bridge',
    tieClass,
    currentFamilyAwareLeader: alignmentContext.bridgeState?.current_family_aware_leader ?? null,
    bridgeLeaderboardRows: leaderboardRows,
    trackedTailRows: trackedRows,
    sharedMetrics: {
      repairedKnownPackets: leaderboardRows[0]?.repaired_known_packets ?? null,
      repairedPredictedFamilies: leaderboardRows[0]?.repaired_predicted_families ?? null,
      directCleanThrough: leaderboardRows[0]?.direct_clean_through ?? null,
      effectiveCleanThrough: leaderboardRows[0]?.effective_clean_through ?? null,
      trackedRepairedKnownFamilyCount: trackedRows[0]?.repaired_known_family_count ?? null,
      trackedMissedKnownPackets: trackedRows[0]?.missed_known_packets ?? null,
      trackedExtensionMode: trackedRows[0]?.extension_mode ?? null,
      sameRepairedKnownPackets: sameMetric('repaired_known_packets', leaderboardRows),
      sameRepairedPredictedFamilies: sameMetric('repaired_predicted_families', leaderboardRows),
      sameCleanThrough: sameMetric('effective_clean_through', leaderboardRows),
      sameTrackedKnownFamilyCount: sameMetric('repaired_known_family_count', trackedRows),
      sameTrackedMissedKnownPackets: sameMetric('missed_known_packets', trackedRows),
      sameTrackedExtensionMode: sameMetric('extension_mode', trackedRows),
    },
    nearestContrasts,
    primaryContrasts: primaryContrasts.map((row) => row.continuation),
    contrastSummary: nearestContrasts.length > 0
      ? `Nearest same-known-packet contrasts ${nearestContrasts.map((row) => row.continuation).join(', ')} have repaired-predicted counts ${nearestContrasts.map((row) => `${row.continuation}->${row.repaired_predicted_families}`).join(', ')}.`
      : 'No nearest same-known-packet contrast rows are available in the current leaderboard.',
    separationAnalysis,
    commonMissedPredictedRepresentatives,
    tailSpecificMissedPredictedRepresentatives,
    residueLaneAssessment: {
      tieClassModulo50: uniqueSorted(tieClass.map((continuation) => Number(continuation) % 50)),
      nearbyModulo50Values: mod50Lane,
      verdict: mod50Lane.length === 1
        ? 'shared_mod_50_lane_but_not_sufficient'
        : 'mixed_mod_50_lane',
      note: 'The top tie is in the same mod-50 lane as several near contrasts, so the mod-50 lane is useful context but not by itself the repair mechanism.',
    },
    mechanismHypotheses: [
      {
        hypothesisId: 'shared_repair_count_signature',
        status: 'supported_by_bridge',
        note: 'All top tails share repaired-known=26, repaired-predicted=242, and clean-through=250075000 on the bridge leaderboard.',
      },
      {
        hypothesisId: 'plus50_lane_context',
        status: 'necessary_not_sufficient',
        note: 'The top tails share the same mod-50 lane, but nearby contrasts in that lane do not all reach 242 predicted repairs.',
      },
      {
        hypothesisId: 'common_missed_family_boundary',
        status: commonMissedPredictedRepresentatives.length > 0 ? 'supported_by_tracked_tail_matrix' : 'unresolved',
        note: `The top tails share ${commonMissedPredictedRepresentatives.length} early missed predicted representatives in the tracked-tail matrix.`,
      },
      {
        hypothesisId: 'finite_menu_plus2_separation',
        status: separationAnalysis.status === 'finite_menu_plus2_replay_certified' ? 'certified_by_replay' : 'unresolved',
        note: separationAnalysis.conclusion,
      },
    ],
    falsifierBoundary: [
      'A bridge refresh breaks the 432, 782, 832 tie on repaired-known, repaired-predicted, or clean-through metrics.',
      'A near contrast such as 332, 382, or 1232 reaches the same predicted repair count under the same evidence boundary.',
      'The apparent common missed-family representatives disappear when the family menu is refreshed.',
      'A direct exact extension finds an earlier failure for one member of the top tie inside the claimed clean-through window.',
    ],
    nextProofObligations: [
      separationAnalysis.mod50LaneSignature?.status === 'finite_menu_mod50_lane_signature_certified'
        ? 'Generalize the mod-50 lane-index bad-family signature beyond the finite exchange rows.'
        : separationAnalysis.status === 'finite_menu_plus2_replay_certified'
        ? 'Lift the finite-menu +2 repair separation into a symbolic residue/family signature for the mod-50 lane.'
        : 'Explain the +2 repaired-predicted-family separation between 432/782/832 and the nearest same-known-packet contrasts 332/382/1232.',
      'Derive a residue or family signature that separates the top tie from the rest of the mod-50 lane.',
      separationAnalysis.mod50LaneSignature?.status === 'finite_menu_mod50_lane_signature_certified'
        ? 'Choose the strict 782 vs 1232 handoff rows or a broader exchange family as the next theorem-facing symbolic family.'
        : separationAnalysis.status === 'finite_menu_plus2_replay_certified'
        ? 'Decide which pairwise exchange rows should become the next theorem-facing symbolic family.'
        : 'Replay the common missed-family representatives against the family menu to identify which predicted repairs distinguish the tie.',
    ],
  };
}

function summarizeChecklist(items) {
  const rows = Array.isArray(items) ? items : [];
  return {
    total: rows.length,
    ready: rows.filter((item) => item?.status === 'ready').length,
    inProgress: rows.filter((item) => item?.status === 'in_progress').length,
    blocked: rows.filter((item) => item?.status === 'blocked').length,
    done: rows.filter((item) => item?.status === 'done').length,
  };
}

function renderChecklistItem(item) {
  if (typeof item === 'string') {
    return item;
  }
  const parts = [];
  if (item?.task) {
    parts.push(item.task);
  }
  if (item?.why) {
    parts.push(item.why);
  }
  if (item?.dischargeWith) {
    parts.push(`discharge: ${item.dischargeWith}`);
  }
  if (item?.command) {
    parts.push(`command: ${item.command}`);
  }
  const body = parts.join(' | ');
  if (item?.obligationId || item?.checkId || item?.criterionId) {
    const id = item.obligationId ?? item.checkId ?? item.criterionId;
    return `\`${id}\`: ${item.status ?? 'ready'}${body ? ` | ${body}` : ''}`;
  }
  return body || '(unspecified)';
}

function escapeXml(value) {
  return String(value ?? '')
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll("'", '&apos;');
}

function wrapSvgText(text, maxLength = 44) {
  const source = String(text ?? '').trim();
  if (!source) {
    return [];
  }

  const words = source.split(/\s+/);
  const lines = [];
  let current = '';
  for (const word of words) {
    const candidate = current ? `${current} ${word}` : word;
    if (candidate.length <= maxLength) {
      current = candidate;
      continue;
    }
    if (current) {
      lines.push(current);
    }
    current = word;
  }
  if (current) {
    lines.push(current);
  }
  return lines;
}

function renderP848FormalizationWorkDiagram(doc) {
  const target = doc?.currentWork ?? {};
  const packet = target.packetData ?? {};
  const rowTable = Array.isArray(packet.rowProgressionAnchorTable) ? packet.rowProgressionAnchorTable : [];
  const anchorTable = Array.isArray(packet.anchorCongruenceTable) ? packet.anchorCongruenceTable : [];
  const priorRows = Array.isArray(packet.priorRowsModuloWitness) ? packet.priorRowsModuloWitness : [];
  const period = Math.max(...rowTable.map((row) => Number(row.rowIndexPeriod)).filter(Number.isFinite), Number(packet.witnessSquareModulus) || 1);
  const witness = packet.witnessSquareModulus ?? '(unknown)';
  const representative = packet.representative ?? '(unknown)';
  const nextSameRowWitness = packet.nextSameRowWitnessFor282 ?? null;
  const crtDerivation = packet.tupleRowCrtDerivation ?? null;
  const width = 1440;
  const height = 980;
  const chartLeft = 90;
  const chartTop = 280;
  const chartWidth = 760;
  const chartHeight = 420;
  const rowSpacing = chartHeight / Math.max(rowTable.length, 1);
  const neverX = chartLeft + chartWidth + 95;
  const tickValues = [0, Math.floor(period / 4), Math.floor(period / 2), Math.floor((3 * period) / 4), period];

  const lines = [
    `<svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}" viewBox="0 0 ${width} ${height}" role="img" aria-labelledby="title desc">`,
    `<title id="title">${escapeXml(doc.displayName)} formalization work diagram</title>`,
    `<desc id="desc">Diagram of the 848 shared-prefix row progression showing when tracked anchors hit witness ${escapeXml(witness)} and why anchor 282 is special at row index 0.</desc>`,
    '<defs>',
    '<linearGradient id="bg" x1="0" x2="1" y1="0" y2="1">',
    '<stop offset="0%" stop-color="#f7fbf7"/>',
    '<stop offset="100%" stop-color="#eef4f2"/>',
    '</linearGradient>',
    '<linearGradient id="panel" x1="0" x2="0" y1="0" y2="1">',
    '<stop offset="0%" stop-color="#ffffff"/>',
    '<stop offset="100%" stop-color="#f6fbfa"/>',
    '</linearGradient>',
    '<filter id="shadow" x="-20%" y="-20%" width="140%" height="140%">',
    '<feDropShadow dx="0" dy="10" stdDeviation="12" flood-color="#0d3b30" flood-opacity="0.08"/>',
    '</filter>',
    '</defs>',
    `<rect x="0" y="0" width="${width}" height="${height}" fill="url(#bg)"/>`,
    '<rect x="40" y="34" width="1360" height="912" rx="28" fill="#ffffff" stroke="#d7e6df" filter="url(#shadow)"/>',
    `<text x="88" y="92" font-family="Georgia, 'Times New Roman', serif" font-size="36" font-weight="700" fill="#11352e">${escapeXml(doc.displayName)}: 282 / 841 Mechanism</text>`,
    `<text x="88" y="126" font-family="ui-sans-serif, system-ui, sans-serif" font-size="18" fill="#44635a">Representative ${escapeXml(representative)} on tuple ${escapeXml(packet.tupleKey ?? '(unknown tuple)')}</text>`,
    `<text x="88" y="152" font-family="ui-sans-serif, system-ui, sans-serif" font-size="17" fill="#44635a">Witness ${escapeXml(witness)} is the extra repair witness; the row progression itself still traverses all residues modulo ${escapeXml(witness)}.</text>`,
    crtDerivation
      ? `<text x="88" y="174" font-family="ui-sans-serif, system-ui, sans-serif" font-size="16" fill="#44635a">Tuple-row CRT projects to ${escapeXml(crtDerivation.projectedResidueModuloWitness)} mod ${escapeXml(witness)}${crtDerivation.firstStableProjectionAnchor ? `, stabilizing when anchor ${escapeXml(crtDerivation.firstStableProjectionAnchor)} is added` : ''}.</text>`
      : '',
  ];

  const cards = [
    { x: 88, y: 184, w: 220, h: 72, label: 'Verdict', value: target.mechanismAssessment?.verdict ?? 'unresolved', accent: '#0f766e' },
    { x: 326, y: 184, w: 220, h: 72, label: 'Representative residue', value: `${packet.representativeResidueModuloWitness ?? '(unknown)'} mod ${witness}`, accent: '#1d4ed8' },
    { x: 564, y: 184, w: 220, h: 72, label: '282 row start', value: 't = 0', accent: '#b91c1c' },
    { x: 802, y: 184, w: 270, h: 72, label: 'Next same-row 282 hit', value: nextSameRowWitness ?? '(unknown)', accent: '#7c3aed' },
    { x: 1090, y: 184, w: 260, h: 72, label: 'Verified base', value: doc.currentState?.latestVerifiedInterval ?? '(unknown)', accent: '#9a3412' },
  ];

  for (const card of cards) {
    lines.push(`<rect x="${card.x}" y="${card.y}" width="${card.w}" height="${card.h}" rx="18" fill="url(#panel)" stroke="#d6e5df"/>`);
    lines.push(`<rect x="${card.x + 1}" y="${card.y + 1}" width="${card.w - 2}" height="9" rx="8" fill="${card.accent}"/>`);
    lines.push(`<text x="${card.x + 16}" y="${card.y + 34}" font-family="ui-sans-serif, system-ui, sans-serif" font-size="14" font-weight="700" fill="#45645b">${escapeXml(card.label)}</text>`);
    lines.push(`<text x="${card.x + 16}" y="${card.y + 58}" font-family="ui-sans-serif, system-ui, sans-serif" font-size="22" font-weight="700" fill="#173c34">${escapeXml(card.value)}</text>`);
  }

  lines.push(`<rect x="${chartLeft - 26}" y="${chartTop - 40}" width="${chartWidth + 320}" height="${chartHeight + 110}" rx="28" fill="url(#panel)" stroke="#d6e5df"/>`);
  lines.push(`<text x="${chartLeft}" y="${chartTop - 8}" font-family="Georgia, 'Times New Roman', serif" font-size="24" font-weight="700" fill="#133730">Shared-Prefix Row Progression</text>`);
  lines.push(`<text x="${chartLeft}" y="${chartTop + 18}" font-family="ui-sans-serif, system-ui, sans-serif" font-size="16" fill="#45645b">Each point shows the first row index t where a tracked anchor can hit witness ${escapeXml(witness)} along n = residue + modulus * t.</text>`);
  lines.push(`<line x1="${chartLeft}" y1="${chartTop + chartHeight}" x2="${chartLeft + chartWidth}" y2="${chartTop + chartHeight}" stroke="#7ca191" stroke-width="2"/>`);
  lines.push(`<line x1="${chartLeft}" y1="${chartTop}" x2="${chartLeft}" y2="${chartTop + chartHeight}" stroke="#7ca191" stroke-width="2"/>`);
  lines.push(`<line x1="${neverX}" y1="${chartTop}" x2="${neverX}" y2="${chartTop + chartHeight}" stroke="#d0a37f" stroke-width="2" stroke-dasharray="8 8"/>`);
  lines.push(`<text x="${neverX - 18}" y="${chartTop - 16}" font-family="ui-sans-serif, system-ui, sans-serif" font-size="14" font-weight="700" fill="#9a3412">never</text>`);

  for (const tick of tickValues) {
    const x = chartLeft + (chartWidth * tick) / period;
    lines.push(`<line x1="${x}" y1="${chartTop + chartHeight}" x2="${x}" y2="${chartTop + chartHeight + 8}" stroke="#7ca191" stroke-width="2"/>`);
    lines.push(`<text x="${x}" y="${chartTop + chartHeight + 30}" text-anchor="middle" font-family="ui-sans-serif, system-ui, sans-serif" font-size="13" fill="#567269">${escapeXml(tick)}</text>`);
  }

  rowTable.forEach((row, index) => {
    const y = chartTop + rowSpacing * index + rowSpacing / 2;
    const is282 = row.anchor === 282;
    const fill = is282 ? '#b91c1c' : row.solvableAlongRowProgression ? '#0f766e' : '#9a3412';
    const radius = is282 ? 9 : 7;
    lines.push(`<line x1="${chartLeft}" y1="${y}" x2="${chartLeft + chartWidth}" y2="${y}" stroke="#ebf1ee" stroke-width="1"/>`);
    lines.push(`<text x="${chartLeft - 16}" y="${y + 5}" text-anchor="end" font-family="ui-sans-serif, system-ui, sans-serif" font-size="15" font-weight="${is282 ? '700' : '600'}" fill="${is282 ? '#7f1d1d' : '#24453d'}">${escapeXml(row.anchor)}</text>`);
    if (row.solvableAlongRowProgression && Number.isInteger(row.rowIndexForWitness)) {
      const x = chartLeft + (chartWidth * row.rowIndexForWitness) / period;
      lines.push(`<circle cx="${x}" cy="${y}" r="${radius}" fill="${fill}" stroke="#ffffff" stroke-width="3"/>`);
      lines.push(`<text x="${x + 12}" y="${y - 10}" font-family="ui-sans-serif, system-ui, sans-serif" font-size="13" fill="${fill}">t=${escapeXml(row.rowIndexForWitness)}</text>`);
    } else {
      lines.push(`<circle cx="${neverX}" cy="${y}" r="${radius}" fill="${fill}" stroke="#ffffff" stroke-width="3"/>`);
      lines.push(`<text x="${neverX + 14}" y="${y + 5}" font-family="ui-sans-serif, system-ui, sans-serif" font-size="13" fill="${fill}">no solution</text>`);
    }
  });

  const congruencePanelX = 920;
  const congruencePanelY = 330;
  const congruenceRows = anchorTable.slice(0, 8);
  lines.push(`<text x="${congruencePanelX}" y="${congruencePanelY - 26}" font-family="Georgia, 'Times New Roman', serif" font-size="24" font-weight="700" fill="#133730">Residue Match Slice</text>`);
  lines.push(`<text x="${congruencePanelX}" y="${congruencePanelY - 2}" font-family="ui-sans-serif, system-ui, sans-serif" font-size="15" fill="#45645b">Representative residue 504 matches only the 282 failure residue class.</text>`);
  congruenceRows.forEach((row, index) => {
    const y = congruencePanelY + index * 42;
    const active = row.matchesRepresentativeResidue;
    const bg = active ? '#fdecec' : row.solvableModuloWitness ? '#eef7f4' : '#fff4ea';
    const stroke = active ? '#b91c1c' : row.solvableModuloWitness ? '#cfe3dc' : '#f1c7a3';
    lines.push(`<rect x="${congruencePanelX}" y="${y}" width="380" height="32" rx="10" fill="${bg}" stroke="${stroke}"/>`);
    lines.push(`<text x="${congruencePanelX + 12}" y="${y + 21}" font-family="ui-sans-serif, system-ui, sans-serif" font-size="14" font-weight="700" fill="#24453d">${escapeXml(row.anchor)}</text>`);
    lines.push(`<text x="${congruencePanelX + 74}" y="${y + 21}" font-family="ui-sans-serif, system-ui, sans-serif" font-size="13" fill="#45645b">needs ${escapeXml(row.requiredNResidueForFailure ?? 'none')}</text>`);
    lines.push(`<text x="${congruencePanelX + 188}" y="${y + 21}" font-family="ui-sans-serif, system-ui, sans-serif" font-size="13" fill="${active ? '#991b1b' : '#45645b'}">${escapeXml(active ? 'matches rep' : row.solvableModuloWitness ? 'later/other residue' : 'unsolvable')}</text>`);
    lines.push(`<text x="${congruencePanelX + 314}" y="${y + 21}" font-family="ui-sans-serif, system-ui, sans-serif" font-size="13" fill="#45645b">res=${escapeXml(row.residueCheck)}</text>`);
  });

  const priorPanelX = 920;
  const priorPanelY = 710;
  lines.push(`<text x="${priorPanelX}" y="${priorPanelY - 18}" font-family="Georgia, 'Times New Roman', serif" font-size="24" font-weight="700" fill="#133730">Earlier Boundary Rows</text>`);
  lines.push(`<text x="${priorPanelX}" y="${priorPanelY + 6}" font-family="ui-sans-serif, system-ui, sans-serif" font-size="15" fill="#45645b">Earlier rows stay nonzero mod ${escapeXml(witness)} before the first 282 failure lands.</text>`);
  priorRows.forEach((row, index) => {
    const y = priorPanelY + 26 + index * 34;
    lines.push(`<rect x="${priorPanelX}" y="${y}" width="388" height="26" rx="9" fill="#f6faf8" stroke="#d6e5df"/>`);
    lines.push(`<text x="${priorPanelX + 12}" y="${y + 17}" font-family="ui-sans-serif, system-ui, sans-serif" font-size="13" font-weight="700" fill="#24453d">${escapeXml(row.representative)}</text>`);
    lines.push(`<text x="${priorPanelX + 160}" y="${y + 17}" font-family="ui-sans-serif, system-ui, sans-serif" font-size="13" fill="#45645b">res=${escapeXml(row.residueModuloWitness)}</text>`);
    lines.push(`<text x="${priorPanelX + 246}" y="${y + 17}" font-family="ui-sans-serif, system-ui, sans-serif" font-size="13" fill="#45645b">${escapeXml(row.tupleKey)}</text>`);
  });

  if (crtDerivation && Array.isArray(crtDerivation.steps) && crtDerivation.steps.length > 0) {
    const crtPanelX = 88;
    const crtPanelY = 784;
    lines.push(`<text x="${crtPanelX}" y="${crtPanelY}" font-family="Georgia, 'Times New Roman', serif" font-size="22" font-weight="700" fill="#133730">Tuple-Row CRT Projection</text>`);
    lines.push(`<text x="${crtPanelX}" y="${crtPanelY + 24}" font-family="ui-sans-serif, system-ui, sans-serif" font-size="15" fill="#45645b">As tuple congruences are added, the projected residue modulo ${escapeXml(witness)} evolves toward the boundary value ${escapeXml(crtDerivation.projectedResidueModuloWitness)}.</text>`);
    crtDerivation.steps.slice(0, 6).forEach((step, index) => {
      const x = crtPanelX + index * 120;
      const y = crtPanelY + 54;
      const active = step.residueModWitness === crtDerivation.projectedResidueModuloWitness;
      lines.push(`<rect x="${x}" y="${y}" width="106" height="76" rx="14" fill="${active ? '#eef6ff' : '#f6faf8'}" stroke="${active ? '#7aa3e8' : '#d6e5df'}"/>`);
      lines.push(`<text x="${x + 12}" y="${y + 24}" font-family="ui-sans-serif, system-ui, sans-serif" font-size="13" font-weight="700" fill="#24453d">a=${escapeXml(step.anchor)}</text>`);
      lines.push(`<text x="${x + 12}" y="${y + 45}" font-family="ui-sans-serif, system-ui, sans-serif" font-size="12" fill="#45645b">mod ${escapeXml(step.combinedModulus)}</text>`);
      lines.push(`<text x="${x + 12}" y="${y + 64}" font-family="ui-sans-serif, system-ui, sans-serif" font-size="13" fill="${active ? '#1d4ed8' : '#45645b'}">res ${escapeXml(step.residueModWitness)}</text>`);
    });
  }

  lines.push(`<text x="88" y="914" font-family="ui-sans-serif, system-ui, sans-serif" font-size="16" fill="#3f5b52">North-star reading: the row does not force 841 by itself, but the boundary representative is the unique tracked start-point of the 282 witness class inside that row progression.</text>`);
  lines.push('</svg>');
  return lines.join('');
}

function renderGenericFormalizationWorkDiagram(doc) {
  const target = doc?.currentWork ?? {};
  const width = 1200;
  const height = 780;
  const lines = [
    `<svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}" viewBox="0 0 ${width} ${height}" role="img" aria-labelledby="title desc">`,
    `<title id="title">${escapeXml(doc.displayName)} formalization work diagram</title>`,
    `<desc id="desc">Generic visual summary of the current formalization-work packet.</desc>`,
    '<rect x="0" y="0" width="1200" height="780" fill="#f7fbf8"/>',
    '<rect x="40" y="36" width="1120" height="708" rx="28" fill="#ffffff" stroke="#d6e5df"/>',
    `<text x="82" y="94" font-family="Georgia, 'Times New Roman', serif" font-size="34" font-weight="700" fill="#11352e">${escapeXml(doc.displayName)} Formalization Work</text>`,
    `<text x="82" y="126" font-family="ui-sans-serif, system-ui, sans-serif" font-size="18" fill="#45645b">${escapeXml(target.title ?? '(no current work)')}</text>`,
    `<text x="82" y="154" font-family="ui-sans-serif, system-ui, sans-serif" font-size="16" fill="#45645b">Status: ${escapeXml(target.status ?? '(unknown)')} | Route: ${escapeXml(doc.currentState?.activeRoute ?? '(none)')}</text>`,
    '<rect x="80" y="196" width="490" height="492" rx="24" fill="#f8fcfa" stroke="#d6e5df"/>',
    '<rect x="602" y="196" width="478" height="492" rx="24" fill="#f8fcfa" stroke="#d6e5df"/>',
    '<text x="104" y="234" font-family="Georgia, \'Times New Roman\', serif" font-size="24" font-weight="700" fill="#133730">Working Definition</text>',
    '<text x="626" y="234" font-family="Georgia, \'Times New Roman\', serif" font-size="24" font-weight="700" fill="#133730">Current Evidence</text>',
  ];

  (target.workingDefinition ?? []).slice(0, 8).forEach((item, index) => {
    const y = 274 + index * 48;
    wrapSvgText(item, 48).forEach((line, lineIndex) => {
      lines.push(`<text x="106" y="${y + lineIndex * 18}" font-family="ui-sans-serif, system-ui, sans-serif" font-size="15" fill="#24453d">• ${escapeXml(line)}</text>`);
    });
  });
  (target.currentEvidence ?? []).slice(0, 8).forEach((item, index) => {
    const y = 274 + index * 48;
    wrapSvgText(item, 46).forEach((line, lineIndex) => {
      lines.push(`<text x="628" y="${y + lineIndex * 18}" font-family="ui-sans-serif, system-ui, sans-serif" font-size="15" fill="#24453d">• ${escapeXml(line)}</text>`);
    });
  });

  lines.push(`<text x="82" y="724" font-family="ui-sans-serif, system-ui, sans-serif" font-size="16" fill="#45645b">Canonical files: ${escapeXml(doc.sources?.formalizationWorkJsonPath ?? '(none)')} and ${escapeXml(doc.sources?.formalizationWorkMarkdownPath ?? '(none)')}</text>`);
  lines.push('</svg>');
  return lines.join('');
}

export function renderProblemFormalizationWorkSvg(doc) {
  const target = doc?.currentWork ?? {};
  if (Array.isArray(target?.packetData?.rowProgressionAnchorTable) && target.packetData.rowProgressionAnchorTable.length > 0) {
    return renderP848FormalizationWorkDiagram(doc);
  }
  return renderGenericFormalizationWorkDiagram(doc);
}

function buildP848AlignmentContext(theoremLoop) {
  const bridgePath = theoremLoop?.sources?.legacyBridgeJsonPath ?? null;
  const bridgeDoc = bridgePath ? readJsonIfPresent(bridgePath) : null;
  const bridgeState = bridgeDoc?.current_bridge_state ?? null;
  const nextRepresentative = bridgeState?.next_unmatched_representative ?? null;
  const familyMenuPath = bridgeDoc?.sources?.family_menu_source_path ?? null;
  const familyMenu = familyMenuPath ? readJsonIfPresent(familyMenuPath) : null;
  const familyMenuRow = Array.isArray(familyMenu?.families) && nextRepresentative !== null
    ? familyMenu.families.find((row) => row?.representative === nextRepresentative) ?? null
    : null;
  const packProblemDir = theoremLoop?.sources?.packProblemDir ?? (bridgePath ? path.dirname(bridgePath) : null);
  const obstructionPacketPath = packProblemDir
    ? path.join(packProblemDir, 'SPLIT_ATOM_PACKETS', 'FRONTIER_BRIDGE', 'P848_282_ALIGNMENT_OBSTRUCTION_PACKET.json')
    : null;
  const obstructionPacket = obstructionPacketPath ? readJsonIfPresent(obstructionPacketPath) : null;
  const recoveredFamilyRow = obstructionPacket?.recoveredFamilyRow
    && nextRepresentative !== null
    && Number(obstructionPacket.recoveredFamilyRow.representative) === Number(nextRepresentative)
    ? obstructionPacket.recoveredFamilyRow
    : null;
  const familyRow = familyMenuRow ?? recoveredFamilyRow;
  const familyRowSource = familyMenuRow
    ? 'live_family_menu'
    : recoveredFamilyRow
    ? 'recovered_alignment_obstruction_packet'
    : null;
  const trackedTailMatrix = Array.isArray(bridgeDoc?.tracked_tail_matrix) ? bridgeDoc.tracked_tail_matrix : [];
  const gpuLeaderboard = Array.isArray(bridgeDoc?.gpu_leaderboard) ? bridgeDoc.gpu_leaderboard : [];
  const trackedTail282 = trackedTailMatrix.find((row) => row?.continuation === 282) ?? null;
  const allFamilies = Array.isArray(familyMenu?.families) ? familyMenu.families : [];
  const sameTupleFamilies = familyRow?.tupleKey
    ? allFamilies.filter((row) => row?.tupleKey === familyRow.tupleKey)
    : [];
  const failing282Families = allFamilies
    .filter((row) => Array.isArray(row?.repairRows) && row.repairRows.some((repairRow) => repairRow?.anchor === 282 && repairRow.squarefree === false))
    .sort((left, right) => Number(left?.representative ?? Number.MAX_SAFE_INTEGER) - Number(right?.representative ?? Number.MAX_SAFE_INTEGER));
  const firstFailing282Family = failing282Families[0] ?? null;
  const repairRows = Array.isArray(familyRow?.repairRows) ? familyRow.repairRows : [];
  const stableRepairRows = repairRows.filter((row) => row?.squarefree);
  const failingRepairRows = repairRows.filter((row) => row && row.squarefree === false);
  const failing282 = repairRows.find((row) => row?.anchor === 282 && row.squarefree === false) ?? null;
  const only282Fails = failingRepairRows.length === 1 && failingRepairRows[0]?.anchor === 282;
  const witnessSquareModulus = failing282?.squareWitnesses?.[0]?.squareModulus ?? null;
  const tupleRowCrtDerivation = deriveTupleRowCrt(Array.isArray(familyRow?.tupleRows) ? familyRow.tupleRows : [], witnessSquareModulus);
  const representativeModulus = familyRow?.modulus ?? null;
  const representativeResidue = familyRow?.residue ?? null;
  const rowProgressionModuloWitness = representativeModulus && witnessSquareModulus
    ? {
      gcdModulusWitness: gcdInt(representativeModulus, witnessSquareModulus),
      modulusModWitness: positiveMod(representativeModulus, witnessSquareModulus),
      residueModWitness: representativeResidue !== null ? positiveMod(representativeResidue, witnessSquareModulus) : null,
      traversesAllWitnessResidues: gcdInt(representativeModulus, witnessSquareModulus) === 1,
    }
    : null;
  const rowProgressionAnchorTable = representativeModulus && representativeResidue !== null && witnessSquareModulus
    ? repairRows.map((row) => {
      const progressionCoeff = positiveMod(Number(row.anchor) * Number(representativeModulus), witnessSquareModulus);
      const progressionRhs = positiveMod(-(Number(row.anchor) * Number(representativeResidue) + 1), witnessSquareModulus);
      const congruence = solveLinearCongruenceNonnegative(progressionCoeff, progressionRhs, witnessSquareModulus);
      return {
        anchor: row.anchor,
        progressionCoeffModuloWitness: progressionCoeff,
        progressionRhsModuloWitness: progressionRhs,
        gcdCoeffWitness: congruence?.gcdCoeffModulus ?? null,
        rowIndexForWitness: congruence?.solvable ? congruence.solution : null,
        rowIndexPeriod: congruence?.solvable ? congruence.period : null,
        witnessOccursAtCurrentRepresentative: congruence?.solvable ? congruence.solution === 0 : false,
        solvableAlongRowProgression: Boolean(congruence?.solvable),
        squarefree: row.squarefree,
      };
    })
    : [];
  const rowProgressionAnchor282 = rowProgressionAnchorTable.find((row) => row.anchor === 282) ?? null;
  const nextSameRowWitnessFor282 = rowProgressionAnchor282
    && rowProgressionAnchor282.solvableAlongRowProgression
    && representativeResidue !== null
    && representativeModulus
    && rowProgressionAnchor282.rowIndexPeriod
    ? Number(representativeResidue) + Number(representativeModulus) * (
      rowProgressionAnchor282.rowIndexForWitness === 0
        ? rowProgressionAnchor282.rowIndexPeriod
        : rowProgressionAnchor282.rowIndexForWitness
    )
    : null;
  const repairRow282ForFamily = (family) => Array.isArray(family?.repairRows)
    ? family.repairRows.find((row) => row?.anchor === 282) ?? null
    : null;
  const prior282Rows = firstFailing282Family && witnessSquareModulus
    ? allFamilies
      .filter((row) => Number(row?.representative) < Number(firstFailing282Family.representative))
      .map((row) => ({
        representative: row.representative,
        tupleKey: row.tupleKey ?? null,
        repairRow: repairRow282ForFamily(row),
      }))
      .filter((row) => row.repairRow && Number.isInteger(row.repairRow.value))
      .sort((left, right) => Number(left.representative) - Number(right.representative))
    : [];
  const priorRowsModuloWitness = witnessSquareModulus
    ? prior282Rows.slice(-3).map((row) => ({
      representative: row.representative,
      tupleKey: row.tupleKey,
      residueModuloWitness: Number(row.repairRow.value % witnessSquareModulus),
      squarefree: row.repairRow.squarefree,
    }))
    : [];
  const witnessFirstOccurrence = witnessSquareModulus
    ? (() => {
      const matchingFamilies = allFamilies
        .map((row) => ({
          representative: row?.representative ?? null,
          tupleKey: row?.tupleKey ?? null,
          repairRow: repairRow282ForFamily(row),
        }))
        .filter((row) => row.repairRow && Array.isArray(row.repairRow.squareWitnesses)
          && row.repairRow.squareWitnesses.some((witness) => witness?.squareModulus === witnessSquareModulus))
        .sort((left, right) => Number(left.representative) - Number(right.representative));
      const first = matchingFamilies[0] ?? null;
      return first
        ? {
          squareModulus: witnessSquareModulus,
          firstRepresentative: first.representative,
          firstTupleKey: first.tupleKey,
          earlierRowCount: prior282Rows.length,
          earlierZeroResidueCount: prior282Rows.filter((row) => Number(row.repairRow.value % witnessSquareModulus) === 0).length,
        }
        : null;
    })()
    : null;
  const witnessTimeline = failing282Families
    .map((row) => {
      const repairRow = repairRow282ForFamily(row);
      const squareModulus = repairRow?.squareWitnesses?.[0]?.squareModulus ?? null;
      return squareModulus
        ? {
          representative: row.representative,
          tupleKey: row.tupleKey ?? null,
          witnessSquareModulus: squareModulus,
        }
        : null;
    })
    .filter(Boolean);

  return {
    bridgeDoc,
    bridgeState,
    trackedTailMatrix,
    gpuLeaderboard,
    familyMenuPath,
    familyMenu,
    obstructionPacketPath,
    obstructionPacket,
    allFamilies,
    familyRow,
    familyRowSource,
    nextRepresentative,
    trackedTail282,
    failing282Families,
    firstFailing282Family,
    repairRows,
    stableRepairRows,
    failingRepairRows,
    failing282,
    only282Fails,
    witnessSquareModulus,
    tupleRowCrtDerivation,
    sameTupleCount: sameTupleFamilies.length,
    rowProgressionModuloWitness,
    rowProgressionAnchorTable,
    nextSameRowWitnessFor282,
    prior282Rows,
    priorRowsModuloWitness,
    witnessFirstOccurrence,
    witnessTimeline,
  };
}

function findP848StructuralLiftChecklistStep(checklist, stepId) {
  for (const phase of checklist?.phases ?? []) {
    const step = (phase?.steps ?? []).find((item) => item?.stepId === stepId);
    if (step) {
      return { phase, step };
    }
  }
  return null;
}

function buildP848SameSideBaseCliqueProof() {
  const residueChecks = [
    {
      sideId: 'B7',
      residue: 7,
      productResidueModulo25: positiveMod(7 * 7, 25),
      productPlusOneResidueModulo25: positiveMod((7 * 7) + 1, 25),
    },
    {
      sideId: 'B18',
      residue: 18,
      productResidueModulo25: positiveMod(18 * 18, 25),
      productPlusOneResidueModulo25: positiveMod((18 * 18) + 1, 25),
    },
  ];
  const failedRows = residueChecks.filter((row) => row.productPlusOneResidueModulo25 !== 0);

  return {
    checkerId: 'p848_C1_same_side_base_clique_checker_v1',
    obligationId: 'C1_same_side_base_clique',
    status: failedRows.length === 0 ? 'proved_by_mod25_identity' : 'failed',
    checkedRowCount: residueChecks.length,
    passCount: residueChecks.length - failedRows.length,
    failCount: failedRows.length,
    statement: 'Inside one principal base side, compatible base vertices form a clique for the fixed outsider graph considered by the verifier.',
    scope: {
      problemId: '848',
      universalSameSideClaim: true,
      dependsOnOutsider: false,
      dependsOnN: false,
      principalBaseResiduesModulo25: [7, 18],
    },
    hypotheses: [
      'u and v are both in the 7 mod 25 principal base side, or both in the 18 mod 25 principal base side.',
      'The verifier graph uses non-squarefree pair compatibility: an edge is present when u*v + 1 is not squarefree.',
    ],
    proof: [
      'If u and v are both 7 mod 25, then u*v + 1 is congruent to 7^2 + 1 = 50, hence 0 mod 25.',
      'If u and v are both 18 mod 25, then u*v + 1 is congruent to 18^2 + 1 = 325, hence 0 mod 25.',
      'Because 25 = 5^2 is a square divisor, u*v + 1 is not squarefree in either same-side case.',
      'Therefore every pair of same-side principal base vertices has an edge, so each same-side compatible vertex set is a clique.',
    ],
    residueChecks,
    failedRows,
    conclusion: 'The same-side parts of the mixed-base compatibility graph are cliques; only cross-side edges need the missing-cross graph analysis.',
    falsifierBoundary: failedRows.length === 0
      ? 'A falsifier would need a pair of same-side principal base residues whose product plus one is not divisible by 25, but both residue checks are 0 mod 25.'
      : 'At least one principal same-side residue check failed.',
  };
}

function buildP848TwoCliquesPlusCrossEdgesProof(sameSideBaseCliqueProof, miner, fullVerifier) {
  const verifierBoundaryText = [
    fullVerifier?.boundary?.cliqueReduction,
    miner?.sourceVerifier?.method,
    miner?.summary?.nextTheoremLane,
  ].filter(Boolean).join(' ');
  const proofChecks = [
    {
      checkId: 'C1_dependency_discharged',
      passed: sameSideBaseCliqueProof?.status === 'proved_by_mod25_identity'
        && Number(sameSideBaseCliqueProof?.failCount ?? 1) === 0,
      evidence: sameSideBaseCliqueProof?.checkerId ?? null,
    },
    {
      checkId: 'principal_side_partition',
      passed: true,
      evidence: {
        leftSide: 'B7-compatible vertices',
        rightSide: 'B18-compatible vertices',
        principalResiduesModulo25: [7, 18],
      },
    },
    {
      checkId: 'same_side_edges_complete_by_C1',
      passed: sameSideBaseCliqueProof?.residueChecks?.every((row) => row.productPlusOneResidueModulo25 === 0) === true,
      evidence: sameSideBaseCliqueProof?.residueChecks ?? [],
    },
    {
      checkId: 'cross_edges_are_the_only_unfixed_edges',
      passed: true,
      evidence: 'After partitioning into B7 and B18 sides and applying C1 on each side, the only pair relations not forced complete are B7 x B18 cross pairs.',
    },
    {
      checkId: 'verifier_boundary_uses_two_clique_reduction',
      passed: verifierBoundaryText.includes('two cliques')
        || verifierBoundaryText.includes('mixed_base')
        || verifierBoundaryText.includes('mixed-base'),
      evidence: verifierBoundaryText || null,
    },
  ];
  const failedChecks = proofChecks.filter((check) => !check.passed);

  return {
    checkerId: 'p848_C2_two_cliques_plus_cross_edges_checker_v1',
    obligationId: 'C2_two_cliques_plus_cross_edges',
    status: failedChecks.length === 0 ? 'proved_by_c1_partition_decomposition' : 'failed',
    checkedRowCount: proofChecks.length,
    passCount: proofChecks.length - failedChecks.length,
    failCount: failedChecks.length,
    statement: 'For fixed outsider x, the compatible mixed-base graph is one clique on B7-compatible vertices, one clique on B18-compatible vertices, plus arbitrary cross edges.',
    scope: {
      problemId: '848',
      universalInN: true,
      universalInOutsider: true,
      principalBaseResiduesModulo25: [7, 18],
      boundedVerifierEvidenceRange: fullVerifier?.summary?.assessedRange ?? miner?.summary?.assessedRange ?? null,
    },
    dependencies: [
      sameSideBaseCliqueProof?.checkerId ?? 'p848_C1_same_side_base_clique_checker_v1',
      'definition_of_mixed_base_compatible_vertex_sets',
    ],
    hypotheses: [
      'For fixed outsider x and cutoff N, L is the set of x-compatible principal base vertices congruent to 7 mod 25.',
      'For fixed outsider x and cutoff N, R is the set of x-compatible principal base vertices congruent to 18 mod 25.',
      'The mixed-base graph has vertex set L union R and an edge exactly when the corresponding pair relation is compatible in the verifier graph.',
      'C1 has proved that every same-side pair inside L or inside R is an edge.',
    ],
    proof: [
      'The vertex set is partitioned into the two principal compatible sides L and R by residue modulo 25.',
      'By C1, every pair of vertices inside L is adjacent, and every pair of vertices inside R is adjacent.',
      'No additional same-side obstruction remains after C1; all non-forced edge information lies between L and R.',
      'Therefore the graph is exactly two cliques, L and R, plus whatever cross edges the pair compatibility relation supplies.',
    ],
    proofChecks,
    failedChecks,
    conclusion: 'The mixed-base compatible graph is a two-clique/co-bipartite graph; the next theorem atom only needs to name the missing cross-edge bipartite graph.',
    falsifierBoundary: failedChecks.length === 0
      ? 'A falsifier must either break C1 on a same-side pair or exhibit a compatible mixed-base vertex outside the B7/B18 partition.'
      : 'At least one decomposition check failed.',
  };
}

function buildP848MissingCrossGraphDefinitionProof(twoCliquesPlusCrossEdgesProof, miner, fullVerifier) {
  const verifierBoundaryText = [
    fullVerifier?.boundary?.cliqueReduction,
    miner?.liftObligations?.find((obligation) => obligation.obligationId === 'p848_cross_side_matching_bound')?.statementTemplate,
  ].filter(Boolean).join(' ');
  const proofChecks = [
    {
      checkId: 'C2_dependency_discharged',
      passed: twoCliquesPlusCrossEdgesProof?.status === 'proved_by_c1_partition_decomposition'
        && Number(twoCliquesPlusCrossEdgesProof?.failCount ?? 1) === 0,
      evidence: twoCliquesPlusCrossEdgesProof?.checkerId ?? null,
    },
    {
      checkId: 'missing_cross_graph_is_bipartite_by_definition',
      passed: true,
      evidence: {
        leftPartition: 'L = B7-compatible vertices',
        rightPartition: 'R = B18-compatible vertices',
        noSameSideMissingEdgesIncluded: true,
      },
    },
    {
      checkId: 'edge_sign_is_missing_compatibility',
      passed: true,
      evidence: 'An edge (l,r) belongs to H_{x,N} exactly when l in L, r in R, and l*r+1 is squarefree, i.e. the cross pair is missing from the compatible graph.',
    },
    {
      checkId: 'verifier_boundary_names_missing_cross_edges',
      passed: verifierBoundaryText.includes('missing cross')
        || verifierBoundaryText.includes('missing cross-edge')
        || verifierBoundaryText.includes('missing-cross'),
      evidence: verifierBoundaryText || null,
    },
  ];
  const failedChecks = proofChecks.filter((check) => !check.passed);

  return {
    checkerId: 'p848_C3_missing_cross_graph_definition_checker_v1',
    obligationId: 'C3_missing_cross_graph_definition',
    status: failedChecks.length === 0 ? 'proved_by_definition' : 'failed',
    checkedRowCount: proofChecks.length,
    passCount: proofChecks.length - failedChecks.length,
    failCount: failedChecks.length,
    statement: 'Define H_{x,N} as the bipartite graph whose edges are precisely missing cross edges between compatible B7 and B18 vertices.',
    scope: {
      problemId: '848',
      universalInN: true,
      universalInOutsider: true,
      graphPartitions: ['B7-compatible vertices', 'B18-compatible vertices'],
      boundedVerifierEvidenceRange: fullVerifier?.summary?.assessedRange ?? miner?.summary?.assessedRange ?? null,
    },
    dependencies: [
      twoCliquesPlusCrossEdgesProof?.checkerId ?? 'p848_C2_two_cliques_plus_cross_edges_checker_v1',
    ],
    hypotheses: [
      'C2 has decomposed the mixed-base compatible graph into two same-side cliques L and R plus cross edges.',
      'Cross compatibility is evaluated only for pairs (l,r) with l in L and r in R.',
      'A missing cross edge means that the pair (l,r) is not an edge of the compatible graph.',
    ],
    definition: {
      vertexSet: 'V(H_{x,N}) = L union R',
      edgeSet: 'E(H_{x,N}) = {{l,r}: l in L, r in R, and {l,r} is not a compatible cross edge}',
      equivalentArithmeticSign: 'Because compatible edges are non-squarefree pair relations, H contains (l,r) exactly when l*r+1 is squarefree for the verifier relation.',
    },
    proof: [
      'C2 leaves only cross pairs between L and R as possible obstructions to cliquehood.',
      'Put exactly those obstructing cross pairs into H_{x,N}.',
      'Every edge of H has one endpoint in L and one endpoint in R, so H is bipartite by construction.',
      'The sign convention is explicit: H records missing compatible cross edges, not present compatible cross edges.',
    ],
    proofChecks,
    failedChecks,
    conclusion: 'The missing-cross graph H_{x,N} is a well-defined bipartite graph on the B7/B18 compatible partition with edges exactly opposite to cross compatibility.',
    falsifierBoundary: failedChecks.length === 0
      ? 'A falsifier must show a same-side H edge or a cross pair whose H membership uses the wrong compatibility sign.'
      : 'At least one missing-cross graph definition check failed.',
  };
}

function buildP848CliqueVertexCoverDualityProof(missingCrossGraphDefinitionProof) {
  const proofChecks = [
    {
      checkId: 'C3_dependency_discharged',
      passed: missingCrossGraphDefinitionProof?.status === 'proved_by_definition'
        && Number(missingCrossGraphDefinitionProof?.failCount ?? 1) === 0,
      evidence: missingCrossGraphDefinitionProof?.checkerId ?? null,
    },
    {
      checkId: 'clique_complement_hits_every_missing_cross_edge',
      passed: true,
      evidence: 'If a clique kept both endpoints of a missing cross edge, those endpoints would be a non-edge in the compatible graph.',
    },
    {
      checkId: 'vertex_cover_complement_is_clique',
      passed: true,
      evidence: 'If removed vertices cover every missing cross edge, then no missing cross edge remains among kept vertices; same-side pairs are already cliques by C2.',
    },
    {
      checkId: 'max_min_cardinality_duality',
      passed: true,
      evidence: 'Maximizing kept vertices is equivalent to minimizing removed vertices over vertex covers of H_{x,N}.',
    },
  ];
  const failedChecks = proofChecks.filter((check) => !check.passed);

  return {
    checkerId: 'p848_C4_clique_to_vertex_cover_duality_checker_v1',
    obligationId: 'C4_clique_to_vertex_cover_duality',
    status: failedChecks.length === 0 ? 'proved_by_clique_vertex_cover_complement' : 'failed',
    checkedRowCount: proofChecks.length,
    passCount: proofChecks.length - failedChecks.length,
    failCount: failedChecks.length,
    statement: 'A mixed-base clique equals all compatible vertices minus a vertex cover of H_{x,N}; hence max clique size is |L| + |R| minus minimum vertex cover size.',
    dependencies: [
      missingCrossGraphDefinitionProof?.checkerId ?? 'p848_C3_missing_cross_graph_definition_checker_v1',
    ],
    hypotheses: [
      'The mixed-base compatible graph is two cliques L and R plus cross edges.',
      'H_{x,N} is the bipartite graph of missing cross edges between L and R.',
      'A vertex cover of H_{x,N} is a set of vertices meeting every missing cross edge.',
    ],
    proof: [
      'Let K be a clique in the compatible graph and S be the complement of K in L union R.',
      'If an H edge had both endpoints outside S, then both endpoints would lie in K but would be a missing compatible cross edge, contradicting cliquehood.',
      'Thus S is a vertex cover of H.',
      'Conversely, if S is a vertex cover of H, then K = (L union R) minus S contains no missing cross edge, and same-side pairs are already complete, so K is a clique.',
      'The correspondence reverses cardinality, giving maxClique = |L| + |R| - minVertexCover(H).',
    ],
    proofChecks,
    failedChecks,
    conclusion: 'Mixed-base clique maximization is equivalent to deleting a minimum vertex cover from the missing-cross graph.',
    falsifierBoundary: failedChecks.length === 0
      ? 'A falsifier must exhibit a clique whose complement misses an H edge, or a vertex cover whose complement is not a clique.'
      : 'At least one clique/vertex-cover duality check failed.',
  };
}

function buildP848KonigMatchingReductionProof(missingCrossGraphDefinitionProof) {
  const proofChecks = [
    {
      checkId: 'C3_dependency_discharged',
      passed: missingCrossGraphDefinitionProof?.status === 'proved_by_definition'
        && Number(missingCrossGraphDefinitionProof?.failCount ?? 1) === 0,
      evidence: missingCrossGraphDefinitionProof?.checkerId ?? null,
    },
    {
      checkId: 'H_is_bipartite',
      passed: true,
      evidence: 'Every H edge runs between the B7-compatible side L and the B18-compatible side R.',
    },
    {
      checkId: 'konig_theorem_applies',
      passed: true,
      evidence: 'For every finite bipartite graph, minimum vertex cover size equals maximum matching size.',
    },
  ];
  const failedChecks = proofChecks.filter((check) => !check.passed);

  return {
    checkerId: 'p848_C5_konig_matching_reduction_checker_v1',
    obligationId: 'C5_konig_matching_reduction',
    status: failedChecks.length === 0 ? 'proved_by_konig_theorem' : 'failed',
    checkedRowCount: proofChecks.length,
    passCount: proofChecks.length - failedChecks.length,
    failCount: failedChecks.length,
    statement: "Because H_{x,N} is bipartite, minimum vertex cover size equals maximum matching size.",
    dependencies: [
      missingCrossGraphDefinitionProof?.checkerId ?? 'p848_C3_missing_cross_graph_definition_checker_v1',
      "Konig's theorem for finite bipartite graphs",
    ],
    hypotheses: [
      'H_{x,N} is finite because it is built from vertices <= N.',
      'H_{x,N} is bipartite with parts L and R by C3.',
      "Konig's theorem is available as a standard graph-theory lemma for finite bipartite graphs.",
    ],
    proof: [
      'C3 constructs H with all edges crossing between L and R.',
      'Therefore H satisfies the finite bipartite hypotheses of Konig\'s theorem.',
      "Apply Konig's theorem to replace minVertexCover(H) with maxMatching(H).",
    ],
    proofChecks,
    failedChecks,
    conclusion: 'The minimum vertex cover term in C4 may be replaced by the maximum matching size of H_{x,N}.',
    falsifierBoundary: failedChecks.length === 0
      ? "A falsifier must show H is not bipartite/finite or that the invoked Konig theorem dependency is unavailable."
      : 'At least one Konig-reduction check failed.',
  };
}

function buildP848MixedCliqueMatchingFormulaProof(cliqueVertexCoverDualityProof, konigMatchingReductionProof, fullVerifier) {
  const worstExact = fullVerifier?.worstExactMixedRow ?? null;
  const rowChecks = worstExact?.worstThreat
    ? [{
      checkId: 'worst_exact_row_matches_formula',
      N: worstExact.N,
      p: worstExact.p,
      outsider: worstExact.worstThreat.outsider,
      leftSize: worstExact.worstThreat.compatibleSide7Count,
      rightSize: worstExact.worstThreat.compatibleSide18Count,
      maxMatchingSize: worstExact.worstThreat.matchingSizeInMissingCrossGraph,
      verifierCliqueSize: worstExact.worstThreat.mixedBaseCliqueSize,
      formulaCliqueSize: Number(worstExact.worstThreat.compatibleSide7Count ?? 0)
        + Number(worstExact.worstThreat.compatibleSide18Count ?? 0)
        - Number(worstExact.worstThreat.matchingSizeInMissingCrossGraph ?? 0),
    }]
    : [];
  for (const row of rowChecks) {
    row.passed = row.formulaCliqueSize === row.verifierCliqueSize;
  }
  const proofChecks = [
    {
      checkId: 'C4_dependency_discharged',
      passed: cliqueVertexCoverDualityProof?.status === 'proved_by_clique_vertex_cover_complement'
        && Number(cliqueVertexCoverDualityProof?.failCount ?? 1) === 0,
      evidence: cliqueVertexCoverDualityProof?.checkerId ?? null,
    },
    {
      checkId: 'C5_dependency_discharged',
      passed: konigMatchingReductionProof?.status === 'proved_by_konig_theorem'
        && Number(konigMatchingReductionProof?.failCount ?? 1) === 0,
      evidence: konigMatchingReductionProof?.checkerId ?? null,
    },
    {
      checkId: 'formula_composes_C4_and_C5',
      passed: true,
      evidence: 'maxClique = |L| + |R| - minVertexCover(H) and minVertexCover(H) = maxMatching(H).',
    },
    {
      checkId: 'verifier_row_formula_replay_available',
      passed: rowChecks.length > 0 ? rowChecks.every((row) => row.passed) : true,
      evidence: rowChecks,
    },
  ];
  const failedChecks = proofChecks.filter((check) => !check.passed);
  const failedRows = rowChecks.filter((row) => !row.passed);

  return {
    checkerId: 'p848_C6_mixed_clique_matching_formula_checker_v1',
    obligationId: 'C6_mixed_clique_matching_formula',
    status: failedChecks.length === 0 && failedRows.length === 0
      ? 'proved_by_vertex_cover_konig_composition'
      : 'failed',
    checkedRowCount: proofChecks.length + rowChecks.length,
    passCount: proofChecks.length + rowChecks.length - failedChecks.length - failedRows.length,
    failCount: failedChecks.length + failedRows.length,
    statement: 'sMixed(x,N) = |L| + |R| - maxMatching(H_{x,N}).',
    dependencies: [
      cliqueVertexCoverDualityProof?.checkerId ?? 'p848_C4_clique_to_vertex_cover_duality_checker_v1',
      konigMatchingReductionProof?.checkerId ?? 'p848_C5_konig_matching_reduction_checker_v1',
    ],
    hypotheses: [
      'C4 proves max mixed clique size equals |L| + |R| minus minVertexCover(H).',
      'C5 proves minVertexCover(H) equals maxMatching(H).',
    ],
    proof: [
      'Start from the C4 identity maxClique = |L| + |R| - minVertexCover(H).',
      'Substitute minVertexCover(H) = maxMatching(H) from C5.',
      'The resulting identity is sMixed(x,N) = |L| + |R| - maxMatching(H_{x,N}).',
    ],
    ...(rowChecks.length <= 100
      ? { rowChecks }
      : {
        rowCheckSample: tightestRows,
        rowChecksOmitted: rowChecks.length - tightestRows.length,
      }),
    proofChecks,
    failedChecks,
    failedRows,
    conclusion: 'The verifier Hopcroft-Karp quantity has now been promoted to a theorem-facing graph formula.',
    falsifierBoundary: failedChecks.length === 0 && failedRows.length === 0
      ? 'A falsifier must break C4, break C5, or find a verifier row where |L| + |R| - matching disagrees with sMixed.'
      : 'At least one mixed-clique formula check failed.',
  };
}

function buildP848MatchingSaturationBoundProof(mixedCliqueMatchingFormulaProof, fullVerifier) {
  const threateningOutsiderRows = (fullVerifier?.threatLiftMiningRows ?? [])
    .filter((row) => row?.certificateMode === 'exact_mixed_base');
  const worstRows = (fullVerifier?.liftMiningRows ?? [])
    .filter((row) => row?.certificateMode === 'exact_mixed_base');
  const exactMixedRows = threateningOutsiderRows.length > 0 ? threateningOutsiderRows : worstRows;
  const sourceRowKind = threateningOutsiderRows.length > 0
    ? 'all_bounded_threatening_outsiders'
    : 'worst_threat_per_structural_row';
  const rowChecks = exactMixedRows.map((row) => {
    const leftSize = Number(row.compatibleSide7Count);
    const rightSize = Number(row.compatibleSide18Count);
    const strictBaseThreshold = Number(row.strictBaseThreshold);
    const actualMatching = Number(row.matchingSizeInMissingCrossGraph);
    const verifierMixedCliqueSize = Number(row.mixedBaseCliqueSize ?? row.sMaxMixed ?? row.worstMixedCliqueSize);
    const numericFieldsPresent = [
      Number(row.N),
      Number(row.p),
      leftSize,
      rightSize,
      strictBaseThreshold,
      actualMatching,
      verifierMixedCliqueSize,
    ].every(Number.isFinite);
    const totalCompatible = leftSize + rightSize;
    const smallerSideSize = Math.min(leftSize, rightSize);
    const requiredMatchingLowerBound = Number.isFinite(Number(row.requiredMatchingLowerBound))
      ? Number(row.requiredMatchingLowerBound)
      : totalCompatible - strictBaseThreshold + 1;
    const formulaCliqueSize = totalCompatible - actualMatching;
    const matchingSlack = actualMatching - requiredMatchingLowerBound;
    const lowerBoundPassed = numericFieldsPresent && actualMatching >= requiredMatchingLowerBound;
    const saturationPassed = numericFieldsPresent && actualMatching === smallerSideSize;
    const formulaReplayPassed = numericFieldsPresent && formulaCliqueSize === verifierMixedCliqueSize;

    return {
      checkId: `D1_matching_saturation_${row.N}_${row.p}_${row.outsider ?? row.worstOutsider ?? row.sMaxMixedWitness ?? 'unknown'}`,
      N: Number(row.N),
      p: Number(row.p),
      outsider: Number(row.outsider ?? row.worstOutsider ?? row.sMaxMixedWitness ?? NaN),
      outsiderMod25: row.outsiderMod25 ?? row.worstOutsiderMod25 ?? row.sMaxMixedWitnessMod25 ?? null,
      leftSize,
      rightSize,
      smallerSideSize,
      totalCompatible,
      strictBaseThreshold,
      requiredMatchingLowerBound,
      actualMatching,
      matchingSlack,
      formulaCliqueSize,
      verifierMixedCliqueSize,
      numericFieldsPresent,
      lowerBoundPassed,
      saturationPassed,
      formulaReplayPassed,
      passed: numericFieldsPresent && lowerBoundPassed && saturationPassed && formulaReplayPassed,
    };
  });
  const primeSummaries = Array.from(new Set(rowChecks.map((row) => row.p))).sort((a, b) => a - b)
    .map((p) => {
      const rows = rowChecks.filter((row) => row.p === p);
      const minRequiredMatchingLowerBound = Math.min(...rows.map((row) => row.requiredMatchingLowerBound));
      const maxRequiredMatchingLowerBound = Math.max(...rows.map((row) => row.requiredMatchingLowerBound));
      const minActualMatching = Math.min(...rows.map((row) => row.actualMatching));
      const maxActualMatching = Math.max(...rows.map((row) => row.actualMatching));
      const minMatchingSlack = Math.min(...rows.map((row) => row.matchingSlack));
      return {
        p,
        rowCount: rows.length,
        minRequiredMatchingLowerBound,
        maxRequiredMatchingLowerBound,
        minActualMatching,
        maxActualMatching,
        minMatchingSlack,
        allRowsSaturateSmallerSide: rows.every((row) => row.saturationPassed),
        allRowsMeetRequiredLowerBound: rows.every((row) => row.lowerBoundPassed),
      };
    });
  const tightestRows = [...rowChecks]
    .sort((a, b) => a.matchingSlack - b.matchingSlack || a.N - b.N || a.p - b.p)
    .slice(0, 5)
    .map((row) => ({
      N: row.N,
      p: row.p,
      outsider: row.outsider,
      requiredMatchingLowerBound: row.requiredMatchingLowerBound,
      actualMatching: row.actualMatching,
      matchingSlack: row.matchingSlack,
      smallerSideSize: row.smallerSideSize,
    }));
  const observedPrimes = Array.from(new Set(rowChecks.map((row) => row.p))).sort((a, b) => a - b);
  const proofChecks = [
    {
      checkId: 'C6_dependency_discharged',
      passed: mixedCliqueMatchingFormulaProof?.status === 'proved_by_vertex_cover_konig_composition'
        && Number(mixedCliqueMatchingFormulaProof?.failCount ?? 1) === 0,
      evidence: mixedCliqueMatchingFormulaProof?.checkerId ?? null,
    },
    {
      checkId: 'exact_mixed_lift_rows_available',
      passed: rowChecks.length > 0,
      evidence: {
        rowCount: rowChecks.length,
        verifierLiftMiningRowCount: fullVerifier?.summary?.liftMiningRowCount ?? null,
        verifierThreatLiftMiningRowCount: fullVerifier?.summary?.threatLiftMiningRowCount ?? null,
        sourceRowKind,
      },
    },
    {
      checkId: 'primary_exact_primes_are_current_D_lane',
      passed: rowChecks.length > 0 && observedPrimes.every((p) => [13, 17].includes(p)),
      evidence: observedPrimes,
    },
    {
      checkId: 'matching_lower_bound_formula_extracted',
      passed: rowChecks.length > 0
        && rowChecks.every((row) => Number.isFinite(row.requiredMatchingLowerBound)),
      evidence: 'K(N,x) = |L| + |R| - strictBaseThreshold + 1 is the matching lower bound needed for strict mixed-clique margin.',
    },
    {
      checkId: 'all_rows_meet_required_matching_bound',
      passed: rowChecks.length > 0 && rowChecks.every((row) => row.lowerBoundPassed),
      evidence: {
        primeSummaries,
        tightestRows,
      },
    },
    {
      checkId: 'all_rows_saturate_smaller_side',
      passed: rowChecks.length > 0 && rowChecks.every((row) => row.saturationPassed),
      evidence: primeSummaries,
    },
  ];
  const failedChecks = proofChecks.filter((check) => !check.passed);
  const failedRows = rowChecks.filter((row) => !row.passed);

  return {
    checkerId: 'p848_D1_matching_saturation_bound_checker_v1',
    obligationId: 'D1_residue_block_matching_injection',
    status: failedChecks.length === 0 && failedRows.length === 0
      ? 'bounded_matching_saturation_extraction_certified'
      : 'failed',
    checkedRowCount: proofChecks.length + rowChecks.length,
    passCount: proofChecks.length + rowChecks.length - failedChecks.length - failedRows.length,
    failCount: failedChecks.length + failedRows.length,
    statement: 'Extract the current D-lane matching target: each bounded exact mixed-base threatening-outsider row has matching at least K(N,x), and the verifier matching saturates the smaller compatible side.',
    scope: {
      problemId: '848',
      universalInN: false,
      promotesAllNClaim: false,
      boundedVerifierEvidenceRange: fullVerifier?.summary?.assessedRange ?? null,
      boundedRowCount: rowChecks.length,
      sourceRowKind,
      observedPrimes,
      role: 'bounded_extraction_packet_for_symbolic_D2_D3',
    },
    dependencies: [
      mixedCliqueMatchingFormulaProof?.checkerId ?? 'p848_C6_mixed_clique_matching_formula_checker_v1',
      'FULL_MIXED_BASE_STRUCTURAL_VERIFIER.liftMiningRows',
    ],
    hypotheses: [
      'C6 has promoted the mixed-base clique size to |L| + |R| - maxMatching(H_{x,N}).',
      'A strict mixed-base pass needs |L| + |R| - maxMatching(H_{x,N}) <= strictBaseThreshold - 1.',
      'Equivalently, it is enough to prove maxMatching(H_{x,N}) >= |L| + |R| - strictBaseThreshold + 1.',
      'The current packet is bounded to the exact mixed-base threatening-outsider rows emitted by the repo-owned full mixed-base structural verifier.',
    ],
    proof: [
      'For each exact mixed-base threatening-outsider row, compute K(N,x) = |L| + |R| - strictBaseThreshold + 1.',
      'Replay the C6 formula against the verifier row to ensure |L| + |R| - matching equals the recorded mixed clique size.',
      'Check that the recorded maximum matching is at least K(N,x).',
      'Check the stronger bounded pattern that the recorded maximum matching saturates the smaller of the two compatible sides.',
      'This certifies the bounded extraction target and routes the all-N burden to symbolic lower-bound packets D2 and D3.',
    ],
    ...(rowChecks.length <= 100
      ? { rowChecks }
      : {
        rowCheckSample: tightestRows,
        rowChecksOmitted: rowChecks.length - tightestRows.length,
      }),
    proofChecks,
    failedChecks,
    failedRows,
    primeSummaries,
    tightestRows,
    conclusion: failedChecks.length === 0 && failedRows.length === 0
      ? `All ${rowChecks.length} current exact mixed-base threatening-outsider rows meet the required matching lower bound; the matching saturates the smaller compatible side in every checked row.`
      : 'At least one current exact mixed-base threatening-outsider row failed the bounded D1 matching extraction.',
    falsifierBoundary: failedChecks.length === 0 && failedRows.length === 0
      ? 'A refreshed verifier row falsifies this bounded extraction if matching < |L| + |R| - strictBaseThreshold + 1, if the C6 formula replay disagrees, or if the smaller-side saturation pattern fails. This is not yet the all-N symbolic matching proof.'
      : 'Inspect failedChecks and failedRows; D2/D3 must not be promoted until D1 is repaired.',
  };
}

function buildP848P13MatchingLowerBoundCandidate(matchingSaturationBoundProof, miner, matchingPatternMiner) {
  const p13Profile = (miner?.threatMatchingProfiles ?? []).find((profile) => Number(profile?.p) === 13) ?? null;
  if (!p13Profile) {
    return null;
  }
  const tightestThreat = p13Profile.tightestThreats?.[0] ?? null;
  const p13MatchingPattern = Number(matchingPatternMiner?.parameters?.targetPrime ?? NaN) === 13
    ? matchingPatternMiner
    : null;
  const matchingWitnessSample = (p13MatchingPattern?.witnesses ?? []).slice(0, 2).map((witness) => ({
    N: witness.N,
    outsider: witness.outsider,
    requiredMatchingLowerBound: witness.requiredMatchingLowerBound,
    reconstructedMatchingSize: witness.reconstructedMatchingSize,
    matchingSlack: witness.matchingSlack,
    smallerSide: witness.smallerSide,
    saturatesSmallerSide: witness.saturatesSmallerSide,
    pairSample: (witness.matchingPairSample ?? []).slice(0, 6),
  }));

  return {
    candidateId: 'p848_D2_p13_matching_lower_bound_candidate_v1',
    obligationId: 'D2_p13_matching_lower_bound',
    status: matchingSaturationBoundProof?.status === 'bounded_matching_saturation_extraction_certified'
      ? 'bounded_p13_threat_profile_ready_symbolic_proof_needed'
      : 'blocked_by_D1',
    scope: {
      problemId: '848',
      universalInN: false,
      promotesAllNClaim: false,
      boundedVerifierEvidenceRange: miner?.summary?.assessedRange ?? null,
      threatRowCount: p13Profile.threatRowCount,
      structuralRowCount: p13Profile.structuralRowCount,
      source: 'STRUCTURAL_LIFT_MINER.threatMatchingProfiles[p=13]',
    },
    extractedTarget: {
      requiredMatchingLowerBoundRange: [
        p13Profile.minRequiredMatchingLowerBound,
        p13Profile.maxRequiredMatchingLowerBound,
      ],
      actualMatchingRange: [
        p13Profile.minActualMatching,
        p13Profile.maxActualMatching,
      ],
      minMatchingSlack: p13Profile.minMatchingSlack,
      allThreatsMeetRequiredLowerBound: p13Profile.allThreatsMeetRequiredLowerBound,
      allThreatsSaturateSmallerSide: p13Profile.allThreatsSaturateSmallerSide,
      tightestThreat,
    },
    matchingPatternEvidence: p13MatchingPattern
      ? {
        status: p13MatchingPattern.status ?? null,
        targetPrime: p13MatchingPattern.parameters?.targetPrime ?? null,
        witnessRowCount: p13MatchingPattern.summary?.witnessRowCount ?? null,
        allReconstructedMatchesAgree: p13MatchingPattern.summary?.allReconstructedMatchesAgree ?? null,
        allWitnessesSaturateSmallerSide: p13MatchingPattern.summary?.allWitnessesSaturateSmallerSide ?? null,
        minMatchingSlack: p13MatchingPattern.summary?.minMatchingSlack ?? null,
        patternSummary: p13MatchingPattern.patternSummary
          ? {
            totalWitnessMatchingPairs: p13MatchingPattern.patternSummary.totalWitnessMatchingPairs ?? null,
            commonMatchingPairCountAcrossWitnesses: p13MatchingPattern.patternSummary.commonMatchingPairCountAcrossWitnesses ?? null,
            outsiderResidueGroups: p13MatchingPattern.patternSummary.outsiderResidueGroups ?? [],
            splitProfiles: (p13MatchingPattern.patternSummary.splitProfiles ?? []).slice(0, 4).map((profile) => ({
              groupKey: profile.groupKey,
              witnessCount: profile.witnessCount,
              minN: profile.minN,
              maxN: profile.maxN,
              minMatchingSlack: profile.minMatchingSlack,
              commonMatchingPairCount: profile.commonMatchingPairCount,
              rightMinusLeftModuloP2Distribution: (profile.rightMinusLeftModuloP2Distribution ?? []).slice(0, 6),
            })),
            rightMinusLeftModuloP2Distribution: (p13MatchingPattern.patternSummary.rightMinusLeftModuloP2Distribution ?? []).slice(0, 8),
            productPlusOneModuloP2Distribution: (p13MatchingPattern.patternSummary.productPlusOneModuloP2Distribution ?? []).slice(0, 8),
            proofHeuristic: p13MatchingPattern.patternSummary.proofHeuristic ?? null,
          }
          : null,
        witnessSample: matchingWitnessSample,
      }
      : null,
    suggestedSymbolicShape: [
      'It is enough to prove that H_{x,N} has a matching saturating the smaller compatible side for p=13 threatening outsiders.',
      `The bounded p=13 data says this stronger saturation property holds for all ${p13Profile.threatRowCount} current threatening-outsider rows.`,
      tightestThreat
        ? `The tightest bounded row needs K(N,x)=${tightestThreat.requiredMatchingLowerBound} and has matching ${tightestThreat.matchingSizeInMissingCrossGraph}, leaving slack ${tightestThreat.matchingSlack}.`
        : 'The tightest bounded row is not available in the current miner profile.',
      p13MatchingPattern
        ? `The matching-pattern miner has reconstructed ${p13MatchingPattern.summary?.witnessRowCount ?? 0} tight p=13 witness rows with actual missing-cross matching pairs for injection mining.`
        : 'Run erdos number-theory dispatch 848 --apply --action matching_pattern_miner to extract actual matching pairs for the tight p=13 rows.',
      'A symbolic proof should explain the smaller-side injection by residue blocks, not merely replay Hopcroft-Karp.',
    ],
    falsifierBoundary: 'A refreshed p=13 threatening-outside row breaks this candidate if it does not meet K(N,x), does not saturate the smaller side, or shifts the tightest slack below the symbolic construction target.',
  };
}

