function buildP848P13SplitCoreWitnessProof(matchingSaturationBoundProof, p13MatchingLowerBoundCandidate, matchingPatternMiner) {
  const isP13Pattern = Number(matchingPatternMiner?.parameters?.targetPrime ?? NaN) === 13;
  if (!isP13Pattern || !matchingPatternMiner) {
    return null;
  }
  const patternSummary = isP13Pattern ? matchingPatternMiner?.patternSummary ?? null : null;
  const splitProfiles = Array.isArray(patternSummary?.splitProfiles) ? patternSummary.splitProfiles : [];
  const profileChecks = splitProfiles.map((profile) => {
    const commonMatchingPairCount = Number(profile.commonMatchingPairCount);
    const commonMatchingPairs = Array.isArray(profile.commonMatchingPairs) ? profile.commonMatchingPairs : [];
    const maxRequiredMatchingLowerBound = Number(profile.maxRequiredMatchingLowerBound);
    const minSmallerSideSize = Number(profile.minSmallerSideSize);
    const witnessCount = Number(profile.witnessCount);
    const numericFieldsPresent = [
      commonMatchingPairCount,
      maxRequiredMatchingLowerBound,
      minSmallerSideSize,
      witnessCount,
    ].every(Number.isFinite);
    return {
      checkId: `D2_split_core_${String(profile.groupKey ?? 'unknown').replaceAll(/[^A-Za-z0-9_=-]/g, '_')}`,
      groupKey: profile.groupKey ?? null,
      witnessCount,
      minN: profile.minN ?? null,
      maxN: profile.maxN ?? null,
      minRequiredMatchingLowerBound: profile.minRequiredMatchingLowerBound ?? null,
      maxRequiredMatchingLowerBound,
      minReconstructedMatchingSize: profile.minReconstructedMatchingSize ?? null,
      maxReconstructedMatchingSize: profile.maxReconstructedMatchingSize ?? null,
      minSmallerSideSize,
      maxSmallerSideSize: profile.maxSmallerSideSize ?? null,
      minMatchingSlack: profile.minMatchingSlack ?? null,
      commonMatchingPairCount,
      commonMatchingPairs,
      commonMatchingPairExportComplete: Number.isFinite(commonMatchingPairCount)
        && commonMatchingPairs.length === commonMatchingPairCount,
      numericFieldsPresent,
      commonCoreMeetsMaxRequiredBound: numericFieldsPresent
        && commonMatchingPairCount >= maxRequiredMatchingLowerBound,
      commonCoreSaturatesMinSmallerSide: numericFieldsPresent
        && commonMatchingPairCount >= minSmallerSideSize,
      rightMinusLeftModuloP2Distribution: (profile.rightMinusLeftModuloP2Distribution ?? []).slice(0, 8),
    };
  });
  const proofChecks = [
    {
      checkId: 'D1_dependency_discharged',
      passed: matchingSaturationBoundProof?.status === 'bounded_matching_saturation_extraction_certified'
        && Number(matchingSaturationBoundProof?.failCount ?? 1) === 0,
      evidence: matchingSaturationBoundProof?.checkerId ?? null,
    },
    {
      checkId: 'p13_candidate_ready',
      passed: p13MatchingLowerBoundCandidate?.status === 'bounded_p13_threat_profile_ready_symbolic_proof_needed',
      evidence: p13MatchingLowerBoundCandidate?.candidateId ?? null,
    },
    {
      checkId: 'matching_pattern_artifact_ready',
      passed: isP13Pattern && matchingPatternMiner?.status === 'matching_pattern_witness_packet_ready',
      evidence: {
        status: matchingPatternMiner?.status ?? null,
        targetPrime: matchingPatternMiner?.parameters?.targetPrime ?? null,
        witnessRowCount: matchingPatternMiner?.summary?.witnessRowCount ?? null,
      },
    },
    {
      checkId: 'matching_reconstruction_agrees_with_verifier',
      passed: matchingPatternMiner?.summary?.allReconstructedMatchesAgree === true,
      evidence: matchingPatternMiner?.summary?.allReconstructedMatchesAgree ?? null,
    },
    {
      checkId: 'all_witnesses_saturate_smaller_side',
      passed: matchingPatternMiner?.summary?.allWitnessesSaturateSmallerSide === true,
      evidence: matchingPatternMiner?.summary?.saturatedSideDistribution ?? null,
    },
    {
      checkId: 'split_profiles_available',
      passed: profileChecks.length > 0,
      evidence: {
        splitProfileCount: profileChecks.length,
        commonAcrossAllProfiles: patternSummary?.commonMatchingPairCountAcrossWitnesses ?? null,
        proofHeuristic: patternSummary?.proofHeuristic ?? null,
      },
    },
    {
      checkId: 'split_common_cores_meet_required_K',
      passed: profileChecks.length > 0 && profileChecks.every((profile) => profile.commonCoreMeetsMaxRequiredBound),
      evidence: profileChecks.map((profile) => ({
        groupKey: profile.groupKey,
        commonMatchingPairCount: profile.commonMatchingPairCount,
        maxRequiredMatchingLowerBound: profile.maxRequiredMatchingLowerBound,
      })),
    },
    {
      checkId: 'split_common_core_pairs_exported',
      passed: profileChecks.length > 0 && profileChecks.every((profile) => profile.commonMatchingPairExportComplete),
      evidence: profileChecks.map((profile) => ({
        groupKey: profile.groupKey,
        commonMatchingPairCount: profile.commonMatchingPairCount,
        exportedPairCount: profile.commonMatchingPairs.length,
      })),
    },
    {
      checkId: 'split_common_cores_saturate_smaller_side_on_tight_rows',
      passed: profileChecks.length > 0 && profileChecks.every((profile) => profile.commonCoreSaturatesMinSmallerSide),
      evidence: profileChecks.map((profile) => ({
        groupKey: profile.groupKey,
        commonMatchingPairCount: profile.commonMatchingPairCount,
        minSmallerSideSize: profile.minSmallerSideSize,
      })),
    },
  ];
  const failedChecks = proofChecks.filter((check) => !check.passed);
  const failedProfiles = profileChecks.filter((profile) => (
    !profile.commonCoreMeetsMaxRequiredBound
    || !profile.commonCoreSaturatesMinSmallerSide
  ));
  const profileSummary = profileChecks.map((profile) => ({
    groupKey: profile.groupKey,
    witnessCount: profile.witnessCount,
    nRange: `${profile.minN}..${profile.maxN}`,
    requiredMatchingLowerBoundRange: [
      profile.minRequiredMatchingLowerBound,
      profile.maxRequiredMatchingLowerBound,
    ],
    reconstructedMatchingRange: [
      profile.minReconstructedMatchingSize,
      profile.maxReconstructedMatchingSize,
    ],
    commonMatchingPairCount: profile.commonMatchingPairCount,
    commonMatchingPairExportComplete: profile.commonMatchingPairExportComplete,
    commonMatchingPairs: profile.commonMatchingPairs,
    minMatchingSlack: profile.minMatchingSlack,
    commonCoreMeetsMaxRequiredBound: profile.commonCoreMeetsMaxRequiredBound,
    commonCoreSaturatesMinSmallerSide: profile.commonCoreSaturatesMinSmallerSide,
  }));

  return {
    checkerId: 'p848_D2_p13_split_core_witness_checker_v1',
    obligationId: 'D2_p13_split_core_witness_extraction',
    parentObligationId: 'D2_p13_matching_lower_bound',
    status: failedChecks.length === 0 && failedProfiles.length === 0
      ? 'bounded_split_core_witness_certified'
      : 'failed',
    checkedRowCount: proofChecks.length + profileChecks.length,
    passCount: proofChecks.length + profileChecks.length - failedChecks.length - failedProfiles.length,
    failCount: failedChecks.length + failedProfiles.length,
    statement: 'The tight p=13 matching-pattern witnesses split into residue/saturated-side profiles whose common matching cores already meet the required K(N,x) lower bound.',
    scope: {
      problemId: '848',
      universalInN: false,
      promotesAllNClaim: false,
      targetPrime: 13,
      sourceArtifact: 'MATCHING_PATTERN_MINER.json',
      sourceAssessedRange: matchingPatternMiner?.parameters?.sourceAssessedRange ?? null,
      witnessRowCount: matchingPatternMiner?.summary?.witnessRowCount ?? null,
      splitProfileCount: profileChecks.length,
      role: 'bounded_split_core_witness_for_symbolic_D2_lift',
    },
    dependencies: [
      matchingSaturationBoundProof?.checkerId ?? 'p848_D1_matching_saturation_bound_checker_v1',
      p13MatchingLowerBoundCandidate?.candidateId ?? 'p848_D2_p13_matching_lower_bound_candidate_v1',
      'MATCHING_PATTERN_MINER.patternSummary.splitProfiles',
    ],
    hypotheses: [
      'D1 has extracted the p=13 matching lower-bound target K(N,x).',
      'The matching-pattern miner reconstructs Hopcroft-Karp matchings as explicit missing-cross matching pairs for tight p=13 rows.',
      'The sampled tight rows split by outsider residue modulo 13^2, outsider residue modulo 25, and which side is smaller.',
      'Within each split profile, the common matching core is a matching present in every sampled row of that profile.',
    ],
    proof: [
      'Read the p=13 split profiles from MATCHING_PATTERN_MINER.patternSummary.',
      'For each split profile, compare the common matching-pair count with the largest required K(N,x) among sampled rows in that profile.',
      'Check the stronger saturation witness: the common core also reaches the minimum smaller-side size observed in that profile.',
      'Because every sampled row in the split profile contains the common core, that core gives a bounded matching lower-bound witness for the sampled tight rows.',
      'This does not discharge D2 universally; it turns D2 into explicit split symbolic subgoals whose common cores must be proved to persist by residue/block argument.',
    ],
    proofChecks,
    failedChecks,
    profileChecks,
    failedProfiles,
    profileSummary,
    symbolicSubgoals: profileSummary.map((profile, index) => ({
      subgoalId: `D2.${index + 1}_persist_${String(profile.groupKey).replaceAll(/[^A-Za-z0-9_=-]/g, '_')}`,
      groupKey: profile.groupKey,
      goal: `Prove that the ${profile.commonMatchingPairCount}-edge common matching core persists for all p=13 threatening rows in split ${profile.groupKey}, or replace it with a parameterized extension core.`,
      boundedTarget: {
        requiredMatchingLowerBoundRange: profile.requiredMatchingLowerBoundRange,
        commonMatchingPairCount: profile.commonMatchingPairCount,
        commonMatchingPairExportComplete: profile.commonMatchingPairExportComplete,
        commonMatchingPairs: profile.commonMatchingPairs,
        minMatchingSlack: profile.minMatchingSlack,
      },
      falsifierBoundary: 'A row in this split loses one of the common-core missing-cross edges before a replacement edge is proved, or its K(N,x) exceeds the symbolic core size.',
    })),
    conclusion: failedChecks.length === 0 && failedProfiles.length === 0
      ? `The tight p=13 sample is reduced to ${profileChecks.length} split-core subgoals; every split common core meets the sampled maximum K(N,x) and saturates the sampled smaller side.`
      : 'At least one p=13 split core failed to meet the sampled K(N,x) target.',
    falsifierBoundary: failedChecks.length === 0 && failedProfiles.length === 0
      ? 'A refreshed matching-pattern miner falsifies this bounded witness packet if a split profile has no common core, if the common core falls below max K(N,x), or if the split heuristic changes. D2 remains open until these split cores are proved symbolically.'
      : 'Inspect failedChecks and failedProfiles before using this as a D2 symbolic-lift guide.',
  };
}

function buildP848P17SplitCoreWitnessProof(matchingSaturationBoundProof, p17MatchingLowerBoundCandidate, matchingPatternMiner) {
  const isP17Pattern = Number(matchingPatternMiner?.parameters?.targetPrime ?? NaN) === 17;
  if (!isP17Pattern || !matchingPatternMiner) {
    return null;
  }
  const patternSummary = matchingPatternMiner?.patternSummary ?? null;
  const splitProfiles = Array.isArray(patternSummary?.splitProfiles) ? patternSummary.splitProfiles : [];
  const profileChecks = splitProfiles.map((profile) => {
    const commonMatchingPairCount = Number(profile.commonMatchingPairCount);
    const commonMatchingPairs = Array.isArray(profile.commonMatchingPairs) ? profile.commonMatchingPairs : [];
    const maxRequiredMatchingLowerBound = Number(profile.maxRequiredMatchingLowerBound);
    const minSmallerSideSize = Number(profile.minSmallerSideSize);
    const witnessCount = Number(profile.witnessCount);
    const numericFieldsPresent = [
      commonMatchingPairCount,
      maxRequiredMatchingLowerBound,
      minSmallerSideSize,
      witnessCount,
    ].every(Number.isFinite);
    return {
      checkId: `D3_split_core_${String(profile.groupKey ?? 'unknown').replaceAll(/[^A-Za-z0-9_=-]/g, '_')}`,
      groupKey: profile.groupKey ?? null,
      witnessCount,
      minN: profile.minN ?? null,
      maxN: profile.maxN ?? null,
      minRequiredMatchingLowerBound: profile.minRequiredMatchingLowerBound ?? null,
      maxRequiredMatchingLowerBound,
      minReconstructedMatchingSize: profile.minReconstructedMatchingSize ?? null,
      maxReconstructedMatchingSize: profile.maxReconstructedMatchingSize ?? null,
      minSmallerSideSize,
      maxSmallerSideSize: profile.maxSmallerSideSize ?? null,
      minMatchingSlack: profile.minMatchingSlack ?? null,
      commonMatchingPairCount,
      commonMatchingPairs,
      commonMatchingPairExportComplete: Number.isFinite(commonMatchingPairCount)
        && commonMatchingPairs.length === commonMatchingPairCount,
      numericFieldsPresent,
      commonCoreMeetsMaxRequiredBound: numericFieldsPresent
        && commonMatchingPairCount >= maxRequiredMatchingLowerBound,
      commonCoreSaturatesMinSmallerSide: numericFieldsPresent
        && commonMatchingPairCount >= minSmallerSideSize,
      rightMinusLeftModuloP2Distribution: (profile.rightMinusLeftModuloP2Distribution ?? []).slice(0, 8),
    };
  });
  const proofChecks = [
    {
      checkId: 'D1_dependency_discharged',
      passed: matchingSaturationBoundProof?.status === 'bounded_matching_saturation_extraction_certified'
        && Number(matchingSaturationBoundProof?.failCount ?? 1) === 0,
      evidence: matchingSaturationBoundProof?.checkerId ?? null,
    },
    {
      checkId: 'p17_candidate_ready',
      passed: p17MatchingLowerBoundCandidate?.status === 'bounded_p17_threat_profile_ready_symbolic_proof_needed',
      evidence: p17MatchingLowerBoundCandidate?.candidateId ?? null,
    },
    {
      checkId: 'matching_pattern_artifact_ready',
      passed: isP17Pattern && matchingPatternMiner?.status === 'matching_pattern_witness_packet_ready',
      evidence: {
        status: matchingPatternMiner?.status ?? null,
        targetPrime: matchingPatternMiner?.parameters?.targetPrime ?? null,
        witnessRowCount: matchingPatternMiner?.summary?.witnessRowCount ?? null,
      },
    },
    {
      checkId: 'matching_reconstruction_agrees_with_verifier',
      passed: matchingPatternMiner?.summary?.allReconstructedMatchesAgree === true,
      evidence: matchingPatternMiner?.summary?.allReconstructedMatchesAgree ?? null,
    },
    {
      checkId: 'all_witnesses_saturate_smaller_side',
      passed: matchingPatternMiner?.summary?.allWitnessesSaturateSmallerSide === true,
      evidence: matchingPatternMiner?.summary?.saturatedSideDistribution ?? null,
    },
    {
      checkId: 'split_profiles_available',
      passed: profileChecks.length > 0,
      evidence: {
        splitProfileCount: profileChecks.length,
        commonAcrossAllProfiles: patternSummary?.commonMatchingPairCountAcrossWitnesses ?? null,
        proofHeuristic: patternSummary?.proofHeuristic ?? null,
      },
    },
    {
      checkId: 'split_common_cores_meet_required_K',
      passed: profileChecks.length > 0 && profileChecks.every((profile) => profile.commonCoreMeetsMaxRequiredBound),
      evidence: profileChecks.map((profile) => ({
        groupKey: profile.groupKey,
        commonMatchingPairCount: profile.commonMatchingPairCount,
        maxRequiredMatchingLowerBound: profile.maxRequiredMatchingLowerBound,
      })),
    },
    {
      checkId: 'split_common_core_pairs_exported',
      passed: profileChecks.length > 0 && profileChecks.every((profile) => profile.commonMatchingPairExportComplete),
      evidence: profileChecks.map((profile) => ({
        groupKey: profile.groupKey,
        commonMatchingPairCount: profile.commonMatchingPairCount,
        exportedPairCount: profile.commonMatchingPairs.length,
      })),
    },
    {
      checkId: 'split_common_cores_saturate_smaller_side_on_tight_rows',
      passed: profileChecks.length > 0 && profileChecks.every((profile) => profile.commonCoreSaturatesMinSmallerSide),
      evidence: profileChecks.map((profile) => ({
        groupKey: profile.groupKey,
        commonMatchingPairCount: profile.commonMatchingPairCount,
        minSmallerSideSize: profile.minSmallerSideSize,
      })),
    },
  ];
  const failedChecks = proofChecks.filter((check) => !check.passed);
  const failedProfiles = profileChecks.filter((profile) => (
    !profile.commonCoreMeetsMaxRequiredBound
    || !profile.commonCoreSaturatesMinSmallerSide
  ));
  const profileSummary = profileChecks.map((profile) => ({
    groupKey: profile.groupKey,
    witnessCount: profile.witnessCount,
    nRange: `${profile.minN}..${profile.maxN}`,
    requiredMatchingLowerBoundRange: [
      profile.minRequiredMatchingLowerBound,
      profile.maxRequiredMatchingLowerBound,
    ],
    reconstructedMatchingRange: [
      profile.minReconstructedMatchingSize,
      profile.maxReconstructedMatchingSize,
    ],
    commonMatchingPairCount: profile.commonMatchingPairCount,
    commonMatchingPairExportComplete: profile.commonMatchingPairExportComplete,
    commonMatchingPairs: profile.commonMatchingPairs,
    minMatchingSlack: profile.minMatchingSlack,
    commonCoreMeetsMaxRequiredBound: profile.commonCoreMeetsMaxRequiredBound,
    commonCoreSaturatesMinSmallerSide: profile.commonCoreSaturatesMinSmallerSide,
  }));

  return {
    checkerId: 'p848_D3_p17_split_core_witness_checker_v1',
    obligationId: 'D3_p17_split_core_witness_extraction',
    parentObligationId: 'D3_p17_matching_lower_bound',
    status: failedChecks.length === 0 && failedProfiles.length === 0
      ? 'bounded_split_core_witness_certified'
      : 'failed',
    checkedRowCount: proofChecks.length + profileChecks.length,
    passCount: proofChecks.length + profileChecks.length - failedChecks.length - failedProfiles.length,
    failCount: failedChecks.length + failedProfiles.length,
    statement: 'The tight p=17 matching-pattern witnesses split into residue/saturated-side profiles whose common matching cores already meet the required K(N,x) lower bound.',
    scope: {
      problemId: '848',
      universalInN: false,
      promotesAllNClaim: false,
      targetPrime: 17,
      sourceArtifact: 'MATCHING_PATTERN_MINER_P17.json',
      sourceAssessedRange: matchingPatternMiner?.parameters?.sourceAssessedRange ?? null,
      witnessRowCount: matchingPatternMiner?.summary?.witnessRowCount ?? null,
      splitProfileCount: profileChecks.length,
      role: 'bounded_split_core_witness_for_symbolic_D3_lift',
    },
    dependencies: [
      matchingSaturationBoundProof?.checkerId ?? 'p848_D1_matching_saturation_bound_checker_v1',
      p17MatchingLowerBoundCandidate?.candidateId ?? 'p848_D3_p17_matching_lower_bound_candidate_v1',
      'MATCHING_PATTERN_MINER_P17.patternSummary.splitProfiles',
    ],
    hypotheses: [
      'D1 has extracted the p=17 matching lower-bound target K(N,x).',
      'The matching-pattern miner reconstructs Hopcroft-Karp matchings as explicit missing-cross matching pairs for tight p=17 rows.',
      'The sampled tight rows split by outsider residue modulo 17^2, outsider residue modulo 25, and which side is smaller.',
      'Within each split profile, the common matching core is a matching present in every sampled row of that profile.',
    ],
    proof: [
      'Read the p=17 split profiles from MATCHING_PATTERN_MINER_P17.patternSummary.',
      'For each split profile, compare the common matching-pair count with the largest required K(N,x) among sampled rows in that profile.',
      'Check the stronger saturation witness: the common core also reaches the minimum smaller-side size observed in that profile.',
      'Because every sampled row in the split profile contains the common core, that core gives a bounded matching lower-bound witness for the sampled tight rows.',
      'This does not discharge D3 universally; it turns D3 into explicit split symbolic subgoals whose common cores must be proved to persist by residue/block argument.',
    ],
    proofChecks,
    failedChecks,
    profileChecks,
    failedProfiles,
    profileSummary,
    symbolicSubgoals: profileSummary.map((profile, index) => ({
      subgoalId: `D3.${index + 1}_persist_${String(profile.groupKey).replaceAll(/[^A-Za-z0-9_=-]/g, '_')}`,
      groupKey: profile.groupKey,
      goal: `Prove that the ${profile.commonMatchingPairCount}-edge common matching core persists for all p=17 threatening rows in split ${profile.groupKey}, or replace it with a parameterized extension core.`,
      boundedTarget: {
        requiredMatchingLowerBoundRange: profile.requiredMatchingLowerBoundRange,
        commonMatchingPairCount: profile.commonMatchingPairCount,
        commonMatchingPairExportComplete: profile.commonMatchingPairExportComplete,
        commonMatchingPairs: profile.commonMatchingPairs,
        minMatchingSlack: profile.minMatchingSlack,
      },
      falsifierBoundary: 'A row in this split loses one of the common-core missing-cross edges before a replacement edge is proved, or its K(N,x) exceeds the symbolic core size.',
    })),
    conclusion: failedChecks.length === 0 && failedProfiles.length === 0
      ? `The tight p=17 sample is reduced to ${profileChecks.length} split-core subgoals; every split common core meets the sampled maximum K(N,x) and saturates the sampled smaller side.`
      : 'At least one p=17 split core failed to meet the sampled K(N,x) target.',
    falsifierBoundary: failedChecks.length === 0 && failedProfiles.length === 0
      ? 'A refreshed p=17 matching-pattern miner falsifies this bounded witness packet if a split profile has no common core, if the common core falls below max K(N,x), or if the split heuristic changes. D3 remains open until these split cores are proved symbolically.'
      : 'Inspect failedChecks and failedProfiles before using this as a D3 symbolic-lift guide.',
  };
}

function buildP848StructuralLiftAtomicSurface(formalization) {
  const packProblemDir = formalization?.sources?.packProblemDir ?? null;
  const minerPath = packProblemDir ? path.join(packProblemDir, 'STRUCTURAL_LIFT_MINER.json') : null;
  const checklistPath = packProblemDir ? path.join(packProblemDir, 'STRUCTURAL_LIFT_CHECKLIST.json') : null;
  const fullVerifierPath = packProblemDir ? path.join(packProblemDir, 'FULL_MIXED_BASE_STRUCTURAL_VERIFIER.json') : null;
  const matchingPatternPath = packProblemDir ? path.join(packProblemDir, 'MATCHING_PATTERN_MINER.json') : null;
  const matchingPatternP17Path = packProblemDir ? path.join(packProblemDir, 'MATCHING_PATTERN_MINER_P17.json') : null;
  const miner = minerPath ? readJsonIfPresent(minerPath) : null;
  const checklist = checklistPath ? readJsonIfPresent(checklistPath) : null;
  const fullVerifier = fullVerifierPath ? readJsonIfPresent(fullVerifierPath) : null;
  const matchingPatternMiner = matchingPatternPath ? readJsonIfPresent(matchingPatternPath) : null;
  const matchingPatternMinerP17 = matchingPatternP17Path ? readJsonIfPresent(matchingPatternP17Path) : null;
  if (miner?.summary?.coverageComplete !== true || !checklist) {
    return null;
  }

  const currentFocus = checklist.currentFocus ?? {};
  const requestedActiveStepId = currentFocus.firstActionableStepId ?? 'C1_same_side_base_clique';
  const targetStepId = currentFocus.targetStepId ?? 'C6_mixed_clique_matching_formula';
  const sameSideBaseCliqueProof = buildP848SameSideBaseCliqueProof();
  const twoCliquesPlusCrossEdgesProof = buildP848TwoCliquesPlusCrossEdgesProof(
    sameSideBaseCliqueProof,
    miner,
    fullVerifier,
  );
  const missingCrossGraphDefinitionProof = buildP848MissingCrossGraphDefinitionProof(
    twoCliquesPlusCrossEdgesProof,
    miner,
    fullVerifier,
  );
  const cliqueVertexCoverDualityProof = buildP848CliqueVertexCoverDualityProof(
    missingCrossGraphDefinitionProof,
  );
  const konigMatchingReductionProof = buildP848KonigMatchingReductionProof(
    missingCrossGraphDefinitionProof,
  );
  const mixedCliqueMatchingFormulaProof = buildP848MixedCliqueMatchingFormulaProof(
    cliqueVertexCoverDualityProof,
    konigMatchingReductionProof,
    fullVerifier,
  );
  const matchingSaturationBoundProof = buildP848MatchingSaturationBoundProof(
    mixedCliqueMatchingFormulaProof,
    fullVerifier,
  );
  const p13MatchingLowerBoundCandidate = buildP848P13MatchingLowerBoundCandidate(
    matchingSaturationBoundProof,
    miner,
    matchingPatternMiner,
  );
  const p13SplitCoreWitnessProof = buildP848P13SplitCoreWitnessProof(
    matchingSaturationBoundProof,
    p13MatchingLowerBoundCandidate,
    matchingPatternMiner,
  );
  const p17MatchingLowerBoundCandidate = buildP848P17MatchingLowerBoundCandidate(
    matchingSaturationBoundProof,
    miner,
    matchingPatternMinerP17,
  );
  const p17SplitCoreWitnessProof = buildP848P17SplitCoreWitnessProof(
    matchingSaturationBoundProof,
    p17MatchingLowerBoundCandidate,
    matchingPatternMinerP17,
  );
  const proofPackets = {
    [sameSideBaseCliqueProof.obligationId]: sameSideBaseCliqueProof,
    [twoCliquesPlusCrossEdgesProof.obligationId]: twoCliquesPlusCrossEdgesProof,
    [missingCrossGraphDefinitionProof.obligationId]: missingCrossGraphDefinitionProof,
    [cliqueVertexCoverDualityProof.obligationId]: cliqueVertexCoverDualityProof,
    [konigMatchingReductionProof.obligationId]: konigMatchingReductionProof,
    [mixedCliqueMatchingFormulaProof.obligationId]: mixedCliqueMatchingFormulaProof,
    [matchingSaturationBoundProof.obligationId]: matchingSaturationBoundProof,
    ...(p13SplitCoreWitnessProof
      ? { [p13SplitCoreWitnessProof.obligationId]: p13SplitCoreWitnessProof }
      : {}),
    ...(p17SplitCoreWitnessProof
      ? { [p17SplitCoreWitnessProof.obligationId]: p17SplitCoreWitnessProof }
      : {}),
  };
  const dischargedProofStepIds = new Set(Object.values(proofPackets)
    .filter((proof) => Number(proof.failCount ?? 0) === 0)
    .map((proof) => proof.obligationId));
  const requestedActive = findP848StructuralLiftChecklistStep(checklist, requestedActiveStepId);
  const target = findP848StructuralLiftChecklistStep(checklist, targetStepId);
  const activePhase = requestedActive?.phase ?? target?.phase ?? null;
  const stepDependenciesDischarged = (step) => (step?.dependsOn ?? [])
    .every((dependencyId) => dischargedProofStepIds.has(dependencyId));
  const stepIsRunnable = (step) => {
    if (!step || step.stepId === targetStepId || dischargedProofStepIds.has(step.stepId) || step.status === 'target') {
      return false;
    }
    return !String(step.status ?? '').startsWith('blocked') || stepDependenciesDischarged(step);
  };
  const activeStepId = dischargedProofStepIds.has(requestedActiveStepId)
    ? ((activePhase?.steps ?? []).find((step) => (
        stepIsRunnable(step)
      ))?.stepId ?? targetStepId)
    : requestedActiveStepId;
  const active = findP848StructuralLiftChecklistStep(checklist, activeStepId);
  const activeStep = active?.step ?? null;
  const targetStep = target?.step ?? null;
  const proofObligations = (activePhase?.steps ?? []).map((step) => ({
    obligationId: step.stepId,
    status: dischargedProofStepIds.has(step.stepId)
      ? 'done'
      : step.stepId === activeStepId
        ? 'in_progress'
        : String(step.status ?? '').startsWith('blocked') && stepDependenciesDischarged(step)
          ? 'ready'
          : step.status ?? 'ready',
    task: step.statement,
    statement: step.statement,
    dependsOn: step.dependsOn ?? [],
    proofType: step.proofType ?? null,
    falsifierBoundary: step.falsifierBoundary ?? null,
    dischargedBy: proofPackets[step.stepId]?.checkerId ?? null,
    dischargeWith: proofPackets[step.stepId]?.conclusion
      ?? (step.stepId === activeStepId
      ? `Prove the active atom ${step.stepId} at its stated scope, then refresh FORMALIZATION_WORK so the next dependency is selected from the updated evidence.`
      : null),
  }));

  return {
    surfaceId: 'p848_structural_lift_atomic_surface_v1',
    status: 'active',
    canonicalSurface: 'FORMALIZATION_WORK.currentWork',
    role: 'atomic_proof_obligation_surface',
    evidenceArtifact: {
      path: minerPath,
      status: miner.status ?? null,
      minedExactRowCount: miner.summary?.minedExactRowCount ?? null,
      primaryExactPrimes: miner.summary?.primaryExactPrimes ?? [],
      nextTheoremLane: miner.summary?.nextTheoremLane ?? null,
    },
    matchingPatternArtifact: matchingPatternMiner
      ? {
        path: matchingPatternPath,
        status: matchingPatternMiner.status ?? null,
        targetPrime: matchingPatternMiner.parameters?.targetPrime ?? null,
        witnessRowCount: matchingPatternMiner.summary?.witnessRowCount ?? null,
        minMatchingSlack: matchingPatternMiner.summary?.minMatchingSlack ?? null,
      }
      : null,
    matchingPatternArtifacts: [
      matchingPatternMiner
        ? {
          path: matchingPatternPath,
          status: matchingPatternMiner.status ?? null,
          targetPrime: matchingPatternMiner.parameters?.targetPrime ?? null,
          witnessRowCount: matchingPatternMiner.summary?.witnessRowCount ?? null,
          minMatchingSlack: matchingPatternMiner.summary?.minMatchingSlack ?? null,
        }
        : null,
      matchingPatternMinerP17
        ? {
          path: matchingPatternP17Path,
          status: matchingPatternMinerP17.status ?? null,
          targetPrime: matchingPatternMinerP17.parameters?.targetPrime ?? null,
          witnessRowCount: matchingPatternMinerP17.summary?.witnessRowCount ?? null,
          minMatchingSlack: matchingPatternMinerP17.summary?.minMatchingSlack ?? null,
        }
        : null,
    ].filter(Boolean),
    referenceBacklog: {
      path: checklistPath,
      role: 'non_canonical_reference_backlog',
      note: 'The checklist is a map of possible sub-lemmas. The active theorem lane is the single atomic obligation surfaced here.',
    },
    activePacket: {
      packetId: currentFocus.packetId ?? activePhase?.phaseId ?? null,
      title: activePhase?.title ?? null,
      goal: activePhase?.goal ?? null,
    },
    requestedActiveAtom: requestedActive?.step
      ? {
        obligationId: requestedActive.step.stepId,
        status: dischargedProofStepIds.has(requestedActive.step.stepId) ? 'done' : requestedActive.step.status ?? 'ready',
        statement: requestedActive.step.statement,
      }
      : null,
    activeAtom: activeStep
      ? {
        obligationId: activeStep.stepId,
        status: dischargedProofStepIds.has(activeStep.stepId) ? 'done' : 'in_progress',
        statement: activeStep.statement,
        dependsOn: activeStep.dependsOn ?? [],
        proofType: activeStep.proofType ?? null,
        falsifierBoundary: activeStep.falsifierBoundary ?? null,
      }
      : null,
    targetAtom: targetStep
      ? {
        obligationId: targetStep.stepId,
        status: targetStep.status ?? 'target',
        statement: targetStep.statement,
        dependsOn: targetStep.dependsOn ?? [],
        proofType: targetStep.proofType ?? null,
        falsifierBoundary: targetStep.falsifierBoundary ?? null,
      }
      : null,
    dischargedAtoms: Object.values(proofPackets)
      .filter((proof) => Number(proof.failCount ?? 0) === 0)
      .map((proof) => ({
        obligationId: proof.obligationId,
        status: proof.status,
        checkerId: proof.checkerId,
        conclusion: proof.conclusion,
      })),
    proofPackets,
    candidatePackets: {
      ...(p13MatchingLowerBoundCandidate
        ? { [p13MatchingLowerBoundCandidate.obligationId]: p13MatchingLowerBoundCandidate }
        : {}),
      ...(p13SplitCoreWitnessProof
        ? { [p13SplitCoreWitnessProof.obligationId]: p13SplitCoreWitnessProof }
        : {}),
      ...(p17MatchingLowerBoundCandidate
        ? { [p17MatchingLowerBoundCandidate.obligationId]: p17MatchingLowerBoundCandidate }
        : {}),
      ...(p17SplitCoreWitnessProof
        ? { [p17SplitCoreWitnessProof.obligationId]: p17SplitCoreWitnessProof }
        : {}),
    },
    activeAtomEvidence: activeStepId === 'D2_p13_matching_lower_bound' && p13MatchingLowerBoundCandidate
      ? {
        ...p13MatchingLowerBoundCandidate,
        splitCoreWitnessPacket: p13SplitCoreWitnessProof
          ? {
            checkerId: p13SplitCoreWitnessProof.checkerId,
            status: p13SplitCoreWitnessProof.status,
            splitProfileCount: p13SplitCoreWitnessProof.scope?.splitProfileCount ?? null,
            failCount: p13SplitCoreWitnessProof.failCount,
            profileSummary: p13SplitCoreWitnessProof.profileSummary ?? [],
            symbolicSubgoals: p13SplitCoreWitnessProof.symbolicSubgoals ?? [],
            conclusion: p13SplitCoreWitnessProof.conclusion,
          }
          : null,
      }
      : null,
    proofObligations,
    atomicDiscipline: [
      'Do not promote the whole checklist as a theorem claim.',
      'Work one active atom at a time inside FORMALIZATION_WORK.currentWork.',
      'After each atom is discharged or falsified, regenerate this surface from the miner/checklist evidence.',
    ],
    boundary: {
      claimLevel: 'formalization_work_atom_not_proof',
      note: 'This surface names the next theorem obligation implied by the structural lift miner; it does not certify any new N by itself.',
    },
  };
}

function pickFormalizationWorkFocus(target) {
  const proofObligations = Array.isArray(target?.proofObligations) ? target.proofObligations : [];
  return (
    proofObligations.find((item) => item?.status === 'in_progress')
    ?? proofObligations.find((item) => item?.status === 'ready')
    ?? proofObligations[0]
    ?? null
  );
}

function buildGenericFormalizationTarget(problem, theoremLoop, claimPass) {
  const recommendations = Array.isArray(claimPass?.recommendations) ? claimPass.recommendations : [];
  const theoremRecommendation = recommendations.find((item) => item.lane === 'theorem_formalization') ?? recommendations[0] ?? null;
  const latestVerifiedInterval = claimPass?.currentState?.latestVerifiedInterval ?? null;
  const focusId = theoremRecommendation?.recommendation_id ?? 'seed_formalization_packet';
  const title = theoremRecommendation
    ? titleCaseWords(theoremRecommendation.recommendation_id)
    : 'Seed Formalization Packet';

  return {
    formalizationId: `${problem.cluster}_${problem.problemId}_${focusId}_v1`,
    focusId,
    title,
    status: theoremRecommendation ? 'ready' : 'seeded',
    lane: theoremRecommendation?.lane ?? 'theorem_formalization',
    sourceRecommendationId: theoremRecommendation?.recommendation_id ?? null,
    summary: theoremRecommendation?.reason ?? theoremLoop.currentState?.nextHonestMove ?? 'Seed the next honest theorem-facing packet.',
    statement: theoremRecommendation
      ? `Candidate formalization target: ${theoremRecommendation.reason}`
      : `Candidate formalization target: ${theoremLoop.currentState?.nextHonestMove ?? 'Seed the next honest theorem-facing claim.'}`,
    whyThisExists: theoremRecommendation
      ? 'This packet exists to turn a claim-pass recommendation into a concrete theorem-facing proof obligation with explicit falsifiers and promotion criteria.'
      : 'This packet exists to give the theorem lane a stable starting point even before richer bridge-backed claims have been promoted.',
    whyNow: theoremRecommendation?.reason
      ?? theoremLoop.currentState?.nextHonestMove
      ?? 'No richer theorem recommendation is recorded yet.',
    evidenceBasis: [
      `Current claim surface: ${theoremLoop.currentState?.currentClaimSurface ?? '(unknown)'}.`,
      `Active route: ${theoremLoop.activeRoute ?? '(none)'}.`,
      latestVerifiedInterval
        ? `Latest verified interval: ${latestVerifiedInterval}.`
        : 'No canonical verified interval is currently frozen.',
    ],
    proofObligations: [
      {
        obligationId: 'state_claim_honestly',
        status: 'ready',
        task: 'State the candidate theorem-facing claim in pack language without overstating current support.',
        why: 'This keeps the formalization target narrower than the current evidence boundary.',
        dischargeWith: 'Write a claim statement that is no stronger than the active claim-pass support surface.',
      },
      {
        obligationId: 'freeze_support_artifacts',
        status: 'ready',
        task: 'List the exact canonical artifacts that support the claim and the artifacts that could still falsify it.',
        why: 'The theorem lane should point at stable evidence, not drifting interpretation.',
        dischargeWith: 'Attach theorem-loop, claim-pass, and any bridge-backed packet paths directly to the packet.',
      },
      {
        obligationId: 'define_promotion_boundary',
        status: 'ready',
        task: 'Promote the target only when its support survives the current claim-pass falsifiers.',
        why: 'This prevents formalization packets from silently outrunning the rest of the loop.',
        dischargeWith: 'Record explicit promotion criteria tied to current falsifiers.',
      },
    ],
    falsifierChecks: [
      {
        checkId: 'claim_pass_survival',
        status: 'ready',
        task: 'A refreshed claim pass drops the target recommendation or marks the underlying claim unsupported.',
        why: 'If the recommendation itself no longer survives refresh, the formalization target is stale.',
        command: claimPass?.commands?.claimPassRefresh ?? null,
      },
      {
        checkId: 'artifact_boundary_check',
        status: 'ready',
        task: 'A canonical artifact boundary check shows the statement is stronger than the current pack evidence.',
        why: 'The packet should fail early if it is stronger than what the pack actually certifies.',
        command: theoremLoop?.commands?.theoremLoop ?? null,
      },
    ],
    promotionCriteria: [
      {
        criterionId: 'top_recommendation_survives',
        status: 'ready',
        task: 'The current target remains the top theorem-formalization recommendation after refresh.',
      },
      {
        criterionId: 'statement_stays_narrow',
        status: 'ready',
        task: 'The candidate statement is narrower than or equal to the current claim-pass support surface.',
      },
      {
        criterionId: 'obligations_are_actionable',
        status: 'ready',
        task: 'The remaining proof obligations are explicit enough to guide search or exact follow-up.',
      },
    ],
    supportingCommands: [
      theoremLoop.commands?.theoremLoop ?? null,
      claimPass?.commands?.claimPass ?? null,
      claimPass?.commands?.claimPassRefresh ?? null,
    ].filter(Boolean),
  };
}

function buildP848AlignmentFormalizationTarget(theoremLoop, claimPass) {
  const bridgeState = theoremLoop.currentBridgeState ?? {};
  const alignmentContext = buildP848AlignmentContext(theoremLoop);
  const nextRepresentative = bridgeState.next_unmatched_representative ?? '(unknown)';
  const strongestCompletedTail = bridgeState.strongest_completed_structured_tail?.continuation ?? '(unknown)';
  const currentLeader = bridgeState.current_family_aware_leader?.continuation ?? '(unknown)';
  const latestVerifiedInterval = claimPass?.currentState?.latestVerifiedInterval ?? null;
  const familyRow = alignmentContext.familyRow;
  const familyRowSourceLabel = alignmentContext.familyRowSource === 'live_family_menu'
    ? 'live family menu'
    : alignmentContext.familyRowSource === 'recovered_alignment_obstruction_packet'
    ? 'recovered alignment obstruction packet'
    : null;
  const tupleSummary = Array.isArray(familyRow?.tupleRows)
    ? familyRow.tupleRows.map((row) => `${row.anchor}->${row.squareModulus}/${row.residue}`).join(', ')
    : null;
  const stableRepairAnchors = alignmentContext.stableRepairRows.map((row) => row.anchor);
  const failingRepairAnchors = alignmentContext.failingRepairRows.map((row) => row.anchor);
  const failing282Witness = Array.isArray(alignmentContext.failing282?.squareWitnesses)
    ? alignmentContext.failing282.squareWitnesses.map((row) => row.squareModulus).join(', ')
    : null;
  const derivedActivationLemmaCheck = checkP848ActivationLemmaCertificates(
    alignmentContext.allFamilies,
    alignmentContext.familyMenuPath,
  );
  const derivedTupleRowLift132Proof = buildP848TupleRowLift132ProofFromAlignment(alignmentContext);
  const derivedTopRepairClassMechanism = buildP848TopRepairClassMechanism(alignmentContext);
  const formalizationWorkPath = theoremLoop.sources?.packProblemDir
    ? path.join(theoremLoop.sources.packProblemDir, 'FORMALIZATION_WORK.json')
    : null;
  const formalizationWorkDoc = formalizationWorkPath ? readJsonIfPresent(formalizationWorkPath) : null;
  const workPacket = formalizationWorkDoc?.currentWork ?? null;
  const activationLemmaCheck = workPacket?.packetData?.activationLemmaCheck ?? derivedActivationLemmaCheck;
  const tupleRowLift132Proof = workPacket?.packetData?.tupleRowLift132Proof ?? derivedTupleRowLift132Proof;
  const topRepairSeparation = workPacket?.packetData?.topRepairClassMechanism?.separationAnalysis
    ?? derivedTopRepairClassMechanism?.separationAnalysis
    ?? null;
  const mod50LaneSignature = topRepairSeparation?.mod50LaneSignature ?? null;
  const checkedMechanismPacketPromoted = activationLemmaCheck?.status === 'passed'
    && tupleRowLift132Proof?.status === 'proved_from_tuple_row_crt'
    && (
      Array.isArray(workPacket?.dischargedWork)
        ? workPacket.dischargedWork.some((item) => String(item).includes('132-row lift'))
        : true
    );
  const checkedTopRepairPacketPromoted = topRepairSeparation?.status === 'finite_menu_plus2_replay_certified'
    && mod50LaneSignature?.status === 'finite_menu_mod50_lane_signature_certified';

  return {
    formalizationId: 'p848_282_alignment_formalization_v1',
    focusId: 'formalize_282_alignment',
    title: 'Formalize the 282 Obstruction Alignment',
    status: checkedMechanismPacketPromoted ? 'in_progress' : 'ready',
    lane: 'theorem_formalization',
    sourceRecommendationId: 'formalize_282_alignment',
    sourceClaimId: 'p848_next_unmatched_alignment_claim',
    sourceHookId: 'next_unmatched_equals_282_failure',
    summary: checkedMechanismPacketPromoted
      ? `The live ${nextRepresentative} / 282 obstruction packet is checked at finite-menu scope; the remaining theorem work is the narrower symbolic-lift boundary.`
      : `Turn the live ${nextRepresentative} / 282 coincidence into a claim-safe obstruction-class packet.`,
    statement: checkedMechanismPacketPromoted
      ? `Checked finite-menu statement: the shared-prefix obstruction represented at n=${nextRepresentative} aligns with continuation tail 282 through the 841 witness class, with the 132-row lift and activation certificates replayed; a universal symbolic lift remains separate.`
      : `Candidate theorem-facing statement: the shared-prefix obstruction currently first represented at n=${nextRepresentative} is not just a finite-window coincidence, but the same obstruction class that first forces failure of continuation tail 282.`,
    whyThisExists: 'This packet exists to bridge the gap between search evidence and proof. Without it, the loop only says the alignment is suggestive; with it, the theorem lane gets an explicit object to prove, falsify, or narrow.',
    whyNow: `The canonical bridge freezes next unmatched representative ${nextRepresentative}, and the claim pass already marks its equality with the first failure of tail 282 as supported.`,
    evidenceBasis: [
      `The canonical bridge records next unmatched representative ${nextRepresentative}.`,
      `The tracked-tail matrix records continuation 282 failing first at ${nextRepresentative}.`,
      familyRow
        ? `The ${familyRowSourceLabel} supplies representative ${nextRepresentative} with tuple key ${familyRow.tupleKey} and tuple rows ${tupleSummary}.`
        : `The current family menu does not yet expose a concrete row for representative ${nextRepresentative}.`,
      familyRow && alignmentContext.only282Fails
        ? `On that family-menu row, only continuation 282 fails among the tracked tails, and it does so via witness modulus ${failing282Witness}.`
        : `The tracked repair boundary for representative ${nextRepresentative} is not yet isolated to a single failing continuation.`,
      `The strongest completed structured tail remains ${strongestCompletedTail}, so this packet isolates the 282 obstruction mechanism rather than conflating it with the current family-aware leader ${currentLeader}.`,
      latestVerifiedInterval
        ? `The finite exact base is already certified through ${latestVerifiedInterval}, so the open work is structural rather than basic interval bookkeeping.`
        : 'The finite exact base is not yet frozen, so this packet remains provisional.',
      checkedMechanismPacketPromoted
        ? `Formalization-work checker ${activationLemmaCheck.checkerId} replayed ${activationLemmaCheck.checkedRowCount} activation rows with ${activationLemmaCheck.failCount} failures.`
        : null,
      checkedMechanismPacketPromoted
        ? `Formalization-work checker ${tupleRowLift132Proof.checkerId} proved the 132-row lift with k=${tupleRowLift132Proof.liftParameter} and residue ${tupleRowLift132Proof.liftedResidueModuloWitness} mod ${alignmentContext.witnessSquareModulus}.`
        : null,
      checkedTopRepairPacketPromoted
        ? `The top repair-class side packet is also checked: +2 finite-menu replay plus ${mod50LaneSignature.checkedRowCount} mod-50 lane exchange rows pass.`
        : null,
    ].filter(Boolean),
    proofObligations: [
      {
        obligationId: 'define_shared_prefix_obstruction_class',
        status: familyRow ? 'done' : 'ready',
        task: `Define the shared-prefix obstruction class precisely enough that the representative n=${nextRepresentative} and the 282 continuation can be discussed in the same language.`,
        why: 'Without a shared obstruction language, the current equality is still only a numerical coincidence.',
        dischargeWith: familyRow
          ? 'Use the family-menu row language: shared-prefix tuple rows plus representative/modulus/residue plus tracked-tail repair rows.'
          : 'Write the common packet/tuple/CRT language that contains both the shared-prefix representative and the 282-tail failure.',
      },
      {
        obligationId: 'explain_282_first_failure_mechanism',
        status: checkedMechanismPacketPromoted ? 'done' : alignmentContext.failing282 ? 'in_progress' : 'ready',
        task: 'Explain why the 282 continuation first fails on that obstruction class rather than merely sharing the same first failing n by accident.',
        why: 'This is the core mechanism claim that would upgrade the bridge fact into a theorem-facing lemma candidate.',
        dischargeWith: checkedMechanismPacketPromoted
          ? `Use the checked packet: ${activationLemmaCheck.checkerId} plus ${tupleRowLift132Proof.checkerId} certify the finite-menu mechanism, while keeping the universal lift out of scope.`
          : alignmentContext.failing282
          ? `Describe why the ${failing282Witness} witness appears for continuation 282 on this class while the neighboring tracked tails stay squarefree.`
          : 'Describe the repair/obstruction mechanism that makes 282 vulnerable exactly at that class.',
      },
      {
        obligationId: 'separate_alignment_from_leaderboard_artifacts',
        status: stableRepairAnchors.length > 0 ? 'done' : 'ready',
        task: 'Separate this obstruction-alignment claim from unrelated leaderboard behavior of 432, 782, and 832 so the statement stays narrow and honest.',
        why: 'The 282 packet should not inherit unsupported claims from the current repair-class leaderboard.',
        dischargeWith: stableRepairAnchors.length > 0
          ? `Freeze the local repair boundary: ${failingRepairAnchors.join(', ')} fails on this class while ${stableRepairAnchors.join(', ')} remain squarefree.`
          : 'State explicitly what the packet does not claim about 432, 782, 832, or 332.',
      },
      {
        obligationId: 'freeze_alignment_falsifier_boundary',
        status: alignmentContext.witnessFirstOccurrence?.earlierZeroResidueCount === 0 ? 'done' : 'ready',
        task: 'Record what extra bridge or exact evidence would count as a genuine falsifier of the alignment mechanism.',
        why: 'A theorem packet is more trustworthy when it names its own failure modes.',
        dischargeWith: alignmentContext.witnessFirstOccurrence?.earlierZeroResidueCount === 0
          ? `Bind the packet to the explicit falsifier boundary: a lower representative in the ${alignmentContext.witnessSquareModulus ?? '(unknown)'} witness class, a different first 282 witness, or bridge loss of the ${nextRepresentative} <-> 282 alignment.`
          : 'Bind the packet to refreshable bridge and exact checks that could break it.',
      },
      checkedMechanismPacketPromoted
        ? {
          obligationId: 'lift_132_activation_schema_beyond_finite_menu',
          status: 'ready',
          task: 'Decide whether the checked finite-menu 132 activation schema can be lifted into a symbolic CRT lemma beyond the current family menu.',
          why: 'This is now the honest successor to the discharged 282 mechanism packet: the mechanism is checked finitely, but the universal theorem should not inherit it without a symbolic lift.',
          dischargeWith: 'Prove parameterized tuple-row CRT hypotheses that force pre-132 misses, unique 132 target activation, and 182 preservation beyond the current finite menu.',
        }
        : null,
    ].filter(Boolean),
    falsifierChecks: [
      {
        checkId: 'bridge_next_unmatched_stability',
        status: 'ready',
        task: `A refreshed bridge no longer lists ${nextRepresentative} as the next unmatched representative.`,
        why: 'If the bridge frontier moves, the current packet may no longer be pointing at the right obstruction.',
        command: 'erdos number-theory bridge-refresh 848',
      },
      {
        checkId: 'tracked_tail_282_stability',
        status: 'ready',
        task: `A refreshed tracked-tail matrix no longer gives continuation 282 first failure ${nextRepresentative}.`,
        why: 'The packet is only interesting if the 282-tail boundary stays synchronized with the shared-prefix representative.',
        command: 'erdos problem claim-pass-refresh 848',
      },
      {
        checkId: 'obstruction_class_mismatch',
        status: 'ready',
        task: 'Packet replay or family-menu analysis shows that the shared-prefix representative and the 282 failure belong to different obstruction classes.',
        why: 'This would directly break the mechanism-level interpretation of the alignment.',
        command: 'erdos number-theory dispatch 848 --apply --action cpu_family_search',
      },
    ],
    promotionCriteria: [
      {
        criterionId: 'alignment_hook_survives',
        status: checkedMechanismPacketPromoted ? 'done' : 'ready',
        task: 'The next_unmatched_equals_282_failure hook stays supported after refresh.',
      },
      {
        criterionId: 'statement_is_mechanism_level',
        status: checkedMechanismPacketPromoted ? 'done' : 'ready',
        task: 'The candidate statement is expressed as an obstruction-class alignment, not as a full theorem of closure.',
      },
      {
        criterionId: 'mechanism_is_testable',
        status: checkedMechanismPacketPromoted ? 'done' : 'ready',
        task: 'The packet identifies at least one mechanism-level explanation to test, not just a repeated equality of two numbers.',
      },
      checkedMechanismPacketPromoted
        ? {
          criterionId: 'finite_menu_mechanism_checked',
          status: 'done',
          task: 'The finite-menu 282 mechanism is checked by activation-row and CRT-lift replay certificates.',
        }
        : null,
    ].filter(Boolean),
    supportingCommands: [
      'erdos number-theory bridge-refresh 848',
      'erdos problem claim-pass-refresh 848',
      'erdos problem formalization-work 848',
      'erdos number-theory dispatch 848 --apply --action cpu_family_search',
      'erdos number-theory dispatch 848 --apply --action exact_followup_rollout',
    ],
  };
}

function p848TargetHasDoneObligation(target, obligationId) {
  return Array.isArray(target?.proofObligations)
    && target.proofObligations.some((item) => item?.obligationId === obligationId && item?.status === 'done');
}

function p848TargetHasDonePromotionCriterion(target, criterionId) {
  return Array.isArray(target?.promotionCriteria)
    && target.promotionCriteria.some((item) => item?.criterionId === criterionId && item?.status === 'done');
}

function buildP848TupleRowLift132ProofFromAlignment(alignmentContext) {
  const familyRow = alignmentContext?.familyRow ?? null;
  const tupleRows = Array.isArray(familyRow?.tupleRows) ? familyRow.tupleRows : [];
  const steps = Array.isArray(alignmentContext?.tupleRowCrtDerivation?.steps)
    ? alignmentContext.tupleRowCrtDerivation.steps
    : [];
  const tupleRow132 = tupleRows.find((row) => Number(row.anchor) === 132) ?? null;
  const stepIndex132 = steps.findIndex((row) => Number(row.anchor) === 132);
  const tupleRow132Step = stepIndex132 >= 0 ? steps[stepIndex132] : null;
  const tupleRow132PreviousStep = stepIndex132 > 0 ? steps[stepIndex132 - 1] : null;
  const witnessSquareModulus = alignmentContext?.witnessSquareModulus ?? null;
  const representativeResidueModuloWitness = witnessSquareModulus && familyRow?.representative !== undefined
    ? positiveMod(familyRow.representative, witnessSquareModulus)
    : null;

  if (!tupleRow132 || !tupleRow132Step || !tupleRow132PreviousStep || !witnessSquareModulus) {
    return null;
  }

  const liftCoeffModuloAnchor = positiveMod(tupleRow132PreviousStep.combinedModulus, tupleRow132.squareModulus);
  const liftRhsModuloAnchor = positiveMod(
    tupleRow132.residue - positiveMod(tupleRow132PreviousStep.combinedResidue, tupleRow132.squareModulus),
    tupleRow132.squareModulus,
  );
  const inverseLiftCoeff = modularInverseInt(liftCoeffModuloAnchor, tupleRow132.squareModulus);
  const liftParameter = inverseLiftCoeff === null
    ? null
    : positiveMod(inverseLiftCoeff * liftRhsModuloAnchor, tupleRow132.squareModulus);

  if (liftParameter === null) {
    return {
      checkerId: 'p848_132_lift_crt_checker_v1',
      source: 'tuple_row_crt_equation_replay',
      status: 'failed',
      checkedRowCount: 1,
      passCount: 0,
      failCount: 1,
      failedChecks: ['lift_parameter_missing'],
    };
  }

  const preResidue = BigInt(tupleRow132PreviousStep.combinedResidue);
  const preModulus = BigInt(tupleRow132PreviousStep.combinedModulus);
  const liftParameterBigInt = BigInt(liftParameter);
  const anchorModulus = BigInt(tupleRow132.squareModulus);
  const witnessModulus = BigInt(witnessSquareModulus);
  const liftedByParameter = preResidue + (preModulus * liftParameterBigInt);
  const checks = {
    liftParameterSolvesReducedEquation: positiveModBigInt(BigInt(liftCoeffModuloAnchor) * liftParameterBigInt, anchorModulus)
      === BigInt(liftRhsModuloAnchor),
    liftedResidueMatchesCrtStep: liftedByParameter === BigInt(tupleRow132Step.combinedResidue),
    liftedResidueSatisfiesAnchor132: positiveModBigInt(liftedByParameter, anchorModulus)
      === BigInt(tupleRow132.residue),
    liftedResiduePreservesPriorCrtPrefix: positiveModBigInt(liftedByParameter, preModulus)
      === positiveModBigInt(preResidue, preModulus),
    liftedResidueHitsWitnessProjection: positiveModBigInt(liftedByParameter, witnessModulus)
      === BigInt(tupleRow132Step.residueModWitness),
    liftedResidueHitsBoundaryWitnessResidue: representativeResidueModuloWitness !== null
      && positiveModBigInt(liftedByParameter, witnessModulus) === BigInt(representativeResidueModuloWitness),
  };
  const failedChecks = Object.entries(checks)
    .filter(([, passed]) => !passed)
    .map(([checkId]) => checkId);

  return {
    checkerId: 'p848_132_lift_crt_checker_v1',
    source: 'tuple_row_crt_equation_replay',
    status: failedChecks.length === 0 ? 'proved_from_tuple_row_crt' : 'failed',
    checkedRowCount: 1,
    passCount: failedChecks.length === 0 ? 1 : 0,
    failCount: failedChecks.length,
    equation: `${tupleRow132PreviousStep.combinedResidue} + ${tupleRow132PreviousStep.combinedModulus}*k ≡ ${tupleRow132.residue} (mod ${tupleRow132.squareModulus})`,
    reducedEquation: `${liftCoeffModuloAnchor}*k ≡ ${liftRhsModuloAnchor} (mod ${tupleRow132.squareModulus})`,
    liftParameter,
    liftedResidueByParameter: toJsonInteger(liftedByParameter),
    liftedResidueModuloWitness: tupleRow132Step.residueModWitness,
    targetWitnessResidue: representativeResidueModuloWitness,
    checks,
    failedChecks,
    conclusion: failedChecks.length === 0
      ? `The 132-row lift from residue ${tupleRow132PreviousStep.residueModWitness} to ${tupleRow132Step.residueModWitness} mod ${witnessSquareModulus} is proved by the tuple-row CRT equation.`
      : 'The 132-row lift did not replay from the tuple-row CRT equation.',
  };
}

function buildProblemFormalizationTarget(problem, theoremLoop, claimPass) {
  const recommendations = Array.isArray(claimPass?.recommendations) ? claimPass.recommendations : [];
  const theoremRecommendation = recommendations.find((item) => item.lane === 'theorem_formalization') ?? null;

  if (problem.problemId === '848' && theoremRecommendation?.recommendation_id === 'formalize_282_alignment') {
    return buildP848AlignmentFormalizationTarget(theoremLoop, claimPass);
  }

  return buildGenericFormalizationTarget(problem, theoremLoop, claimPass);
}

export function buildProblemClaimPass(problem) {
  const theoremLoop = buildProblemTheoremLoop(problem);
  const claimLoop = buildProblemClaimLoop(problem);
  const theoremPaths = getProblemTheoremLoopPaths(problem);
  const claimLoopPaths = getProblemClaimLoopPaths(problem);
  const claimPassPaths = getProblemClaimPassPaths(problem);
  const bridgeDoc = theoremPaths.legacyBridgeJsonPath ? readJsonIfPresent(theoremPaths.legacyBridgeJsonPath) : null;
  const intervalQueuePath = theoremPaths.packProblemDir ? path.join(theoremPaths.packProblemDir, 'INTERVAL_WORK_QUEUE.yaml') : null;
  const intervalQueue = readYamlIfPresent(intervalQueuePath);

  const bridgeHooks = new Map(
    Array.isArray(bridgeDoc?.candidate_theorem_hooks)
      ? bridgeDoc.candidate_theorem_hooks.map((hook) => [hook.hook_id, hook])
      : [],
  );

  const hookAssessments = (theoremLoop.theoremHooks ?? []).map((hook) => (
    buildHookAssessment(hook, bridgeHooks.get(hook.hook_id) ?? null, theoremLoop, bridgeDoc)
  ));

  const claimAssessments = (claimLoop.candidateClaims ?? []).map((claim) => (
    buildClaimAssessment(problem, claim, theoremLoop, claimLoop, hookAssessments, bridgeDoc, intervalQueue)
  ));

  const latestVerifiedInterval = getLatestVerifiedInterval(intervalQueue);
  const recommendations = buildClaimPassRecommendations(problem, theoremLoop, claimAssessments, hookAssessments, intervalQueue);

  return {
    schema: 'erdos.problem_claim_pass/1',
    generatedAt: new Date().toISOString(),
    problemId: problem.problemId,
    displayName: problem.displayName,
    title: problem.title,
    cluster: problem.cluster,
    sourceKind: theoremLoop.currentBridgeState ? 'claim_loop_plus_bridge' : 'claim_loop_only',
    claimPassMode: theoremLoop.currentBridgeState ? 'bridge_backed' : 'baseline',
    currentClaimSurface: theoremLoop.currentState.currentClaimSurface,
    currentState: {
      activeRoute: theoremLoop.activeRoute,
      nextHonestMove: theoremLoop.currentState.nextHonestMove,
      routeSummary: theoremLoop.currentState.routeSummary,
      latestVerifiedInterval: latestVerifiedInterval?.range ?? null,
      sourceRefresh: theoremLoop.commands.sourceRefresh ?? null,
    },
    summary: buildClaimPassSummary(hookAssessments, claimAssessments),
    hookAssessments,
    claimAssessments,
    recommendations,
    commands: {
      problemShow: `erdos problem show ${problem.problemId}`,
      problemArtifacts: `erdos problem artifacts ${problem.problemId}`,
      theoremLoop: theoremLoop.commands.theoremLoop,
      theoremLoopRefresh: theoremLoop.commands.theoremLoopRefresh,
      claimLoop: claimLoop.commands.claimLoop,
      claimLoopRefresh: claimLoop.commands.claimLoopRefresh,
      claimPass: `erdos problem claim-pass ${problem.problemId}`,
      claimPassRefresh: `erdos problem claim-pass-refresh ${problem.problemId}`,
      sourceRefresh: theoremLoop.commands.sourceRefresh ?? null,
    },
    sources: {
      packProblemDir: theoremPaths.packProblemDir,
      theoremLoopJsonPath: theoremPaths.theoremLoopJsonPath,
      theoremLoopMarkdownPath: theoremPaths.theoremLoopMarkdownPath,
      claimLoopJsonPath: claimLoopPaths.claimLoopJsonPath,
      claimLoopMarkdownPath: claimLoopPaths.claimLoopMarkdownPath,
      claimPassJsonPath: claimPassPaths.claimPassJsonPath,
      claimPassMarkdownPath: claimPassPaths.claimPassMarkdownPath,
      legacyBridgeJsonPath: theoremPaths.legacyBridgeJsonPath,
      legacyBridgeMarkdownPath: theoremPaths.legacyBridgeMarkdownPath,
      intervalQueuePath,
    },
  };
}

export function renderProblemClaimPassMarkdown(doc) {
  const lines = [
    `# ${doc.displayName} Claim Pass`,
    '',
    doc.sourceKind === 'claim_loop_plus_bridge'
      ? 'This claim pass evaluates theorem-search claims against the canonical claim loop plus bridge-backed search evidence.'
      : 'This claim pass evaluates theorem-search claims against the canonical claim loop and pack-level evidence.',
    '',
    '## Current State',
    '',
    `- Claim pass mode: \`${doc.claimPassMode}\`.`,
    `- Current claim surface: \`${doc.currentClaimSurface}\`.`,
    `- Active route: \`${doc.currentState.activeRoute ?? '(none)'}\`.`,
    `- Route summary: ${doc.currentState.routeSummary}`,
    `- Next honest move: ${doc.currentState.nextHonestMove}`,
    `- Latest verified interval: ${doc.currentState.latestVerifiedInterval ? `\`${doc.currentState.latestVerifiedInterval}\`` : '`(none)`'}`,
    '',
    '## Summary',
    '',
    `- Hook assessments: supported \`${doc.summary.hooks.supported}\`, unresolved \`${doc.summary.hooks.unresolved}\`, broken \`${doc.summary.hooks.broken}\`.`,
    `- Claim assessments: supported \`${doc.summary.claims.supported}\`, actionable \`${doc.summary.claims.actionable}\`, unresolved \`${doc.summary.claims.unresolved}\`, broken \`${doc.summary.claims.broken}\`.`,
    '',
    '## Hook Assessments',
    '',
  ];

  for (const hook of doc.hookAssessments ?? []) {
    lines.push(`- \`${hook.hook_id}\`: ${hook.verdict} | ${hook.rationale}`);
  }

  lines.push('', '## Claim Assessments', '');
  for (const claim of doc.claimAssessments ?? []) {
    lines.push(`- \`${claim.claim_id}\`: ${claim.verdict} | ${claim.summary}${claim.rationale ? ` | ${claim.rationale}` : ''}`);
  }

  lines.push('', '## Recommendations', '');
  for (const recommendation of doc.recommendations ?? []) {
    lines.push(`- \`${recommendation.recommendation_id}\`: ${recommendation.priority} | ${recommendation.lane} | ${recommendation.reason}${recommendation.command ? ` | ${recommendation.command}` : ''}`);
  }

  lines.push('', '## Commands', '');
  lines.push(`- Problem surface: \`${doc.commands.problemShow}\``);
  lines.push(`- Problem artifacts: \`${doc.commands.problemArtifacts}\``);
  lines.push(`- Theorem loop: \`${doc.commands.theoremLoop}\``);
  lines.push(`- Claim loop: \`${doc.commands.claimLoop}\``);
  lines.push(`- Claim pass: \`${doc.commands.claimPass}\``);
  lines.push(`- Claim pass refresh: \`${doc.commands.claimPassRefresh}\``);
  if (doc.commands.sourceRefresh) {
    lines.push(`- Source refresh: \`${doc.commands.sourceRefresh}\``);
  }

  lines.push('', '## Sources', '');
  for (const [label, value] of Object.entries(doc.sources ?? {})) {
    if (!value) {
      continue;
    }
    lines.push(`- ${label}: \`${value}\``);
  }
  lines.push('');
  return lines.join('\n');
}

export function getProblemClaimPassSnapshot(problem) {
  const doc = buildProblemClaimPass(problem);
  const paths = getProblemClaimPassPaths(problem);
  return {
    ...doc,
    claimPassJsonPath: paths.claimPassJsonPath,
    claimPassMarkdownPath: paths.claimPassMarkdownPath,
    claimPassJsonPresent: Boolean(paths.claimPassJsonPath && fs.existsSync(paths.claimPassJsonPath)),
    claimPassMarkdownPresent: Boolean(paths.claimPassMarkdownPath && fs.existsSync(paths.claimPassMarkdownPath)),
  };
}

export function buildProblemFormalization(problem) {
  const theoremLoop = buildProblemTheoremLoop(problem);
  const claimLoop = buildProblemClaimLoop(problem);
  const claimPass = buildProblemClaimPass(problem);
  const paths = getProblemFormalizationPaths(problem);
  const target = buildProblemFormalizationTarget(problem, theoremLoop, claimPass);
  const obligationSummary = summarizeChecklist(target.proofObligations);
  const falsifierSummary = summarizeChecklist(target.falsifierChecks);
  const promotionSummary = summarizeChecklist(target.promotionCriteria);

  return {
    schema: 'erdos.problem_formalization/1',
    generatedAt: new Date().toISOString(),
    problemId: problem.problemId,
    displayName: problem.displayName,
    title: problem.title,
    cluster: problem.cluster,
    sourceKind: theoremLoop.currentBridgeState ? 'claim_pass_plus_bridge' : 'claim_pass_only',
    formalizationMode: theoremLoop.currentBridgeState ? 'bridge_backed' : 'baseline',
    currentClaimSurface: theoremLoop.currentState.currentClaimSurface,
    currentState: {
      activeRoute: theoremLoop.activeRoute,
      routeSummary: theoremLoop.currentState.routeSummary,
      nextHonestMove: theoremLoop.currentState.nextHonestMove,
      latestVerifiedInterval: claimPass.currentState?.latestVerifiedInterval ?? null,
      sourceRefresh: theoremLoop.commands.sourceRefresh ?? null,
    },
    currentTarget: target,
    summary: {
      proofObligations: obligationSummary,
      falsifierChecks: falsifierSummary,
      promotionCriteria: promotionSummary,
    },
    theoremHooks: theoremLoop.theoremHooks ?? [],
    claimAssessments: claimPass.claimAssessments ?? [],
    recommendationLedger: claimPass.recommendations ?? [],
    commands: {
      problemShow: `erdos problem show ${problem.problemId}`,
      problemArtifacts: `erdos problem artifacts ${problem.problemId}`,
      theoremLoop: theoremLoop.commands.theoremLoop,
      claimLoop: claimLoop.commands.claimLoop,
      claimPass: claimPass.commands.claimPass,
      formalization: `erdos problem formalization ${problem.problemId}`,
      formalizationRefresh: `erdos problem formalization-refresh ${problem.problemId}`,
      formalizationWork: `erdos problem formalization-work ${problem.problemId}`,
      formalizationWorkRefresh: `erdos problem formalization-work-refresh ${problem.problemId}`,
      sourceRefresh: theoremLoop.commands.sourceRefresh ?? null,
    },
    sources: {
      packProblemDir: paths.packProblemDir,
      formalizationJsonPath: paths.formalizationJsonPath,
      formalizationMarkdownPath: paths.formalizationMarkdownPath,
      theoremLoopJsonPath: theoremLoop.sources.theoremLoopJsonPath ?? null,
      theoremLoopMarkdownPath: theoremLoop.sources.theoremLoopMarkdownPath ?? null,
      claimLoopJsonPath: claimLoop.sources.claimLoopJsonPath ?? null,
      claimLoopMarkdownPath: claimLoop.sources.claimLoopMarkdownPath ?? null,
      claimPassJsonPath: claimPass.sources.claimPassJsonPath ?? null,
      claimPassMarkdownPath: claimPass.sources.claimPassMarkdownPath ?? null,
      legacyBridgeJsonPath: theoremLoop.sources.legacyBridgeJsonPath ?? null,
      legacyBridgeMarkdownPath: theoremLoop.sources.legacyBridgeMarkdownPath ?? null,
    },
  };
}

