function parseP848ClosedIntegerRange(rangeText) {
  const match = String(rangeText ?? '').trim().match(/^(\d+)\.\.(\d+)$/);
  if (!match) {
    return null;
  }
  return {
    min: Number(match[1]),
    max: Number(match[2]),
  };
}

function parseP848ScientificInteger(value) {
  const text = String(value ?? '').trim().replace(/\s+/g, ' ');
  const match = text.match(/^(\d+(?:\.\d+)?)\s*(?:x|\*)\s*10\^(\d+)$/i);
  if (!match) {
    const plain = text.match(/^\d+$/);
    return plain ? BigInt(text) : null;
  }
  const mantissa = match[1];
  const exponent = Number(match[2]);
  const [whole, fractional = ''] = mantissa.split('.');
  const digits = `${whole}${fractional}`.replace(/^0+/, '') || '0';
  const zeroCount = exponent - fractional.length;
  if (zeroCount < 0) {
    return null;
  }
  return BigInt(`${digits}${'0'.repeat(zeroCount)}`);
}

function formatP848BigInt(value) {
  return value.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ',');
}

function ceilP848BigIntRatio(numerator, denominator) {
  if (denominator <= 0n) {
    return null;
  }
  return (numerator + denominator - 1n) / denominator;
}

function buildP848FiniteGapStrategy(problem, latestVerifiedInterval, intervalQueue, breakpointCertificate) {
  if (String(problem?.problemId ?? '') !== '848') {
    return null;
  }

  const exactIntervalBookkeeping = buildP848ExactIntervalBookkeeping(problem, latestVerifiedInterval, breakpointCertificate);
  const exactRange = parseP848ClosedIntegerRange(latestVerifiedInterval);
  const importedThresholdRaw = intervalQueue?.operational_threshold?.value ?? null;
  const importedThreshold = parseP848ScientificInteger(importedThresholdRaw);
  const certificateSummary = breakpointCertificate?.certificate?.summary ?? null;
  if (!exactRange || !importedThreshold || !certificateSummary?.rowCount || !certificateSummary?.endpointCheckCount) {
    return {
      status: 'incomplete_inputs',
      reason: 'Finite-gap strategy needs a latest exact interval, an operational threshold, and an endpoint certificate summary.',
    };
  }

  const exactMax = BigInt(exactRange.max);
  const remainingRows = importedThreshold > exactMax ? importedThreshold - exactMax : 0n;
  const rowCount = BigInt(certificateSummary.rowCount);
  const endpointCheckCount = BigInt(certificateSummary.endpointCheckCount);
  const projectedEndpointChecks = ceilP848BigIntRatio(remainingRows * endpointCheckCount, rowCount);
  const endpointRowsPerCheck = Number(certificateSummary.rowCount) / Number(certificateSummary.endpointCheckCount);

  return {
    status: 'ready',
    verdict: 'exact_endpoint_rollout_is_not_a_sole_all_N_closure_strategy',
    latestVerifiedInterval,
    exactMax: exactRange.max,
    operationalThreshold: {
      raw: importedThresholdRaw,
      integer: importedThreshold.toString(),
      trustStatus: intervalQueue?.operational_threshold?.trust_status ?? 'external_or_unknown',
      source: intervalQueue?.operational_threshold?.source ?? null,
    },
    remainingRowsToOperationalThreshold: remainingRows.toString(),
    remainingRowsToOperationalThresholdLabel: formatP848BigInt(remainingRows),
    endpointCertificate: {
      interval: certificateSummary.interval,
      rowCount: certificateSummary.rowCount,
      endpointCheckCount: certificateSummary.endpointCheckCount,
      compressionRatio: certificateSummary.compressionRatio,
      approximateRowsPerEndpointCheck: endpointRowsPerCheck,
      sourceStatus: breakpointCertificate?.certificate?.sourceResultsStatus ?? null,
      sourceResultsSha256: breakpointCertificate?.certificate?.sourceResultsSha256 ?? null,
      publicRawPacketInterval: exactIntervalBookkeeping?.publicRepoRawExactInterval ?? null,
      raw40500PacketCommitted: exactIntervalBookkeeping?.raw40500PacketCommitted ?? null,
    },
    projectedEndpointChecksToOperationalThreshold: projectedEndpointChecks?.toString() ?? null,
    projectedEndpointChecksToOperationalThresholdLabel: projectedEndpointChecks
      ? formatP848BigInt(projectedEndpointChecks)
      : null,
    recommendedMode: 'hybrid_threshold_audit_plus_structural_verifier',
    guidance: [
      'Continue endpoint rollouts only as bounded base expansion and regression evidence.',
      'Do not wait for direct endpoint checks to close the imported finite gap.',
      'Prioritize auditing the imported threshold handoff or proving a stronger structural verifier lane.',
      'Use GPU/frontier sweeps to generate structural candidates and counterexamples, not as a substitute for the all-N handoff proof.',
    ],
    ...(exactIntervalBookkeeping
      ? {
        publicRepoRawExactInterval: exactIntervalBookkeeping.publicRepoRawExactInterval,
        localIgnoredRolloutInterval: exactIntervalBookkeeping.localIgnoredRolloutInterval,
        publicRepoRawExactMax: exactIntervalBookkeeping.publicRepoRawExactMax,
        localIgnoredRolloutMax: exactIntervalBookkeeping.localIgnoredRolloutMax,
        exactMaxMeaning: 'public raw packet max; compact local rollout evidence is named separately',
        bookkeepingArtifact: exactIntervalBookkeeping.bookkeepingArtifact,
        exactIntervalBookkeeping,
      }
      : {}),
  };
}

function buildP848ExactIntervalBookkeeping(problem, latestVerifiedInterval = null, breakpointCertificate = null) {
  if (String(problem?.problemId ?? '') !== '848') {
    return null;
  }

  const certificate = breakpointCertificate ?? getP848ExactBreakpointCertificate(problem);
  const certificatePayload = certificate?.certificate ?? certificate;
  const publicRepoRawExactInterval = certificatePayload?.publicRepoRawExactInterval ?? latestVerifiedInterval ?? null;
  const localIgnoredRolloutInterval = certificatePayload?.summary?.interval ?? null;
  if (!publicRepoRawExactInterval && !localIgnoredRolloutInterval) {
    return null;
  }

  const publicRange = parseP848ClosedIntegerRange(publicRepoRawExactInterval);
  const localRange = parseP848ClosedIntegerRange(localIgnoredRolloutInterval);
  const sourceResultsStatus = certificatePayload?.sourceResultsStatus ?? null;
  const raw40500PacketCommitted = sourceResultsStatus
    ? !String(sourceResultsStatus).includes('local_ignored')
    : null;

  return {
    publicRepoRawExactInterval,
    localIgnoredRolloutInterval,
    publicRepoRawExactMax: publicRange?.max ?? null,
    localIgnoredRolloutMax: localRange?.max ?? null,
    exactMaxMeaning: 'Use the public raw exact max for committed raw-packet claims; use the local rollout max only for compact derivative evidence.',
    bookkeepingArtifact: certificatePayload?.bookkeepingArtifact ?? 'EXACT_INTERVAL_BOOKKEEPING.md',
    raw40500PacketCommitted,
  };
}

function positiveModulo(value, modulus) {
  const residue = Number(value) % modulus;
  return residue < 0 ? residue + modulus : residue;
}

function sanitizeP848PacketFileStem(value) {
  return String(value ?? 'unknown')
    .replaceAll(/[^A-Za-z0-9]+/g, '_')
    .replaceAll(/^_+|_+$/g, '')
    .slice(0, 120) || 'unknown';
}

function getP848SplitAtomPacketPaths(problem, atomId = null) {
  const packProblemDir = getProblemPackDir(problem);
  if (!packProblemDir) {
    return null;
  }
  const directoryPath = path.join(packProblemDir, 'SPLIT_ATOM_PACKETS');
  if (!atomId) {
    return {
      directoryPath,
      manifestJsonPath: path.join(directoryPath, 'MANIFEST.json'),
      manifestMarkdownPath: path.join(directoryPath, 'MANIFEST.md'),
    };
  }

  const fileStem = sanitizeP848PacketFileStem(atomId);
  return {
    directoryPath,
    fileStem,
    packetId: `p848_split_atom_packet_${fileStem}`,
    jsonPath: path.join(directoryPath, `${fileStem}.json`),
    markdownPath: path.join(directoryPath, `${fileStem}.md`),
  };
}

function getP848SplitAtomSuccessorPacketPaths(problem, parentAtomId = null, conditionId = null) {
  const packetPaths = getP848SplitAtomPacketPaths(problem);
  if (!packetPaths) {
    return null;
  }
  const directoryPath = path.join(packetPaths.directoryPath, 'SUCCESSORS');
  if (!parentAtomId || !conditionId) {
    return {
      directoryPath,
    };
  }

  const fileStem = sanitizeP848PacketFileStem(`${parentAtomId}__${conditionId}`);
  return {
    directoryPath,
    fileStem,
    packetId: `p848_split_atom_successor_packet_${fileStem}`,
    jsonPath: path.join(directoryPath, `${fileStem}.json`),
    markdownPath: path.join(directoryPath, `${fileStem}.md`),
  };
}

