function getP848DMaxGrowthProfilePaths(problem, atomId = null) {
  const packetPaths = getP848SplitAtomPacketPaths(problem);
  if (!packetPaths) {
    return null;
  }
  const directoryPath = path.join(packetPaths.directoryPath, 'DMAX_GROWTH_PROFILES');
  if (!atomId) {
    return {
      directoryPath,
    };
  }

  const fileStem = sanitizeP848PacketFileStem(atomId);
  return {
    directoryPath,
    fileStem,
    profileId: `p848_dmax_growth_profile_${fileStem}`,
    jsonPath: path.join(directoryPath, `${fileStem}.json`),
  };
}

function readP848DMaxGrowthProfile(problem, atomId) {
  const profilePaths = getP848DMaxGrowthProfilePaths(problem, atomId);
  if (!profilePaths?.jsonPath) {
    return null;
  }
  const profile = readJsonIfPresent(profilePaths.jsonPath);
  if (!profile) {
    return null;
  }
  return {
    ...profile,
    profileId: profile.profileId ?? profilePaths.profileId,
    jsonPath: profilePaths.jsonPath,
  };
}

