  const paths = getProblemTaskListPaths(problem);
  const intervalQueuePath = theoremLoop.sources?.packProblemDir ? path.join(theoremLoop.sources.packProblemDir, 'INTERVAL_WORK_QUEUE.yaml') : null;
  const intervalQueue = intervalQueuePath ? readYamlIfPresent(intervalQueuePath) : null;
  const breakpointScout = getP848ExactBreakpointScout(problem);
  const breakpointCertificate = getP848ExactBreakpointCertificate(problem);
